// ════════════════════════════════════════════════════════════════════════
// DSH.09 — PERFORMANCE SNAPSHOT V3 · Wealth Management Standard (desktop ≥769)
// Executive wealth-performance centre inside .hero-right. Eyebrow → primary
// metric (money in $ mode, % in % mode; % capped so it never blows up) →
// short human context line → 3 horizontal premium indicators (monochrome SVG,
// no emoji). Right: small INVESTABLE-only donut (real estate excluded).
// Driven 100% by REAL data:
//   • period stats  → getChartData(range) over portfolioHistory (total wealth)
//   • composition   → getInvestableDistribution() (liquid wealth, real estate
//     excluded — inmuebles keeps its own card below, never this module's donut)
// No per-asset estimates, no fabricated points, no AI, no debug wording. When a
// range lacks enough real history it shows an honest "Datos insuficientes" state
// — never "Generando histórico fiable", never a placeholder/guess.
// Mobile is untouched: the whole .hero-right is display:none ≤768 and the mobile
// slider keeps its own chart + donut (swipe).
// ════════════════════════════════════════════════════════════════════════

// Premium monochrome inline icons (no emoji). stroke = currentColor so they
// inherit the Aurix-blue indicator colour; identical size + weight + grosor.
const _DSH_ICON_BEST    = '<svg class="perf-ind-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 19V6"/><path d="M6 12l6-6 6 6"/></svg>';
const _DSH_ICON_WORST   = '<svg class="perf-ind-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 5v13"/><path d="M6 12l6 6 6-6"/></svg>';
const _DSH_ICON_POS     = '<svg class="perf-ind-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="8"/><circle cx="12" cy="12" r="2.6"/></svg>';
const _DSH_ICON_CONTRIB = '<svg class="perf-ind-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.55" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3.5l2.6 5.7 6.2.6-4.7 4.1 1.4 6.1L12 17l-5.5 3.1 1.4-6.1L3.2 9.8l6.2-.6z"/></svg>';

// Signed money with NO decimals — the premium hero number + clean count-up.
// Locale-correct currency token (es → "346.590 US$", en → "$346,590").
function _dshFmtMoney0(n) {
  const locale = (typeof lang !== 'undefined' && lang === 'en') ? 'en-US' : 'es-ES';
  try {
    return new Intl.NumberFormat(locale, {
      style: 'currency', currency: baseCurrency,
      maximumFractionDigits: 0, signDisplay: 'exceptZero',
    }).format(n);
  } catch (_) {
    return (n >= 0 ? '+' : '') + formatBase(n);
  }
}

// Currency token + placement, derived once from Intl so the compact formatter
// uses the SAME representation as the hero (no "$1.86M" vs "1.86M US$" mismatch).
function _dshCurParts() {
  const locale = (typeof lang !== 'undefined' && lang === 'en') ? 'en-US' : 'es-ES';
  try {
    const parts = new Intl.NumberFormat(locale, { style: 'currency', currency: baseCurrency, maximumFractionDigits: 0 }).formatToParts(1);
    const cur = (parts.find(p => p.type === 'currency') || {}).value || '$';
    return { cur, prefix: !!(parts[0] && parts[0].type === 'currency'), locale };
  } catch (_) { return { cur: '$', prefix: true, locale: 'es-ES' }; }
}

// Compact money (K/M) with the SAME currency token as the hero. e.g. 444.5K US$.
function _dshMoneyCompact(n) {
  const { cur, prefix, locale } = _dshCurParts();
  const a = Math.abs(n), sign = n < 0 ? '-' : '';
  let num;
  if (a >= 1e6) num = (a / 1e6).toFixed(2) + 'M';
  else if (a >= 1e3) num = (a / 1e3).toFixed(1) + 'K';
  else num = new Intl.NumberFormat(locale, { maximumFractionDigits: 0 }).format(a);
  return prefix ? `${sign}${cur}${num}` : `${sign}${num} ${cur}`;
}

// Percentage, capped so an extreme TOTAL never becomes a giant "+22902.25%"
// titular. Returns the clean text, the capped flag, and the real value (for a
// tooltip / secondary line).
function _dshFmtPct(p) {
  if (!Number.isFinite(p)) return { text: '—', capped: false, raw: '—' };
  const sign = p > 0 ? '+' : (p < 0 ? '-' : '');
  const a = Math.abs(p);
  const raw = `${sign}${a.toFixed(2)}%`;
  if (a > 999) return { text: `${sign}999%+`, capped: true, raw };
  return { text: raw, capped: false, raw };
}

function _dshReducedMotion() {
  try { return !!(window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches); }
  catch (_) { return false; }
}

// Period range band — sober reading of the measured amplitude ((max-min)/min).
// "Bajo / Medio / Alto". Real data, not an estimate.
function _dshRangeBand(amplitudePct) {
  if (!Number.isFinite(amplitudePct)) return null;
  if (amplitudePct < 8)  return { key: 'low',  label: t('rangeLow')  };
  if (amplitudePct < 20) return { key: 'med',  label: t('rangeMed')  };
  return { key: 'high', label: t('rangeHigh') };
}

// Liquid/investable share of TOTAL wealth (investable ÷ total). Real metric for
// the donut centre — distinct from the inmuebles card, never duplicated.
function _dshInvestableShare() {
  try {
    if (typeof investableValueUSD !== 'function' || typeof totalValueUSD !== 'function') return null;
    const tot = totalValueUSD();
    if (!(tot > 0)) return null;
    return (investableValueUSD() / tot) * 100;
  } catch (_) { return null; }
}

// Short, human, deterministic reading of the period — derived from direction +
// magnitude of the real change + the selected range. No AI, no invention.
function _dshContextLine(snap, range) {
  if (!snap) return '';
  const p = Number.isFinite(snap.deltaPct) ? snap.deltaPct : 0;
  const a = Math.abs(p);
  const perKey = ({ '24h': 'ctxIn24h', '7d': 'ctxIn7d', '30d': 'ctxIn30d', '1y': 'ctxIn1y', 'all': 'ctxInAll' })[range] || 'ctxInAll';
  let phraseKey;
  if (a < 0.5) phraseKey = 'ctxStable';
  else if (p > 0) phraseKey = a < 3 ? 'ctxUpLight' : a < 10 ? 'ctxUpSolid' : 'ctxUpStrong';
  else phraseKey = a < 3 ? 'ctxDownLight' : a < 10 ? 'ctxDownMod' : 'ctxDownStrong';
  return `${t(phraseKey)} ${t(perKey)}`;
}

// Pure: derive period stats from the SAME flow-neutral investable series the hero
// curve consumes. Returns null when there are < 2 real points for the active range,
// so the caller renders an honest "Datos insuficientes" state instead of inventing.
//
// AURIX-RETURN-UNIFY-1 — previously this read getChartData(range) (RAW total net
// worth) and computed (last−first)/first, so a capital flow (e.g. adding 0.20 BTC)
// inflated this module's % to ~+19% while the hero — neutralising the same flow —
// showed ~+0.2%. It now sources the eligible INVESTABLE series + WN.11 flow
// neutralisation (identical to the hero), so the number matches the badge exactly
// and a deposit can never read as market return.
function _dshComputePerfSnapshot(range) {
  let elig = null;
  try { elig = _aurixEligibleInvestableSeries(range); } catch (_) { return null; }
  const snaps = (elig && Array.isArray(elig.series)) ? elig.series : [];
  if (snaps.length < 2) return null;

  const neutral = _aurixFlowNeutralize(snaps, range);
  const adj = neutral.adjusted;
  const vals = [], ts = [];
  for (let i = 0; i < adj.length; i++) {
    const v = adj[i];
    if (Number.isFinite(v) && v > 0) { vals.push(v); ts.push(snaps[i].ts); }
  }
  if (vals.length < 2) return null;

  // Canonical flow-neutral return (shared with hero + computeRangePnL).
  const _ret = _aurixRangeReturn(range);
  const first = vals[0];
  const last  = vals[vals.length - 1];
  const max   = Math.max(...vals);
  const min   = Math.min(...vals);
  const deltaAbs     = (_ret && Number.isFinite(_ret.deltaAbs)) ? _ret.deltaAbs : (last - first);
  const deltaPct     = (_ret && Number.isFinite(_ret.deltaPct)) ? _ret.deltaPct : (first > 0 ? ((last - first) / first) * 100 : null);
  const amplitudePct = min > 0 ? ((max - min) / min) * 100 : null;

  // Per-period series: collapse to one close per calendar day for multi-day
  // ranges; for 24h use the intraday samples. Powers the consistency read.
  let series = vals;
  if (range !== '24h') {
    const byDay = new Map();
    for (let i = 0; i < ts.length; i++) {
      const dt = new Date(ts[i]);
      byDay.set(`${dt.getFullYear()}-${dt.getMonth()}-${dt.getDate()}`, vals[i]);
    }
    if (byDay.size >= 2) series = [...byDay.values()];
  }
  let up = 0, down = 0;
  for (let i = 1; i < series.length; i++) {
    if (series[i] > series[i - 1]) up++;
    else if (series[i] < series[i - 1]) down++;
  }
  const moves = up + down;
  const consistencyPct = moves > 0 ? (up / moves) * 100 : null;

  return {
    first, last, max, min, deltaAbs, deltaPct, amplitudePct,
    up, down, consistencyPct, rangeBand: _dshRangeBand(amplitudePct),
  };
}

// Live portfolio signals (real, current). Movers/contributor use the live 24h
// change + current values (only honest per-asset signal), real estate excluded
// entirely. Mayor exposición = dominant investable class. Any block without real
// data is omitted. No invention.
function _dshComputeInsights() {
  if (!Array.isArray(assets) || !assets.length) return null;

  // Movers/contributor consider only NON-real-estate assets carrying a live 24h
  // change (real estate has none → naturally excluded; we never reference it).
  const rows = assets
    .filter(a => isInvestableAsset(a))
    .map(a => {
      const valUSD = (typeof assetValueUSD === 'function') ? assetValueUSD(a) : 0;
      const ch = (typeof a.change24h === 'number' && isFinite(a.change24h)) ? a.change24h : null;
      return {
        name: a.name || normalizeSymbol(a.ticker || a.symbol || '') || '—',
        ch, valUSD,
        contribBase: ch != null ? toBase((ch / 100) * valUSD, 'USD') : null,
      };
    })
    .filter(r => r.valUSD > 0);

  // Mayor exposición — dominant INVESTABLE class (real estate excluded), share
  // of investable wealth. Investment context, not inventory.
  let exposure = null;
  const inv = (typeof getInvestableDistribution === 'function') ? getInvestableDistribution() : null;
  if (inv && inv.length) {
    const m = TYPE_META[inv[0].type] || TYPE_META.other;
    exposure = { name: (m.donutLabel || m.label), pct: inv[0].pct };
  }

  // 24h movers + top contributor — only from assets that carry a live 24h
  // change; if none do, those blocks are omitted (never faked).
  const withCh = rows.filter(r => r.ch != null);
  let best = null, worst = null, contributor = null;
  if (withCh.length) {
    best = worst = contributor = withCh[0];
    withCh.forEach(r => {
      if (r.ch > best.ch) best = r;
      if (r.ch < worst.ch) worst = r;
      if (r.contribBase > contributor.contribBase) contributor = r;
    });
  }
  if (!exposure && !best) return null;
  return { exposure, best, worst, contributor };
}

// Right-side context: INVESTABLE composition only (real estate excluded — it
// keeps its own card below). Small donut + compact legend; centre shows the
// liquid share of total wealth. Percentages only, no amounts (no duplication).
function _dshBuildCompoHtml() {
  const dist = (typeof getInvestableDistribution === 'function') ? getInvestableDistribution() : null;
  const invShare = _dshInvestableShare();
  const centerVal = Number.isFinite(invShare) ? `${invShare.toFixed(1)}%` : '—';

  if (!dist || !dist.length) {
    return `<div class="perf-donut perf-donut--empty">
        <svg class="perf-donut-svg" viewBox="0 0 150 150" aria-hidden="true"><circle cx="75" cy="75" r="71" fill="none" stroke="rgba(255,255,255,0.06)" stroke-width="9"/></svg>
        <div class="perf-donut-center"><div class="perf-donut-center-sub">${t('emptyDonutLabel')}</div></div>
      </div>`;
  }

  const size = 150, sw = 9, r = (size - sw) / 2, c = size / 2, C = 2 * Math.PI * r;
  let acc = 0;
  const segs = dist.map(seg => {
    const frac = Math.max(0, seg.pct) / 100;
    const len  = frac * C;
    const col  = (TYPE_META[seg.type] || TYPE_META.other).color;
    const html = `<circle class="perf-donut-seg" cx="${c}" cy="${c}" r="${r}" fill="none" stroke="${col}" stroke-width="${sw}" stroke-dasharray="${len.toFixed(2)} ${(C - len).toFixed(2)}" stroke-dashoffset="${(-acc * C).toFixed(2)}"/>`;
    acc += frac;
    return html;
  }).join('');

  const legend = dist.slice(0, 5).map(seg => {
    const m = TYPE_META[seg.type] || TYPE_META.other;
    return `<div class="perf-legend-item"><span class="perf-legend-left"><span class="perf-legend-dot" style="background:${m.color}"></span><span class="perf-legend-label">${m.donutLabel || m.label}</span></span><span class="perf-legend-pct">${seg.pct.toFixed(1)}%</span></div>`;
  }).join('');

  return `
    <div class="perf-donut">
      <svg class="perf-donut-svg" viewBox="0 0 ${size} ${size}" aria-hidden="true"><circle cx="${c}" cy="${c}" r="${r}" fill="none" stroke="rgba(255,255,255,0.04)" stroke-width="${sw}"/>${segs}</svg>
      <div class="perf-donut-center"><div class="perf-donut-center-val">${centerVal}</div><div class="perf-donut-center-sub">${t('centerInvertible')}</div></div>
    </div>
    <div class="perf-donut-legend">${legend}</div>`;
}

// Smooth count-up of the primary number (easeOutCubic, ~520ms). fmt formats
// each frame (money or %), so the same routine drives both toggle modes.
let _dshLastPrimary = null;
function _dshCountUp(el, from, to, fmt) {
  const dur = 520;
  let startTs = null;
  const ease = x => 1 - Math.pow(1 - x, 3);
  function frame(ts) {
    if (startTs === null) startTs = ts;
    const p = Math.min(1, (ts - startTs) / dur);
    el.textContent = fmt(from + (to - from) * ease(p));
    if (p < 1) requestAnimationFrame(frame);
    else el.textContent = fmt(to);
  }
  requestAnimationFrame(frame);
}

// Build + paint the module. doCountUp animates the primary number from its last
// shown value (user range/unit change); silent on background refreshes.
function _dshPaintPerfSnapshot(root, doCountUp) {
  // P0-FINAL-RENDER-OWNERSHIP-SURGERY (S1) — PASSIVE CONSUMER. The "Resumen de rendimiento" hero no longer
  // computes its own return/pending (no _dshComputePerfSnapshot / getValidReturnBaseline). The return %/€ and
  // the pending verdict come from the single producer (computePerformanceSnapshot). The insight blocks
  // (best/worst/contributor/exposure — current 24h asset facts) + donut keep rendering: they are not the
  // return and not the chart series.
  const _ps = (typeof computePerformanceSnapshot === 'function') ? computePerformanceSnapshot(activeRange) : null;
  const _hasData = !!(_ps && _ps.chartPointCount >= 2);
  const snap = _hasData ? { deltaPct: (_ps.badgeReady ? _ps.displayedReturnPct : 0), deltaAbs: (_ps.badgeReady ? _ps.displayedReturnValue : 0) } : null;
  const _pending = _hasData && !_ps.badgeReady;

  let infoHtml;
  if (!snap) {
    infoHtml = `<div class="perf-empty">${t('perfEmpty')}</div>`;
  } else {
    const pct  = Number.isFinite(snap.deltaPct) ? snap.deltaPct : 0;
    const abs  = Number.isFinite(snap.deltaAbs) ? snap.deltaAbs : 0;
    const tone = _pending ? 'flat' : (pct > 0.005 ? 'up' : pct < -0.005 ? 'down' : 'flat');
    // The %/$ toggle drives the hierarchy: the active unit leads (large), the
    // other sits below (small). % is capped so it never blows up the headline.
    const mode      = activePerfMode === 'curr' ? 'curr' : 'pct';
    const moneyText = _dshFmtMoney0(abs);
    const pctFmt    = _dshFmtPct(pct);
    const primaryText   = _pending ? _aurixReturnPendingHTML() : (mode === 'curr' ? moneyText  : pctFmt.text);
    const secondaryText = _pending ? '' : (mode === 'curr' ? pctFmt.text : moneyText);
    const primaryTitle  = (!_pending && mode === 'pct' && pctFmt.capped) ? ` title="${pctFmt.raw}"` : '';

    // Insight blocks — the ASSET is the protagonist: NAME → description → value.
    // Only blocks backed by real data are emitted (no faking, no real estate).
    const ins = _dshComputeInsights();
    const block = (name, desc, subHtml) =>
      `<div class="perf-block"><span class="perf-block-name">${name}</span><span class="perf-block-desc">${desc}</span>${subHtml}</div>`;
    const pctSub = v => `<span class="perf-block-sub ${v >= 0 ? 'pos' : 'neg'}">${v >= 0 ? '+' : ''}${v.toFixed(2)}%</span>`;
    const blocks = [];
    if (ins) {
      if (ins.best) blocks.push(block(ins.best.name, t('insBest'), pctSub(ins.best.ch)));
      if (ins.contributor && Number.isFinite(ins.contributor.contribBase)) {
        const c = ins.contributor.contribBase;
        blocks.push(block(ins.contributor.name, t('insContributor'), `<span class="perf-block-sub ${c >= 0 ? 'pos' : 'neg'}">${c >= 0 ? '+' : ''}${_dshMoneyCompact(c)}</span>`));
      }
      if (ins.exposure) blocks.push(block(ins.exposure.name, t('insExposure'), `<span class="perf-block-sub perf-block-neutral">${ins.exposure.pct.toFixed(1)}%</span>`));
      if (ins.worst) blocks.push(block(ins.worst.name, t('insWorst'), pctSub(ins.worst.ch)));
    }
    const insightsHtml = blocks.length ? `<div class="perf-insights-grid">${blocks.join('')}</div>` : '';

    infoHtml = `
      <div class="perf-hero">
        <div class="perf-hero-money ${_pending ? 'calculating' : tone}"${primaryTitle}>${primaryText}</div>
        <div class="perf-hero-pct ${tone}">${secondaryText}</div>
      </div>
      ${insightsHtml}`;
  }

  root.innerHTML = `<div class="perf-info">${infoHtml}</div><div class="perf-compo">${_dshBuildCompoHtml()}</div>`;

  // Count-up the primary number (active unit). Skip across a unit switch or a
  // capped %, where counting is meaningless. RETURN-PENDING-FINAL — and skip entirely while
  // pending, so the count-up never overwrites the "Calculando…" markup with a number.
  if (snap && !_pending) {
    const el   = root.querySelector('.perf-hero-money');
    const mode = activePerfMode === 'curr' ? 'curr' : 'pct';
    const val  = mode === 'curr'
      ? (Number.isFinite(snap.deltaAbs) ? snap.deltaAbs : 0)
      : (Number.isFinite(snap.deltaPct) ? snap.deltaPct : 0);
    const fmt    = mode === 'curr' ? _dshFmtMoney0 : (v => _dshFmtPct(v).text);
    const capped = mode === 'pct' && _dshFmtPct(val).capped;
    if (el) {
      if (doCountUp && _dshLastPrimary && _dshLastPrimary.mode === mode &&
          Number.isFinite(_dshLastPrimary.value) && _dshLastPrimary.value !== val &&
          !capped && !_dshReducedMotion()) {
        _dshCountUp(el, _dshLastPrimary.value, val, fmt);
      } else {
        el.textContent = fmt(val);
      }
    }
    _dshLastPrimary = { mode, value: val };
  } else {
    _dshLastPrimary = null;
  }
}

// ════════════════════════════════════════════════════════════════════════
// WealthSnapshotCurve — a single, responsive, premium wealth curve shared by
// desktop (.hero-right → #perfSnapshot) and mobile (slider slide 1 →
// #wealthCurveMobile). It REPLACES the old desktop Performance-Snapshot module
// (mejor activo / mayor contribuidor / mayor exposición / mayor retroceso /
// donut) AND the old mobile chart engine's visible surface.
//
// DATA: validated INTERNAL snapshots only, via getChartData(activeRange) — the
// canonical portfolioHistory pipeline. That function already discards points
// that are null/undefined/NaN/zero/negative or carry an invalid timestamp,
// applies the post-reset epoch filter, strips corrupt spikes, and returns the
// empty shape when fewer than 2 valid points remain. So this component never
// invents, interpolates or draws a defective point. NO CoinGecko, NO PCE, NO
// external/historical price APIs, NO per-asset history. Each point is wealth as
// Aurix measured it at a moment — the SAME canonical "Valor total de cartera"
// total the left hero block shows (toBase(value,'USD') in base currency).
//
// VISUAL: thin smooth line, generous negative space, no heavy grid, no trading
// fill — institutional, calm. Pure inline SVG, zero new dependencies.
// ════════════════════════════════════════════════════════════════════════

const _WSC_VIEW_W = 1000;
const _WSC_VIEW_H = 240;
// WSC.4 INSTITUTIONAL ENGINE — the chart is derived ENTIRELY from real wealth
// snapshots (getChartData). Pipeline: clean → (per-range) aggregate → robust
// outlier-aware scaling → monotone-cubic interpolation → render. There is NO
// synthetic movement: no microvariation, no seeded noise, no fabricated trend,
// no decorative oscillation. Only the visual SCALE adapts (robust statistics +
// adaptive occupancy) so real movement is always legible and outliers never
// dictate the chart height. Metric / % / gain stay the real figures.
const _WSC_PAD_X    = 0.06;   // WN.6/WN.25 — wider plot (smaller horizontal inset); WN.25 PART 3 panel density: 0.075→0.06 ≈ +3.5% usable width (right Y labels keep clearance: curve right edge ~94%)
const _WSC_OCC_SCALE = 0.05;  // robust relative-spread that maps to ~mid occupancy
// WN.7 — line occupancy (no-floor/no-ceiling): the data line fills ~54–66% of
// the chart height, centred inside a taller grid, so it never hugs the top or
// bottom (≥ ~17% margin each). Adaptive per timeframe within this range.
const _WSC_OCC = {
  '24h': [0.54, 0.62],
  '7d':  [0.55, 0.63],
  '30d': [0.56, 0.64],
  '1y':  [0.58, 0.66],
  'all': [0.58, 0.66],
};
// Per-range adjacent-jump threshold (%) above which a SUSTAINED level shift is
// treated as a capital / import / construction event (not market performance).
const _WSC_CAPITAL_JUMP = { '24h': 8, '7d': 15, '30d': 25, '1y': 35, 'all': 35 };

// Linear-interpolated percentile of an ascending-sorted array (p ∈ [0,1]).
function _wscPercentile(sortedAsc, p) {
  const m = sortedAsc.length;
  if (!m) return 0;
  if (m === 1) return sortedAsc[0];
  const idx = (m - 1) * Math.min(1, Math.max(0, p));
  const lo = Math.floor(idx), hi = Math.ceil(idx);
  return lo === hi ? sortedAsc[lo] : sortedAsc[lo] + (sortedAsc[hi] - sortedAsc[lo]) * (idx - lo);
}

// Centred moving average over real values (window win) — honest noise reduction
// for the macro timeframes (aggregation of real data, never invented movement).
function _wscMovingAvg(arr, win) {
  if (win <= 1) return arr.slice();
  const m = arr.length, half = Math.floor(win / 2), out = new Array(m);
  for (let i = 0; i < m; i++) {
    let sum = 0, cnt = 0;
    for (let j = i - half; j <= i + half; j++) if (j >= 0 && j < m) { sum += arr[j]; cnt++; }
    out[i] = sum / (cnt || 1);
  }
  return out;
}

// Hampel despike — replace isolated outliers with their local median (window
// ±k) using a robust median+MAD test, with a small relative floor so an
// endpoint spike is caught even when the recent neighbourhood is near-flat.
// Operates on REAL values only (visual position); the metric and tooltip keep
// the true figures. Removes 24H right-edge hooks and stair-causing blips.
function _wscDespike(vals, k, nSig) {
  const n = vals.length;
  if (n < 5) return vals.slice();
  const med = arr => { const s = arr.slice().sort((a, b) => a - b); return s[(s.length - 1) >> 1]; };
  const out = vals.slice();
  for (let i = 0; i < n; i++) {
    const lo = Math.max(0, i - k), hi = Math.min(n - 1, i + k);
    const win = vals.slice(lo, hi + 1);
    const m = med(win);
    const mad = med(win.map(x => Math.abs(x - m)));
    const sigma = Math.max(1.4826 * mad, Math.abs(m) * 0.002);   // relative floor
    if (sigma > 0 && Math.abs(vals[i] - m) > nSig * sigma) out[i] = m;
  }
  return out;
}

// Monotone cubic (Fritsch–Carlson) interpolation → SVG cubic-bézier path. The
// institutional-grade curve: smooth and faithful to the real points, with NO
// overshoot, NO loops, NO spikes (tangents are limited so the spline can never
// invent a peak/valley the data doesn't have).
// WN.22 — PCHIP tangents (Fritsch–Carlson with the weighted-HARMONIC mean).
// This is the standard smooth, shape-preserving monotone interpolant: it is
// C1-continuous (no kinked joints → softer regime transitions / staircases) and
// inherently overshoot-free (no fake highs/lows), while passing through EVERY
// anchor exactly (so the tooltip and WN.19–21 outputs are untouched). The old
// arithmetic-mean tangents kinked at joints; the harmonic mean rounds them.
function _wscPchipTangents(xs, ys) {
  const n = xs.length, m = new Array(n);
  if (n < 2) { m[0] = 0; return m; }
  const dx = [], slope = [];
  for (let i = 0; i < n - 1; i++) { const h = (xs[i + 1] - xs[i]) || 1e-6; dx.push(h); slope.push((ys[i + 1] - ys[i]) / h); }
  if (n === 2) { m[0] = m[1] = slope[0]; return m; }
  // One-sided, shape-preserving endpoint tangents (clamped against overshoot).
  const endTan = (s0, s1, h0, h1) => {
    let t = ((2 * h0 + h1) * s0 - h0 * s1) / (h0 + h1);
    if (t * s0 <= 0) t = 0; else if (s0 * s1 <= 0 && Math.abs(t) > 3 * Math.abs(s0)) t = 3 * s0;
    return t;
  };
  m[0] = endTan(slope[0], slope[1], dx[0], dx[1]);
  m[n - 1] = endTan(slope[n - 2], slope[n - 3], dx[n - 2], dx[n - 3]);
  for (let i = 1; i < n - 1; i++) {
    if (slope[i - 1] * slope[i] <= 0) { m[i] = 0; continue; }          // local extremum → flat tangent (no overshoot)
    const w1 = 2 * dx[i] + dx[i - 1], w2 = dx[i] + 2 * dx[i - 1];
    m[i] = (w1 + w2) / (w1 / slope[i - 1] + w2 / slope[i]);            // weighted harmonic mean → smooth + monotone
  }
  return m;
}
function _wscMonotonePath(pts) {
  const n = pts.length;
  if (n < 2) return '';
  if (n === 2) return `M${pts[0].x.toFixed(2)},${pts[0].y.toFixed(2)} L${pts[1].x.toFixed(2)},${pts[1].y.toFixed(2)}`;
  const xs = pts.map(p => p.x), ys = pts.map(p => p.y);
  const m = _wscPchipTangents(xs, ys);
  let d = `M${xs[0].toFixed(2)},${ys[0].toFixed(2)}`;
  for (let i = 0; i < n - 1; i++) {
    const h = (xs[i + 1] - xs[i]) || 1e-6;
    const c1x = xs[i] + h / 3,     c1y = ys[i] + m[i] * h / 3;
    const c2x = xs[i + 1] - h / 3, c2y = ys[i + 1] - m[i + 1] * h / 3;
    d += ` C${c1x.toFixed(2)},${c1y.toFixed(2)} ${c2x.toFixed(2)},${c2y.toFixed(2)} ${xs[i + 1].toFixed(2)},${ys[i + 1].toFixed(2)}`;
  }
  return d;
}

// ── WN.22 — Institutional Curve Naturalization (analysis + scoring) ─────────
// Measures the DRAWN curve geometry (screen space, post all warps/scales) for
// artificial ramps, staircases, plateau rigidity, transition harshness and
// curvature continuity — and how much organic microstructure survives. Pure
// measurement on the rendered anchors + the PCHIP curve; it changes no value,
// anchor, tooltip or metric. The PCHIP renderer above IS the naturalization
// (C1 joints, overshoot-free); these functions detect/score what it produced.
function _wscCurveSampleCurvature(pts) {
  // Dense-sample the PCHIP curve and return per-sample turning (2nd difference).
  const n = pts.length; if (n < 3) return { samples: [], turns: [] };
  const xs = pts.map(p => p.x), ys = pts.map(p => p.y), m = _wscPchipTangents(xs, ys);
  const samp = [];
  for (let i = 0; i < n - 1; i++) {
    const h = (xs[i + 1] - xs[i]) || 1e-6;
    for (let s = 0; s < 6; s++) {
      const t = s / 6, t2 = t * t, t3 = t2 * t;
      const y = (2 * t3 - 3 * t2 + 1) * ys[i] + (t3 - 2 * t2 + t) * h * m[i] + (-2 * t3 + 3 * t2) * ys[i + 1] + (t3 - t2) * h * m[i + 1];
      const x = xs[i] + t * h;
      samp.push({ x, y });
    }
  }
  samp.push({ x: xs[n - 1], y: ys[n - 1] });
  const turns = [];
  for (let i = 1; i < samp.length - 1; i++) {
    const dy1 = samp[i].y - samp[i - 1].y, dy2 = samp[i + 1].y - samp[i].y;
    turns.push(Math.abs(dy2 - dy1));
  }
  return { samples: samp, turns };
}
// PART 1 — long near-linear (ruler) ramps in screen space.
function _wscDetectArtificialRamps(pts, range) {
  const out = []; const n = pts.length; if (n < 4) return out;
  const xs = pts.map(p => p.x), ys = pts.map(p => p.y);
  const totalW = (xs[n - 1] - xs[0]) || 1, totalH = (Math.max(...ys) - Math.min(...ys)) || 1;
  const widthThr = range === '24h' ? 0.25 : range === '7d' ? 0.20 : 0.15;
  let i = 0;
  while (i < n - 2) {
    let j = i + 1;
    // extend while points stay near the chord from i (max deviation < 2% of height)
    while (j < n - 1) {
      const k = j + 1, fx = (xs[k] - xs[i]) || 1e-6;
      let maxDev = 0;
      for (let p = i + 1; p <= k; p++) {
        const chord = ys[i] + (ys[k] - ys[i]) * ((xs[p] - xs[i]) / fx);
        maxDev = Math.max(maxDev, Math.abs(ys[p] - chord));
      }
      if (maxDev > 0.02 * totalH) break;
      j = k;
    }
    const widthPct = (xs[j] - xs[i]) / totalW;
    const slope = (ys[j] - ys[i]) / ((xs[j] - xs[i]) || 1e-6);
    if (j - i >= 3 && widthPct >= widthThr && Math.abs(ys[j] - ys[i]) > 0.03 * totalH) {
      out.push({ start: i, end: j, widthPct: +(widthPct * 100).toFixed(1), slope: +slope.toFixed(4), curvature: 0 });
      i = j;
    } else i++;
  }
  return out;
}
// PART 4 — flat → jump → flat staircases (screen space).
function _wscDetectStaircases(pts, totalH) {
  const n = pts.length; if (n < 5) return 0;
  const ys = pts.map(p => p.y); let steps = 0, i = 1;
  const flat = (a, b) => Math.abs(ys[b] - ys[a]) < 0.02 * totalH;
  while (i < n - 2) {
    const jump = Math.abs(ys[i + 1] - ys[i]) > 0.08 * totalH;
    if (jump && flat(Math.max(0, i - 1), i) && flat(i + 1, Math.min(n - 1, i + 2))) { steps++; i += 2; } else i++;
  }
  return steps;
}
// PART 5 — rigid (perfectly frozen) plateaus wider than 12%.
function _wscDetectPlateaus(pts, range) {
  const out = []; const n = pts.length; if (n < 4) return out;
  const xs = pts.map(p => p.x), ys = pts.map(p => p.y);
  const totalW = (xs[n - 1] - xs[0]) || 1, totalH = (Math.max(...ys) - Math.min(...ys)) || 1;
  let i = 0;
  while (i < n - 1) {
    let j = i, lo = ys[i], hi = ys[i];
    while (j < n - 1 && Math.max(hi, ys[j + 1]) - Math.min(lo, ys[j + 1]) < 0.015 * totalH) { j++; lo = Math.min(lo, ys[j]); hi = Math.max(hi, ys[j]); }
    const widthPct = (xs[j] - xs[i]) / totalW;
    if (j - i >= 2 && widthPct > 0.12) {
      const rangeH = (hi - lo) / totalH;                         // 0 = perfectly frozen
      out.push({ start: i, end: j, widthPct: +(widthPct * 100).toFixed(1), rigidity: +(1 - Math.min(1, rangeH / 0.01)).toFixed(2) });
      i = j + 1;
    } else i++;
  }
  return out;
}
// PART 6 — institutional curve naturality score (0–100). Measures whether the
// DRAWN curve reads like a real wealth history: smooth (C1) joints, organic
// microstructure, and freedom from GENUINE artifacts. It does NOT penalise
// legitimate smooth structure — a clean rally or a softly-rendered regime
// transition is institutional, not an artifact. Penalties fire only for: a
// zero-microstructure RULER (perfectly straight gap-fill), a FROZEN wide plateau,
// or a HARD-cornered joint (low curvature continuity).
function _wscInstitutionalCurveScore(pts, range) {
  const out = { institutionalCurveScore: null, rampPenalty: 0, plateauPenalty: 0, staircasePenalty: 0, continuityScore: 100, microstructureScore: 100, artificialRampCount: 0, staircaseCount: 0, plateauCount: 0, transitionHarshness: 0, microstructureRecovered: false };
  try {
    const n = pts.length; if (n < 4) { out.institutionalCurveScore = 100; return out; }
    const ys = pts.map(p => p.y), totalH = (Math.max(...ys) - Math.min(...ys)) || 1;
    const ramps = _wscDetectArtificialRamps(pts, range);
    const plateaus = _wscDetectPlateaus(pts, range);
    out.artificialRampCount = ramps.length; out.plateauCount = plateaus.length;
    out.staircaseCount = _wscDetectStaircases(pts, totalH);
    // direction changes within an anchor span (organic microstructure detector).
    const dcIn = (a, b) => { let c = 0; for (let i = a + 2; i <= b && i < n; i++) { const p = Math.sign(ys[i - 1] - ys[i - 2]), q = Math.sign(ys[i] - ys[i - 1]); if (p && q && p !== q) c++; } return c; };
    // curvature continuity + harshness from the dense PCHIP curve (smooth → high).
    const { turns } = _wscCurveSampleCurvature(pts);
    let cont = 100, harsh = 0;
    if (turns.length) { const mean = turns.reduce((a, b) => a + b, 0) / turns.length; const varr = turns.reduce((a, b) => a + (b - mean) * (b - mean), 0) / turns.length; harsh = Math.sqrt(varr) / totalH; cont = Math.max(0, 100 - harsh * 600); }
    out.transitionHarshness = +(harsh * 100).toFixed(2);
    out.continuityScore = +cont.toFixed(1);
    let dirc = 0; for (let i = 2; i < n; i++) { const a = Math.sign(ys[i - 1] - ys[i - 2]), b = Math.sign(ys[i] - ys[i - 1]); if (a !== 0 && b !== 0 && a !== b) dirc++; }
    out.microstructureScore = +Math.min(100, 55 + dirc * 5).toFixed(1);
    out.microstructureRecovered = dirc > 0;
    // RULER penalty: a steep monotone rally is legitimate (and PCHIP eases its
    // ends), so only an EXTREME zero-microstructure straight run (>40% of width,
    // e.g. a long gap-fill) incurs a mild penalty — the dominant quality signal
    // is curvature continuity, not the mere presence of a straight trend.
    let rulerW = 0; ramps.forEach(r => { if (dcIn(r.start, r.end) === 0) rulerW += r.widthPct; });
    out.rampPenalty = +Math.min(8, Math.max(0, rulerW - 40) * 0.3).toFixed(1);
    // FROZEN-plateau penalty: only perfectly-rigid wide plateaus (a calm
    // consolidation that still moves is institutional, not an artifact).
    out.plateauPenalty = +Math.min(20, plateaus.reduce((s, p) => s + (p.rigidity > 0.9 ? (p.widthPct - 12) * 0.5 : 0), 0)).toFixed(1);
    // HARD-corner penalty: only when curvature continuity drops (PCHIP keeps it high).
    out.staircasePenalty = +Math.min(20, Math.max(0, 94 - cont) * 1.2).toFixed(1);
    const artifact = Math.max(0, 100 - out.rampPenalty - out.plateauPenalty - out.staircasePenalty);
    const score = 0.42 * cont + 0.23 * out.microstructureScore + 0.35 * artifact;
    out.institutionalCurveScore = +Math.max(0, Math.min(100, score)).toFixed(1);
  } catch (e) { out.error = String(e && e.message || e); out.institutionalCurveScore = 100; }
  return out;
}

// ── Institutional viewport ──────────────────────────────────────────────────
// Compute the per-timeframe vertical mapping from REAL values using robust
// statistics. Returns { yOf } mapping a real value → viewBox y inside an
// adaptive occupancy band. Outliers (creation/import/reset/anomalies) are
// excluded from the scale via percentile clipping, so they never flatten valid
// movement nor determine the height. Each call is independent per timeframe.
function _wscViewport(values, range) {
  const H = _WSC_VIEW_H, center = H / 2;
  const sorted = values.slice().sort((a, b) => a - b);
  // VALUE chart: true min/max → accurate labels (data is clean investable value;
  // isolated spikes already removed upstream by despike).
  let lo = sorted[0], hi = sorted[sorted.length - 1];
  const median = _wscPercentile(sorted, 0.5);
  let span = hi - lo;
  if (!(span > 0)) { span = Math.abs(median) * 1e-4 || 1; lo = median - span / 2; hi = median + span / 2; }

  // Adaptive occupancy of the LINE within a no-floor/no-ceiling band (WN.7):
  // the data line occupies ~54–66% of the chart height, centred, so it never
  // hugs the top or bottom (≥ ~17% margin each). The GRID region is generous
  // (taller) and the data line sits comfortably inside it.
  const [minOcc, maxOcc] = _WSC_OCC[range] || _WSC_OCC['30d'];
  const relSpread = span / (Math.abs(median) || hi || 1);
  const occ = Math.min(maxOcc, Math.max(minOcc,
    minOcc + (maxOcc - minOcc) * Math.tanh(relSpread / _WSC_OCC_SCALE)));
  const lineBand = occ * H, lineTop = center - lineBand / 2, lineBot = center + lineBand / 2;
  const gridTop = H * 0.10, gridBot = H * 0.88;          // generous grid, away from host edges

  const yOf  = v => lineBot - Math.min(1, Math.max(0, (v - lo) / span)) * lineBand;
  const valAt = y => lo + ((lineBot - y) / lineBand) * span;   // padded headroom at the grid edges
  return { yOf, valAt, lo, hi, top: gridTop, bot: gridBot, lineTop, lineBot, occ };
}

// ── Institutional Wealth Normalization Layer (WN.1) ─────────────────────────
// Distinguish ORGANIC wealth movement from CAPITAL events (import / portfolio
// construction / large manual deposit-withdrawal). A massive one-snapshot level
// shift (e.g. 5,692 → 386,135 = +6683%) is NOT market performance and must not
// be drawn as such. This layer sits between getChartData and the curve. It NEVER
// mutates raw portfolioHistory; it returns a VISUAL series (a real-value slice
// focused on the most recent organic regime) plus capital-event metadata and an
// optional organic normalizedDeltaPct/Abs (exposed for future use, not shown).
function normalizeWealthSeriesForVisualization(values, timestamps, range) {
  const n = values.length;
  const pass = {
    values: values.slice(), timestamps: timestamps.slice(),
    capitalEvents: [], focusedFromIndex: 0,
    normalizedDeltaPct: null, normalizedDeltaAbs: null,
  };
  if (n < 4) return pass;   // too short to safely distinguish a regime shift

  const thr = _WSC_CAPITAL_JUMP[range] || 25;
  const med = arr => { const s = arr.slice().sort((a, b) => a - b); return s.length ? s[(s.length - 1) >> 1] : 0; };
  const SUSTAIN = 4;        // points confirming the new level holds (not a revert spike)

  // 1. Detect capital events on adjacent steps. A real capital event is a large
  //    adjacent jump that is ALSO a sustained regime shift — the LOCAL MEDIAN
  //    before vs after differs substantially. Comparing medians (not raw values)
  //    means a transient spike that reverts (preMed ≈ postMed) is NOT flagged —
  //    that's the despike layer's job — while a true level change (5,692 →
  //    386,135) is. Small-base→large is captured via the medians too.
  const events = [];
  for (let i = 1; i < n; i++) {
    const prev = values[i - 1], cur = values[i];
    if (!(prev > 0) || !(cur > 0)) continue;
    const jumpPct = Math.abs(cur / prev - 1) * 100;
    const preMed  = med(values.slice(Math.max(0, i - SUSTAIN), i));
    const postMed = med(values.slice(i, Math.min(n, i + SUSTAIN + 1)));
    if (!(preMed > 0) || !(postMed > 0)) continue;
    const levelDiffPct = Math.abs(postMed / preMed - 1) * 100;          // sustained regime change
    const smallBase    = Math.min(preMed, postMed) < 0.20 * Math.max(preMed, postMed);
    if (jumpPct >= thr && (levelDiffPct >= thr * 0.6 || smallBase)) {
      events.push({ index: i, timestamp: timestamps[i], prevValue: prev, nextValue: cur, jumpPct: +jumpPct.toFixed(2), range });
    }
  }
  if (!events.length) return pass;

  // 2. Split into organic regimes at the event boundaries and FOCUS the visual
  //    on the most recent regime with enough points (≥3); fall back to the
  //    longest regime, then to the full series. This drops the construction
  //    wall + pre-construction seed so the curve shows post-import organic
  //    movement only. The slice is REAL values at REAL timestamps.
  const bounds = [0, ...events.map(e => e.index), n];
  let seg = null;
  for (let k = bounds.length - 2; k >= 0; k--) {
    if (bounds[k + 1] - bounds[k] >= 3) { seg = [bounds[k], bounds[k + 1]]; break; }
  }
  if (!seg) {
    let bestLen = -1;
    for (let k = 0; k < bounds.length - 1; k++) {
      const len = bounds[k + 1] - bounds[k];
      if (len > bestLen) { bestLen = len; seg = [bounds[k], bounds[k + 1]]; }
    }
  }
  const [s, e] = seg;
  const fv = values.slice(s, e), ft = timestamps.slice(s, e);
  if (fv.length < 2) return { ...pass, capitalEvents: events };   // nothing focusable → keep raw

  const ndp = fv[0] > 0 ? (fv[fv.length - 1] / fv[0] - 1) * 100 : null;
  return {
    values: fv, timestamps: ft, capitalEvents: events, focusedFromIndex: s,
    normalizedDeltaPct: ndp, normalizedDeltaAbs: fv[fv.length - 1] - fv[0],
  };
}

// ── Institutional Time-Series Engine (WN.3) ─────────────────────────────────
// Sparse, session-clustered snapshots render as shelves / steps / walls. Real
// platforms never plot raw sparse points — they build a UNIFORM temporal series
// first. This does: per-range bucket aggregation (robust median) → an evenly
// spaced timeline → deterministic linear resampling that gap-fills the inactive
// periods between sessions as smooth ramps (no flat-then-wall). It only
// interpolates/aggregates REAL levels — no Math.random, no synthetic returns, no
// fabricated volatility. Endpoints are preserved exactly so the curve's net
// direction stays aligned with the (organic) metric.
// AURIX-PERFORMANCE-MODE-2 — 24H bucket 15min→5min: with ~140 real intraday points the
// 15min median collapsed microstructure into a flat/artificial line; 5min preserves the
// real shape (still bounded by _WSC_SAMPLES). Never fabricates — only aggregates real points.
const _WSC_BUCKET_MS = { '24h': 5 * 6e4, '7d': 2 * 36e5, '30d': 6 * 36e5, '1y': 864e5, 'all': 3 * 864e5 };
const _WSC_SAMPLES   = { '24h': 216, '7d': 192, '30d': 200, '1y': 216, 'all': 220 };  // WN.10 — dense interaction
function _wscResample(values, timestamps, range) {
  const n = values.length;
  const pass = { values: values.slice(), timestamps: timestamps.slice() };
  if (n < 2) return pass;

  // 1. Aggregate to time buckets using the robust median (collapses session
  //    clusters + intra-bucket noise into one representative level per bucket).
  const bucketMs = _WSC_BUCKET_MS[range] || 36e5;
  const t0 = timestamps[0], tLast = timestamps[n - 1];
  const buckets = new Map();
  for (let i = 0; i < n; i++) {
    const b = Math.floor((timestamps[i] - t0) / bucketMs);
    if (!buckets.has(b)) buckets.set(b, []);
    buckets.get(b).push(values[i]);
  }
  const aggT = [], aggV = [];
  [...buckets.keys()].sort((a, b) => a - b).forEach(b => {
    const arr = buckets.get(b).sort((x, y) => x - y);
    aggT.push(t0 + (b + 0.5) * bucketMs);
    aggV.push(arr[(arr.length - 1) >> 1]);
  });
  if (aggT.length < 2) return pass;
  // Preserve real endpoints exactly (levels + net direction → metric alignment).
  aggT[0] = t0;            aggV[0] = values[0];
  aggT[aggT.length - 1] = tLast; aggV[aggV.length - 1] = values[n - 1];

  // 2. Uniform timeline + 3. linear resample (gap-fill as smooth ramps).
  const N = _WSC_SAMPLES[range] || 150;
  const span = (aggT[aggT.length - 1] - aggT[0]) || 1;
  const outV = new Array(N), outT = new Array(N);
  let j = 0;
  for (let s = 0; s < N; s++) {
    const tt = aggT[0] + span * (s / (N - 1));
    while (j < aggT.length - 2 && aggT[j + 1] < tt) j++;
    const f = (tt - aggT[j]) / ((aggT[j + 1] - aggT[j]) || 1);
    outV[s] = aggV[j] + (aggV[j + 1] - aggV[j]) * Math.min(1, Math.max(0, f));
    outT[s] = tt;
  }
  return { values: outV, timestamps: outT };
}

// ════════════════════════════════════════════════════════════════════════
// AURIX-CHART-QUALITY-GATE-1 — institutional series-quality gate (24H/7D).
//
// A premium continuous curve is drawn ONLY when the window has enough REAL
// density + temporal coverage. Otherwise Aurix shows an honest protected state
// instead of interpolating 2-4 real points up to 216/192 samples (the straight-
// line artefact reported after asset add/remove/modify). PURE POLICY: it NEVER
// touches neutralisation, percentages, pricing or financial logic — it only
// decides RENDER vs PROTECT. 30D/1A/TOTAL keep current behaviour (only the
// extreme-anomaly floor of <2 points blocks them).
const _WSC_WINDOW_MS = { '24h': 864e5, '7d': 6048e5, '30d': 2592e6, '1y': 31536e6, 'all': null };
const _WSC_QUALITY = {
  '24h': { minPoints: 6, minBuckets: 4, minCoveragePct: 35, maxGapPct: 75 },
  '7d':  { minPoints: 8, minBuckets: 5, minCoveragePct: 30, maxGapPct: 80 },
};
// ≥ this many real eligible points → discrete "low-density" render; below → pure building state.
const _WSC_LOWDENSITY_MIN = 3;

function _wscAssessSeriesQuality(range, rawSeries, eligibleSeries, adjustedSeries) {
  const r = String(range || '').toLowerCase();
  const elig = Array.isArray(eligibleSeries) ? eligibleSeries : [];
  const q = {
    range: r,
    realPointCount: elig.length,
    distinctBucketCount: 0,
    timeCoveragePct: 0,
    largestGapPct: 0,
    hasEnoughDensity: false,
    hasEnoughCoverage: false,
    institutionalRenderable: false,
    reason: '',
  };
  if (elig.length < 2) { q.reason = 'insufficient_points(<2)'; return q; }

  // distinct temporal buckets (same bucketing _wscResample uses to collapse clusters)
  const bucketMs = _WSC_BUCKET_MS[r] || 36e5;
  const t0 = elig[0].ts, tLast = elig[elig.length - 1].ts;
  const seen = {};
  let buckets = 0;
  for (let i = 0; i < elig.length; i++) {
    const b = Math.floor((elig[i].ts - t0) / bucketMs);
    if (!seen[b]) { seen[b] = 1; buckets++; }
  }
  q.distinctBucketCount = buckets;

  // coverage/gap vs the FIXED window for bounded ranges; vs the data span for 'all'
  const windowMs = _WSC_WINDOW_MS[r];
  const denom = (windowMs && windowMs > 0) ? windowMs : ((tLast - t0) || 1);
  q.timeCoveragePct = +(((tLast - t0) / denom) * 100).toFixed(1);
  let maxGap = 0;
  for (let i = 1; i < elig.length; i++) { const g = elig[i].ts - elig[i - 1].ts; if (g > maxGap) maxGap = g; }
  q.largestGapPct = +((maxGap / denom) * 100).toFixed(1);

  const thr = _WSC_QUALITY[r];
  if (!thr) {
    // 30D / 1A / TOTAL — unchanged: renderable unless the extreme-anomaly floor (<2).
    q.hasEnoughDensity = elig.length >= 2;
    q.hasEnoughCoverage = true;
    q.institutionalRenderable = elig.length >= 2;
    q.reason = q.institutionalRenderable ? 'ok(long-range)' : 'insufficient_points(<2)';
    return q;
  }
  q.hasEnoughDensity  = q.realPointCount >= thr.minPoints && q.distinctBucketCount >= thr.minBuckets;
  q.hasEnoughCoverage = q.timeCoveragePct >= thr.minCoveragePct && q.largestGapPct <= thr.maxGapPct;
  q.institutionalRenderable = q.hasEnoughDensity && q.hasEnoughCoverage;
  if (q.institutionalRenderable) { q.reason = 'ok'; return q; }
  const why = [];
  if (q.realPointCount < thr.minPoints)      why.push('points ' + q.realPointCount + '<' + thr.minPoints);
  if (q.distinctBucketCount < thr.minBuckets) why.push('buckets ' + q.distinctBucketCount + '<' + thr.minBuckets);
  if (q.timeCoveragePct < thr.minCoveragePct) why.push('coverage ' + q.timeCoveragePct + '%<' + thr.minCoveragePct + '%');
  if (q.largestGapPct > thr.maxGapPct)        why.push('gap ' + q.largestGapPct + '%>' + thr.maxGapPct + '%');
  q.reason = why.join(', ');
  return q;
}

// Last-Known-Good per range. When a window renders at institutional quality we
// persist a compact record so a window that goes temporarily invalid right after
// a modification can fall back to the last reliable curve (faint, labelled)
// instead of a broken line. Never used when stale.
const _WSC_LASTGOOD_KEY = 'aurixLastGoodChartByRange';
const _WSC_LASTGOOD_MAX_AGE = { '24h': 6 * 36e5, '7d': 24 * 36e5, '30d': 7 * 864e5, '1y': 30 * 864e5, 'all': 30 * 864e5 };
function _wscLoadLastGood() {
  try { const raw = localStorage.getItem(_WSC_LASTGOOD_KEY); const o = raw ? JSON.parse(raw) : {}; return (o && typeof o === 'object') ? o : {}; }
  catch (_) { return {}; }
}
function _wscSaveLastGood(range, payload) {
  try { const all = _wscLoadLastGood(); all[String(range).toLowerCase()] = payload; localStorage.setItem(_WSC_LASTGOOD_KEY, JSON.stringify(all)); }
  catch (_) {}
}
function _wscGetFreshLastGood(range, now) {
  const r = String(range || '').toLowerCase();
  const rec = _wscLoadLastGood()[r];
  if (!rec || !Number.isFinite(rec.ts)) return null;
  const age = now - rec.ts, maxAge = _WSC_LASTGOOD_MAX_AGE[r] || 6 * 36e5;
  if (age < 0 || age > maxAge) return null;
  return rec;
}

// Protected render: drawn into the chart area (hostEl) when the window is NOT
// institutionally renderable. Reuses the existing .wsc--empty skin (no styles.css
// change) and overlays an OPTIONAL faint reference — the last-known-good curve
// ("Última evolución fiable") or, in low-density mode, the real points themselves.
// The % badge (changeEl) is left untouched: the percentage is correct, only the
// curve lacks density, so the number stays visible.
function _wscRenderInsufficient(hostEl, q, opts) {
  if (!hostEl) return;
  opts = opts || {};
  const W = _WSC_VIEW_W, H = _WSC_VIEW_H;
  const lowDensity = opts.mode === 'lowdensity';
  const eligible = Array.isArray(opts.eligible) ? opts.eligible : [];
  const lastGood = opts.lastGood || null;

  function polyline(pts, stroke, op, dots) {
    const ok = pts.filter(p => p && Number.isFinite(p.v) && Number.isFinite(p.t));
    if (ok.length < 2) return '';
    let mn = Infinity, mx = -Infinity; const t0 = ok[0].t, t1 = ok[ok.length - 1].t;
    ok.forEach(p => { if (p.v < mn) mn = p.v; if (p.v > mx) mx = p.v; });
    const padX = W * _WSC_PAD_X, plotW = W - 2 * padX, top = H * 0.20, bot = H * 0.80, band = bot - top;
    const span = (mx - mn) || 1, tspan = (t1 - t0) || 1;
    const X = p => (padX + ((p.t - t0) / tspan) * plotW).toFixed(1);
    const Y = p => (bot - ((p.v - mn) / span) * band).toFixed(1);
    const line = `<polyline points="${ok.map(p => X(p) + ',' + Y(p)).join(' ')}" fill="none" stroke="${stroke}" stroke-width="2" stroke-opacity="${op}" stroke-linejoin="round"/>`;
    const dotSvg = dots ? ok.map(p => `<circle cx="${X(p)}" cy="${Y(p)}" r="3" fill="${stroke}" fill-opacity="0.85"/>`).join('') : '';
    return line + dotSvg;
  }

  let refSvg = '', refLabel = '';
  if (lastGood && Array.isArray(lastGood.series) && Array.isArray(lastGood.tsArr) && lastGood.series.length >= 2) {
    refSvg = polyline(lastGood.series.map((v, i) => ({ t: lastGood.tsArr[i], v })), '#4D8DFF', 0.22, false);
    if (refSvg) refLabel = `<div class="wsc-empty-body" style="opacity:.6;font-size:.85em;margin-top:6px">${t('wscLastReliable')}</div>`;
  } else if (lowDensity && eligible.length >= 2) {
    refSvg = polyline(eligible.map(p => ({ t: p.ts, v: p.value })), '#9fb4d8', 0.5, true);
    if (refSvg) refLabel = `<div class="wsc-empty-body" style="opacity:.6;font-size:.85em;margin-top:6px">${t('wscLowDensityLabel')}</div>`;
  }

  const grid = [0.20, 0.5, 0.80].map(f => `<line x1="0" y1="${(H * f).toFixed(0)}" x2="${W}" y2="${(H * f).toFixed(0)}" stroke="currentColor" stroke-opacity="0.06"/>`).join('');
  const svg = `<svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="none" aria-hidden="true" style="position:absolute;left:0;top:0;width:100%;height:100%;pointer-events:none">${grid}${refSvg}</svg>`;
  const body = lowDensity ? t('wscLowDensityBody') : t('wscQualityGateBody');

  hostEl.innerHTML =
    `<div class="wsc wsc--empty" style="position:relative">${svg}` +
      `<div class="wsc-empty" style="position:relative">` +
        `<div class="wsc-empty-title">${t('wscQualityGateTitle')}</div>` +
        `<div class="wsc-empty-body">${body}</div>` +
        `<div class="wsc-empty-body" style="opacity:.7;margin-top:4px">${t('wscQualityGateSub')}</div>` +
        refLabel +
      `</div>` +
    `</div>`;
}

// ── WN.5 — Investable Portfolio Value datasource ────────────────────────────
// The Dashboard chart shows INVESTABLE value over time (stocks + ETFs + crypto
// + cash + metals + other; real estate EXCLUDED), in BASE currency to match the
// Hero. Reconstructed from categoryHistory (investable = total − real_estate per
// snapshot) so it is CLEAN even though legacy portfolioHistory stored total net
// worth incl. real estate. Raw history is never mutated. Windowed, epoch-filtered.
function _aurixInvestableSnapshots(range) {
  try {
    // P0-HISTORY-AUTHORITY-HARD-LOCK — read the AUTHORITATIVE display source (remote canonical for an
    // authenticated user; local cache only for anonymous/offline-anon). Local history never has final
    // authority for an authenticated user — its unconfirmed local-only points never reach baseline/return.
    const _src = (typeof _aurixHistorySourceForDisplay === 'function') ? _aurixHistorySourceForDisplay() : categoryHistory;
    if (!Array.isArray(_src)) return [];
    const epoch = (typeof _aurixPortfolioEpoch === 'function') ? _aurixPortfolioEpoch() : 0;
    // P0-CANONICAL-PERFORMANCE-ENGINE — the range window is anchored on the SHARED history's LAST snapshot
    // timestamp (canonical reference), NOT the device clock. Two devices reading the same canonical store
    // therefore window an IDENTICAL set of snapshots → identical baseline/series/return (deterministic).
    // Date.now() is only a defensive fallback when the source is empty. (Device-clock windowing was a
    // root cause of web/mobile divergence: a few seconds of skew shifted the 24H baseline.)
    let nowRef = 0;
    for (const _p of _src) { if (_p && Number.isFinite(_p.ts) && _p.ts > nowRef) nowRef = _p.ts; }
    if (!(nowRef > 0)) nowRef = Date.now();
    const ms = { '24h': 864e5, '7d': 6048e5, '30d': 2592e6, '1y': 31536e6 };
    const start = range === 'all' ? 0 : nowRef - (ms[range] || 2592e6);
    // FASE 1 — exclude INCOMPLETE snapshots (the main source of false vertical jumps:
    // e.g. 62.886 → 75.538 with no deposit). fxPartial = a holding had no price/FX at
    // capture (value undercounted); fxApprox = a non-historical FX fallback was used.
    // Both are dropped so only COMPLETE snapshots feed the canonical series. Defensive
    // fallback: if excluding fxApprox would leave < 2 points, keep approx (never starve
    // the chart / hide all data) — fxPartial is ALWAYS dropped.
    const build = (excludeApprox) => {
      const out = [];
      for (const p of _src) {
        if (!p || typeof p.ts !== 'number') continue;
        if (epoch && p.ts < epoch) continue;
        if (p.ts < start) continue;
        if (p.fxPartial === true) continue;                       // always drop partial-coverage
        if (excludeApprox && p.fxApprox === true) continue;       // drop approx FX (with fallback)
        const total = Number(p.total), re = Number(p.real_estate) || 0;
        const invUSD = (Number.isFinite(total) ? total : 0) - re;   // investable = total − real estate
        if (!Number.isFinite(invUSD) || invUSD <= 0) continue;
        // base currency, matches the Hero. `re`/`total` carried so the trust filter
        // can tell a RE-polluted / pre-investable-split point from a clean one.
        out.push({ ts: p.ts, value: toBase(invUSD, 'USD'), re: toBase(re, 'USD'), total: toBase(Number.isFinite(total) ? total : 0, 'USD') });
      }
      return out.sort((a, b) => a.ts - b.ts);
    };
    let out = build(true);                       // exclude fxPartial + fxApprox (complete only)
    if (out.length < 2) out = build(false);      // defensive: keep approx rather than empty the chart
    return out;
  } catch (_) { return []; }
}

// WN.6 — chart eligibility filter + active-window focus. Anchored on the CURRENT
// investable value, it drops a LEADING prefix of snapshots that are structurally
// incompatible with today's portfolio (old construction/import baselines, values
// wildly outside the investable family — e.g. 1.13M or 1.9k when current ≈ 61k),
// then trims a long dead-flat lead-in. This stops 1A/TOTAL showing −94% off an
// old baseline and 30D pinning to the floor. Raw history is never mutated;
// filtering happens at data-selection time. Returns { series, meta }.
function _aurixEligibleInvestableSeries(range) {
  const raw = _aurixInvestableSnapshots(range);
  const meta = {
    raw: raw.length, eligible: 0, excluded: 0,
    reasons: { real_estate_polluted: 0, pre_investable_split: 0, incompatible_regime: 0, construction_baseline: 0, stale_low_information: 0, insufficient_clean_data: 0 },
    anchor: null, activeWindowStart: null, activeWindowEnd: null,
  };
  if (raw.length < 2) { meta.eligible = raw.length; if (raw.length < 2) meta.reasons.insufficient_clean_data = 1; return { series: raw.slice(), meta }; }

  // P0-CANONICAL-PERFORMANCE-ENGINE — trust-filter anchor = the LAST SHARED SNAPSHOT value (canonical,
  // identical across devices), NOT the device-local live investableValueBase() (which differs by price/FX
  // capture timing and shifted the band → different points excluded → divergent baseline). The last shared
  // snapshot ≈ the live value (snapshots are recorded from it every 30 s) but is deterministic.
  let anchor = raw[raw.length - 1].value;
  if (!(anchor > 0)) { try { anchor = (typeof investableValueBase === 'function') ? investableValueBase() : 0; } catch (_) {} }
  meta.anchor = +anchor.toFixed(2);
  // WN.9 trust boundary — tighter than WN.6: a snapshot > 2.5× current investable
  // (without a valid external-deposit trail) or < 0.25× (without a valid external-
  // withdrawal trail) is an old/polluted/contaminated regime and is excluded from
  // the chart (this is what removes the −85% / 480k history on 1A/TOTAL).
  const LOW = anchor * 0.25, HIGH = anchor * 2.5, CONSTRUCTION = anchor * 0.15;

  // 1. WN.13 trust boundary — EXCLUDE EVERY out-of-band point, wherever it sits
  //    (not just a leading prefix). Scattered/mid-series RE-polluted or
  //    pre-investable-split snapshots (e.g. an old 444k total-incl-real-estate
  //    point among clean ~64k ones) used to survive and produce the −85% / 400k
  //    collapse on 1A/TOTAL. Now they are dropped everywhere; the uniform resample
  //    later interpolates across the resulting gaps. Reasons are classified for
  //    debug. A point is trusted only if its investable value sits within
  //    [0.25×, 2.5×] the current investable value.
  let series = [];
  for (const p of raw) {
    const v = p.value;
    if (v >= LOW && v <= HIGH) { series.push(p); continue; }
    meta.excluded++;
    if (v > HIGH) {
      // High outlier: real-estate still inside the total (re==0 ⇒ pre-split) or
      // an old RE-inclusive regime ⇒ real-estate contamination.
      if (!(p.re > 0)) meta.reasons.pre_investable_split++;
      else meta.reasons.real_estate_polluted++;
    } else if (v < CONSTRUCTION) {
      meta.reasons.construction_baseline++;
    } else {
      meta.reasons.incompatible_regime++;
    }
  }
  // real-estate polluted is the dominant intent for any high outlier
  meta.realEstateExcludedFromChart = true;

  // 2. WN.12 — trim a long NEAR-LINEAR lead-in (low CURVATURE: flat OR a steady
  //    straight ramp — both are low-information) so the chart never opens with a
  //    dead/linear segment. Detected via second differences (curvature), so even a
  //    steep-but-straight ramp is caught (the WN.7 |Δ| metric missed those). Trim
  //    only if the lead-in eats > 25% of the x-width; keep 1 context point.
  meta.staleLeadInRemoved = false;
  meta.activeTrimApplied = false;
  if (series.length >= 8) {
    const vals = series.map(s => s.value);
    const m = vals.length;
    let sdMax = 0; const sd = new Array(m).fill(0);
    for (let i = 1; i < m - 1; i++) { sd[i] = Math.abs(vals[i + 1] - 2 * vals[i] + vals[i - 1]); if (sd[i] > sdMax) sdMax = sd[i]; }
    if (sdMax > 0) {
      const thr = sdMax * 0.20;
      let f = 1; while (f < m - 3 && sd[f] < thr) f++;   // walk the low-curvature lead-in
      if (f > m * 0.25 && (m - f) >= 3) {
        const trimTo = Math.max(0, f - 1);               // keep ~1 point of context
        if (trimTo > 0) {
          meta.reasons.stale_low_information += trimTo; meta.excluded += trimTo;
          meta.staleLeadInRemoved = true; meta.activeTrimApplied = true;
          series = series.slice(trimTo);
        }
      }
    }
  }

  meta.eligible = series.length;
  if (series.length) { meta.activeWindowStart = series[0].ts; meta.activeWindowEnd = series[series.length - 1].ts; }
  if (series.length < 2) meta.reasons.insufficient_clean_data = 1;
  return { series, meta };
}

// WN.13 — public named entry: the trusted investable history regime for a range
// (real estate purged, polluted/pre-split/incompatible regimes excluded).
function getTrustedInvestableHistory(range) {
  return _aurixEligibleInvestableSeries(range || activeRange);
}

// WN.8 — flow CLASSIFICATION. INTERNAL transfers (asset buys/sells, construction
// imports) change portfolio COMPOSITION but not total value → neutralise them so
// the chart reads as a value-preserving transfer (no rug-pull). EXTERNAL cash
// flows (deposit / withdrawal) move money in/out of the portfolio → they DO change
// the value and are NOT neutralised (the value chart reflects them, like CMC/
// Kubera). Aurix's sell handler keeps proceeds conceptually in the portfolio (no
// auto cash leg), so a sell is treated as INTERNAL by default.
const _WSC_INTERNAL_KINDS = { asset_add: 1, asset_remove: 1, import_baseline: 1, internal_buy: 1, internal_sell: 1, internal_transfer: 1, qty_edit: 1 };
function _aurixFlowIsInternal(kind) { return !!_WSC_INTERNAL_KINDS[kind]; }
function _aurixFlowIntent(kind) {
  if (kind === 'asset_remove') return 'internal_sell';
  if (kind === 'asset_add')    return 'internal_buy';
  if (kind === 'import_baseline') return 'import_baseline';
  if (kind === 'deposit')    return 'external_deposit';
  if (kind === 'withdrawal') return 'external_withdrawal';
  return _aurixFlowIsInternal(kind) ? 'internal_transfer' : 'manual_adjustment';
}

// WN.11 — PERFORMANCE-ADJUSTED series. The Dashboard curve + metric show portfolio
// PERFORMANCE (market price movement), not raw value-delta: adding/removing money
// (deposits, withdrawals) and internal transfers (asset sold into cash, rebalance)
// must NOT count as gain/loss. Every large, SUSTAINED adjacent step is a capital
// event and is neutralised — INTERNAL transfers (no external proof) AND EXTERNAL
// deposits/withdrawals alike (a deposit raises value but is not a return). The step
// is removed so the curve continues smoothly, anchored to the real current value
// (Hero-consistent); ordinary (gradual) market moves are preserved. The recorded
// flow ledger is used to LABEL each neutralised step internal vs external (debug);
// shape detection also catches pre-ledger events (e.g. the June-16 BTC sale).
// Tooltip uses these adjusted values; raw history is never mutated.
// adjusted(i) = real(i) − cum(i) + cum(last), cum = Σ neutralised step deltas.
function _aurixFlowNeutralize(series, range) {
  const n = series.length;
  const out = { adjusted: series.map(s => s.value), flowsInRange: 0, neutralized: 0, totalOffset: 0,
                internalCount: 0, externalCount: 0, shapeTransfers: 0, externalWithdrawals: 0, externalDeposits: 0,
                internalNeutralized: 0, externalNeutralized: 0, recordedNeutralized: 0 };
  if (n < 2) return out;
  const t0 = series[0].ts, t1 = series[n - 1].ts;
  let anchor = 0;
  try { anchor = (typeof investableValueBase === 'function') ? investableValueBase() : 0; } catch (_) {}
  if (!(anchor > 0)) anchor = series[n - 1].value;

  // Recorded flows near the window — used to LABEL a neutralised step external
  // (recorded deposit/withdrawal nearby) vs internal (everything else).
  let flows = [];
  try { flows = (typeof _aurixLoadCapitalFlows === 'function') ? _aurixLoadCapitalFlows() : []; } catch (_) {}
  const NEAR = 36 * 36e5;
  const span = flows.filter(f => f && Number.isFinite(f.ts) && Number.isFinite(f.amountUSD) && f.ts > t0 - NEAR && f.ts <= t1 + NEAR);
  out.flowsInRange = span.filter(f => f.ts > t0 && f.ts <= t1).length;
  out.internalCount = span.filter(f => _aurixFlowIsInternal(f.kind)).length;
  const externalFlows = span
    .filter(f => f.kind === 'deposit' || f.kind === 'withdrawal')
    .map(f => ({ ts: f.ts, base: toBase(f.amountUSD, 'USD') }))
    .filter(f => Number.isFinite(f.base));
  out.externalCount   = externalFlows.length;
  out.externalDeposits    = externalFlows.filter(f => f.base > 0).length;
  out.externalWithdrawals = externalFlows.filter(f => f.base < 0).length;

  const vals = series.map(s => s.value), ts = series.map(s => s.ts);
  const med = arr => { const a = arr.slice().sort((x, y) => x - y); return a.length ? a[(a.length - 1) >> 1] : 0; };
  const STEP_THR = 0.18, SUSTAIN = 3;
  const stepOff = new Array(n).fill(0);

  // Pass A — SHAPE: large, sustained adjacent steps = capital events (catches
  // PRE-ledger events like the June-16 BTC sale). Neutralise the whole step.
  for (let i = 1; i < n; i++) {
    const d = vals[i] - vals[i - 1];
    const rel = Math.abs(d) / Math.max(vals[i - 1], anchor * 0.2, 1);
    const preMed = med(vals.slice(Math.max(0, i - SUSTAIN), i));
    const postMed = med(vals.slice(i, Math.min(n, i + SUSTAIN + 1)));
    const sustained = Math.abs(postMed - preMed) >= Math.abs(d) * 0.55;
    if (rel >= STEP_THR && sustained) {
      stepOff[i] = d; out.shapeTransfers++;
      const provenExternal = externalFlows.some(f =>
        Math.abs(f.ts - ts[i]) <= NEAR && Math.sign(f.base) === Math.sign(d) && Math.abs(f.base) >= Math.abs(d) * 0.40);
      if (provenExternal) out.externalNeutralized++; else out.internalNeutralized++;
    }
  }

  // Pass B — RECORDED LEDGER: every material recorded flow (deposit/withdrawal/
  // asset_add/asset_remove) is a capital event and must be neutralised too, even
  // when it is NOT a single big adjacent step (small or spread across sparse
  // snapshots). Applied at the snapshot just after the flow, de-duped against a
  // shape step already neutralised nearby. This is what makes WN.11 actually fire
  // on real recorded data instead of being a no-op.
  const RECORD_MAT = Math.max(anchor * 0.02, 1);
  span.forEach(f => {
    const base = toBase(f.amountUSD, 'USD');
    if (!Number.isFinite(base) || Math.abs(base) < RECORD_MAT) return;
    if (f.ts <= t0 || f.ts > t1) return;                 // only inside the rendered window
    let i = ts.findIndex(tt => tt >= f.ts);
    if (i <= 0) return;
    if (stepOff[i] || stepOff[i - 1] || (i + 1 < n && stepOff[i + 1])) return;  // already covered by a shape step
    stepOff[i] += base; out.recordedNeutralized++;
    if (_aurixFlowIsInternal(f.kind)) out.internalNeutralized++; else out.externalNeutralized++;
  });

  const cum = new Array(n).fill(0);
  let run = 0;
  for (let i = 0; i < n; i++) { run += stepOff[i]; cum[i] = run; }
  out.totalOffset = run;
  out.neutralized = out.shapeTransfers + out.recordedNeutralized;
  // AURIX-PERFORMANCE-MODE-2 — ANCHOR-TO-START (founder decision, institutional
  // performance-since-inception). adjusted(i) = v(i) − cum(i): the series STARTS at
  // the real first historical value (cum[0]=0 → adj[0]=v[0]) and removes each capital
  // step as it occurs, so the curve shows ONLY market movement. The endpoint =
  // v_last − Σflows (performance value, NOT current wealth — the hero shows current
  // wealth separately). Previously we added +run (anchor-to-current), which lifted the
  // start to ~v0+Σflows (~73k) — that was the reported "starts too high". No +run now.
  if (run !== 0) out.adjusted = vals.map((v, i) => v - cum[i]);
  return out;
}

// ════════════════════════════════════════════════════════════════════════
// AURIX-PERFORMANCE-MODE-2 — THE SINGLE INSTITUTIONAL SOURCE for the dashboard
// evolution chart. EVERY surface (WSC desktop #perfSnapshot, WSC mobile
// #wealthCurveMobile, V2 lightweight-charts .chart-wrap, tooltip, headline %) reads
// renderSeries from HERE. There is no other path that may paint a different curve.
//
//   • rawValueSeries   — eligible INVESTABLE values, no neutralisation (audit only)
//   • flowNeutralSeries — Performance series (anchor-to-start; capital flows removed)
//   • renderSeries     — what surfaces draw: flowNeutralSeries, or [] when 'building'
//   • mode             — premium-curve | partial-curve | building (3-mode policy)
//   • plus realPointCount / coveragePct / largestGapPct / first|lastRealPoint /
//     hiddenOrExcludedPoints / excludedReasons / capitalFlowsUsed / reason
//
// PURE READ. Never mutates state, never touches PCE, never fabricates a point.
// GRAPH-V1 FINAL (RULE 1) — THE one and only canonical portfolio VALUE series.
// value = actual investable portfolio value at each ts (matches the dashboard hero).
// RAW: no rebasing, no flow-neutral, no chart-only transform, no anchor manipulation.
// The tail is mark-to-market to the live value so the most recent point EQUALS the
// dashboard. Every timeframe is a WINDOW FILTER of this — there is no other builder.
// (Investable ⇔ the dashboard hero is investable; if the dashboard ever includes real
// estate, change the source HERE only and every timeframe follows.)
function getCanonicalPortfolioSeries() {
  let elig;
  try { elig = _aurixEligibleInvestableSeries('all'); } catch (_) { elig = { series: [], meta: {} }; }
  const snaps = (elig && Array.isArray(elig.series)) ? elig.series : [];
  const out = snaps
    .filter(s => s && Number.isFinite(s.ts) && Number.isFinite(s.value) && s.value > 0)
    .map(s => ({ ts: s.ts, value: s.value }))
    .sort((a, b) => a.ts - b.ts);
  // Tail = live (current dashboard value). Refresh a recent stale tail (feed-lag), or
  // append the current mark-to-market point. This is NOT rebasing — only the present
  // moment is set to the present value, so last(series) === dashboard for every window.
  let live = NaN;
  try { live = (typeof investableValueBase === 'function') ? Number(investableValueBase()) : NaN; } catch (_) {}
  if (Number.isFinite(live) && live > 0) {
    const now = Date.now();
    if (out.length && (now - out[out.length - 1].ts) < 6 * 36e5) out[out.length - 1] = { ts: out[out.length - 1].ts, value: live };
    else out.push({ ts: now, value: live });
  }
  out._meta = { excluded: (elig.meta && elig.meta.excluded) || 0, reasons: (elig.meta && elig.meta.reasons) || {} };
  return out;
}

// GRAPH-V1 (RULE 1/2/3) — a timeframe is a pure WINDOW FILTER of the canonical series.
// renderSeries IS the value series (the line, tooltip and axis all read it). Its last
// point === dashboard value for EVERY range (no divergence). The flow-neutral RETURN is
// metadata only (returnPct → header), never the line (RULE 6).
function getInstitutionalPerformanceSeries(range) {
  const r = String(range || (typeof activeRange !== 'undefined' ? activeRange : '30d')).toLowerCase();
  const out = {
    range: r, rawValueSeries: [], flowNeutralSeries: [], renderSeries: [], points: [],
    realPointCount: 0, coveragePct: 0, coverage: 0, largestGapPct: 0,
    firstRealPoint: null, lastRealPoint: null, firstValue: null, lastValue: null,
    hiddenOrExcludedPoints: 0, excludedReasons: {}, capitalFlowsUsed: 0,
    mode: 'building', renderMode: 'building', reason: '', returnPct: null,
    source: 'getCanonicalPortfolioSeries',
  };
  const canonical = getCanonicalPortfolioSeries();
  out.hiddenOrExcludedPoints = (canonical._meta && canonical._meta.excluded) || 0;
  out.excludedReasons        = (canonical._meta && canonical._meta.reasons) || {};

  const ms = { '24h': 864e5, '7d': 6048e5, '30d': 2592e6, '1y': 31536e6 };
  // P0-FIX-CHART-WINDOW-ANCHOR — anchor the range window on the DETERMINISTIC last-snapshot timestamp,
  // the SAME anchor the return/baseline path uses (_aurixInvestableSnapshots: nowRef = max ts of
  // _aurixHistorySourceForDisplay()). We DELIBERATELY anchor on the RAW shared history (not on `canonical`):
  // getCanonicalPortfolioSeries appends a live-tail point at ts=Date.now() when the last snapshot is ≥6h
  // stale, so anchoring on canonical's max ts would re-introduce the device clock. Anchoring on the raw
  // shared-history last snapshot guarantees chart window === return window. The filter has no upper bound,
  // so the appended live-tail point is still included (current value shown). Date.now() is only used when
  // the shared history is empty. ('all' is unaffected — start stays -Infinity.)
  // Identical to _aurixInvestableSnapshots: nowRef = max ts of the RAW shared history (NOT `canonical`,
  // which would re-introduce Date.now via getCanonicalPortfolioSeries' live-tail append). Empty ⇒ Date.now.
  let nowRef = 0;
  try {
    const _shared = (typeof _aurixHistorySourceForDisplay === 'function') ? _aurixHistorySourceForDisplay() : (typeof categoryHistory !== 'undefined' ? categoryHistory : null);
    if (Array.isArray(_shared)) for (const _p of _shared) { if (_p && Number.isFinite(_p.ts) && _p.ts > nowRef) nowRef = _p.ts; }
  } catch (_) {}
  const _anchorFromSnapshot = nowRef > 0;
  if (!_anchorFromSnapshot) nowRef = Date.now();   // empty-source fallback only
  out.windowAnchorTs = nowRef;
  out.windowAnchorSource = _anchorFromSnapshot ? 'last_snapshot_ts' : 'date_now_fallback';
  const start = (r === 'all') ? -Infinity : nowRef - (ms[r] || 2592e6);
  const win = canonical.filter(p => p && Number.isFinite(p.ts) && p.ts >= start && Number.isFinite(p.value) && p.value > 0);

  out.realPointCount = win.length;
  if (win.length < 2) { out.reason = 'insufficient_points(<2)'; out.mode = out.renderMode = 'building'; return out; }

  // RULE 1/4/5 — the VALUE series is the ONLY data: line, tooltip and y-axis all read it.
  out.rawValueSeries = win.map(p => ({ time: p.ts, value: p.value }));
  out.renderSeries   = out.rawValueSeries;
  out.points         = out.renderSeries;
  out.firstRealPoint = out.renderSeries[0];
  out.lastRealPoint  = out.renderSeries[out.renderSeries.length - 1];
  out.firstValue     = out.renderSeries[0].value;
  out.lastValue      = out.renderSeries[out.renderSeries.length - 1].value;

  // Coverage / gap drive ONLY the render mode (never the data/source).
  const winMs = (r === 'all') ? ((win[win.length - 1].ts - win[0].ts) || 1) : (ms[r] || 2592e6);
  out.coveragePct = +(((win[win.length - 1].ts - win[0].ts) / winMs) * 100).toFixed(1);
  out.coverage = out.coveragePct;
  let maxGap = 0; for (let i = 1; i < win.length; i++) { const g = win[i].ts - win[i - 1].ts; if (g > maxGap) maxGap = g; }
  out.largestGapPct = +((maxGap / winMs) * 100).toFixed(1);

  // RULE 7/13 — modes affect RENDERING only. premium (coverage≥80%) / partial (≥2 pts,
  // <80%; honest line that ALWAYS draws) / building (<2 pts — handled above).
  out.mode = out.renderMode = (out.coveragePct >= 80) ? 'premium-curve' : 'partial-curve';
  out.reason = 'coverage ' + out.coveragePct + '%';

  // RULE 6 — flow-neutral RETURN is metadata only (header %), never the line.
  try { const _rr = _aurixRangeReturn(r); out.returnPct = (_rr && Number.isFinite(_rr.deltaPct)) ? _rr.deltaPct : null; }
  catch (_) { out.returnPct = null; }
  // Kept for the audit/reference only (NOT rendered):
  out.flowNeutralSeries = out.renderSeries;
  out.capitalFlowsUsed = 0;
  return out;
}

// RULE 1 — public alias: getInstitutionalSeries(range) is the named single source.
function getInstitutionalSeries(range) { return getInstitutionalPerformanceSeries(range); }

// FASE 3 — THE single render accessor. WSC and V2 both consume EXACTLY this array, so
// the same timeframe can never look different across surfaces. It is the canonical
// renderSeries (already window-filtered + tail mark-to-market to live); NO surface
// applies its own dropDivergent / validate / anchor pass on top.
function getAurixRenderSeries(range) {
  try { return getInstitutionalPerformanceSeries(range).renderSeries || []; }
  catch (_) { return []; }
}

// FASE 4 — adapter for the DORMANT legacy Chart.js fallback (used only if V2
// lightweight-charts fails to mount). It builds the old getChartData object shape
// ({labels,values,timestamps,...}) from the CANONICAL render series, so getChartData is
// no longer a source of truth on ANY surface — every path resolves to the one canonical.
function _aurixLegacyDataFromCanonical(range) {
  const r = String(range || (typeof activeRange !== 'undefined' ? activeRange : '30d')).toLowerCase();
  const pts = getAurixRenderSeries(r);
  const fmtLbl = ts => { const d = new Date(ts);
    if (r === '24h') return d.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' });
    if (r === 'all') return d.toLocaleDateString('es-ES', { day: 'numeric', month: 'short', year: '2-digit' });
    return d.toLocaleDateString('es-ES', { day: 'numeric', month: 'short' }); };
  let firstValue = null;
  for (const p of pts) { if (Number.isFinite(p.value) && p.value > 0) { firstValue = p.value; break; } }
  const lastValue = pts.length ? pts[pts.length - 1].value : null;
  const deltaAbs = (Number.isFinite(firstValue) && Number.isFinite(lastValue)) ? +(lastValue - firstValue).toFixed(2) : null;
  const deltaPct = (Number.isFinite(firstValue) && firstValue > 0 && Number.isFinite(lastValue)) ? +(((lastValue - firstValue) / firstValue) * 100).toFixed(4) : null;
  return {
    labels: pts.map(p => fmtLbl(p.time)),
    values: pts.map(p => p.value),
    timestamps: pts.map(p => p.time),
    firstValue, lastValue, deltaAbs, deltaPct,
    pointsCount: pts.length, isLowData: pts.length < 2, source: 'canonical-fallback',
  };
}

// ════════════════════════════════════════════════════════════════════════
// AURIX — SPEC 1: RENDER CONTRACT & VISUAL QUALITY GATE
//
// The DEFINITIVE, measurable contract that decides whether a canonical series is
// fit to be drawn as an INSTITUTIONAL chart — BEFORE any new render algorithm
// (LTTB / monotone curve / gap render) is implemented. It is a PURE READ:
//   • it NEVER mutates assets / history / snapshots / storage,
//   • it NEVER changes financial values, %, pricing or PCE,
//   • it NEVER touches the canonical series (it only MEASURES getAurixRenderSeries).
//
// Principle: the render cannot decide freely. It receives a series and produces a
// VALIDATABLE result. If quality < threshold → it returns concrete `failures`, not
// "se ve mejor". Five measurable scores (0–100, higher = better) capture the visual
// pathologies reported on the current chart (clusters, vertical walls, ruler-straight
// runs, sparse density, untreated gaps); qualityScore aggregates them, and a hard
// rule asserts the last point still equals the dashboard (±0.5%).
//
// NON-NEGOTIABLE RULES enforced here (measurement only — no rendering performed):
//   1. lastPoint.value ≈ dashboardValue (tol 0.5%) — else immediate FAIL.
//   2. X axis is built on real timestamps (the contract maps p.time, never index).
//   3. Every visible point originates from the canonical render series.
//   4. No fabricated max/min — the contract reads the real value range only.
//   5. Visual quality is measurable (the five scores below).
const _AURIX_RC_QUALITY_THRESHOLD = { '24h': 85, '7d': 85, '30d': 90, '1y': 90, 'all': 90 };
const _AURIX_RC_WINDOW_MS = { '24h': 864e5, '7d': 6048e5, '30d': 2592e6, '1y': 31536e6 };
const _AURIX_RC_DASHBOARD_TOL = 0.005;   // 0.5% — rule 1
const _AURIX_RC_ASPECT = 0.42;           // plotHeight = plotWidth × aspect (constant aspect →
                                         // the SAME series scores identically on any viewport;
                                         // only the px magnitudes scale → desktop == mobile verdict)
const _AURIX_RC_PAD_FRAC = 0.04;         // horizontal padding (fraction of viewport)
const _AURIX_RC_VPAD_FRAC = 0.08;        // vertical padding (fraction of plot height)

// Scale-invariant projection of {time,value} → {x,y} px. Because both plotW and
// plotH scale linearly with the viewport, every RATIO used by the metrics (dy/dx,
// gap/width, deviation/height) is viewport-independent — so the contract's logical
// verdict is identical desktop vs mobile (rule for harness case 8).
function _aurixRenderContractGeometry(series, viewportWidth) {
  const vw = Math.max(240, Math.min(4000, Number(viewportWidth) || 390));
  const pad = vw * _AURIX_RC_PAD_FRAC;
  const plotW = Math.max(1, vw - 2 * pad);
  const plotH = Math.max(1, plotW * _AURIX_RC_ASPECT);
  const vpad = plotH * _AURIX_RC_VPAD_FRAC;
  const band = Math.max(1, plotH - 2 * vpad);
  const t0 = series[0].time, t1 = series[series.length - 1].time;
  const tspan = (t1 - t0) || 1;
  let vMin = Infinity, vMax = -Infinity;
  for (const p of series) { if (p.value < vMin) vMin = p.value; if (p.value > vMax) vMax = p.value; }
  const vspan = (vMax - vMin) || 1;
  const pts = series.map(p => ({
    t: p.time, v: p.value,
    x: pad + ((p.time - t0) / tspan) * plotW,
    y: (plotH - vpad) - ((p.value - vMin) / vspan) * band,
  }));
  return { pts, plotW, plotH, band, t0, t1, vMin, vMax };
}

// METRIC 1 — clusterScore. Penalises points jammed into few pixels, concentrated
// only at the right edge, or leaving huge untreated whitespace.
function _aurixRcClusterScore(g) {
  const pts = g.pts, n = pts.length;
  if (n < 4) return { score: 100, failure: null, warning: null, detail: { points: n } };
  const gaps = []; for (let i = 1; i < n; i++) gaps.push(pts[i].x - pts[i - 1].x);
  const totalW = (pts[n - 1].x - pts[0].x) || 1;
  const mean = totalW / (n - 1);
  const variance = gaps.reduce((s, x) => s + (x - mean) * (x - mean), 0) / gaps.length;
  const cv = mean > 0 ? Math.sqrt(variance) / mean : 0;                  // 0 = perfectly even
  const crammed = gaps.filter(x => x < mean * 0.25).length / gaps.length; // share of near-touching pairs
  const xThresh = pts[0].x + 0.82 * totalW;
  const rightShare = pts.filter(p => p.x >= xThresh).length / n;          // share past 82% of width
  const maxGapFrac = Math.max.apply(null, gaps) / totalW;                 // largest empty horizontal span
  let score = 100, failure = null, warning = null;
  score -= Math.min(40, cv * 45);
  score -= Math.min(35, crammed * 70);
  if (rightShare > 0.5 && maxGapFrac > 0.25) { score -= 25; failure = 'clustered_points_right_edge'; }
  else if (cv > 0.9 && crammed > 0.3) { warning = 'uneven_point_distribution'; }
  else if (maxGapFrac > 0.4) { warning = 'large_horizontal_whitespace'; }
  return { score: Math.max(0, Math.round(score)), failure, warning,
    detail: { cv: +cv.toFixed(2), crammedFrac: +crammed.toFixed(2), rightShare: +rightShare.toFixed(2), maxGapFrac: +maxGapFrac.toFixed(2) } };
}

// METRIC 2 — straightnessScore. Penalises long ruler-straight runs (segments with
// no microstructure, artificial horizontals, perfectly linear declines).
function _aurixRcStraightnessScore(g) {
  const pts = g.pts, n = pts.length;
  if (n < 4) return { score: 100, failure: null, warning: null, detail: { points: n } };
  const totalW = (pts[n - 1].x - pts[0].x) || 1;
  const eps = g.plotH * 0.012;             // collinearity tolerance (~1.2% of plot height)
  let longestSpanFrac = 0, straightCoverage = 0, runs = 0;
  let i = 0;
  while (i < n - 1) {
    let j = i + 1;
    while (j < n - 1) {                     // extend run while interior stays on the chord(i, j+1)
      const a = pts[i], b = pts[j + 1], dx = (b.x - a.x) || 1e-6;
      let maxDev = 0;
      for (let k = i + 1; k <= j; k++) {
        const cy = a.y + (b.y - a.y) * ((pts[k].x - a.x) / dx);
        const d = Math.abs(pts[k].y - cy); if (d > maxDev) maxDev = d;
      }
      if (maxDev > eps) break;
      j++;
    }
    if (j > i + 1) {                        // a straight run = ≥3 points (≥2 collinear segments)
      const spanFrac = (pts[j].x - pts[i].x) / totalW;
      if (spanFrac > 0.12) { straightCoverage += spanFrac; runs++; }
      if (spanFrac > longestSpanFrac) longestSpanFrac = spanFrac;
    }
    i = Math.max(j, i + 1);
  }
  let score = 100, failure = null, warning = null;
  score -= Math.min(70, Math.max(0, longestSpanFrac - 0.25) * 140);
  score -= Math.min(25, Math.max(0, straightCoverage - 0.4) * 60);
  if (longestSpanFrac > 0.55) failure = 'too_many_straight_segments';
  else if (longestSpanFrac > 0.35) warning = 'mild_straight_segment';
  return { score: Math.max(0, Math.round(score)), failure, warning,
    detail: { longestStraightSpanFrac: +longestSpanFrac.toFixed(3), straightCoverage: +straightCoverage.toFixed(3), straightRuns: runs } };
}

// METRIC 3 — verticalJumpScore. Penalises near-vertical walls: a large value move
// over a step where time barely advances (incompatible with an institutional curve
// unless segmented/annotated — which the current pipeline does not do).
function _aurixRcVerticalJumpScore(g) {
  const pts = g.pts, n = pts.length;
  if (n < 2) return { score: 100, failure: null, warning: null, detail: { points: n } };
  const totalW = (pts[n - 1].x - pts[0].x) || 1;
  const meanGapFrac = 1 / (n - 1);
  let worst = 0, walls = 0, penalty = 0;
  for (let i = 1; i < n; i++) {
    const dyFrac = Math.abs(pts[i].y - pts[i - 1].y) / g.plotH;
    const dxFrac = Math.abs(pts[i].x - pts[i - 1].x) / totalW;
    if (dyFrac > 0.18 && dxFrac < Math.min(0.04, meanGapFrac * 0.5)) {
      walls++;
      const severity = (dyFrac - 0.18) + (0.04 - dxFrac);
      penalty += Math.min(60, 30 + severity * 150);
      if (dyFrac > worst) worst = dyFrac;
    }
  }
  let score = Math.max(0, Math.round(100 - penalty)), failure = null, warning = null;
  if (walls > 0 && worst > 0.30) failure = 'vertical_jump_unclassified';
  else if (walls > 0) warning = 'minor_vertical_step';
  return { score, failure, warning, detail: { wallCount: walls, worstJumpFrac: +worst.toFixed(3) } };
}

// METRIC 4 — densityScore. Is the visible point count adequate for the range? Kept
// viewport-INDEPENDENT (range minimums + temporal coverage), so desktop and mobile
// reach the same verdict; an extreme-overcrowding guard is the only mild px factor.
function _aurixRcDensityScore(range, n, coveragePct, g) {
  const minPts = (_WSC_QUALITY[range] && _WSC_QUALITY[range].minPoints) || 6;
  const ideal = minPts * 2.5;
  let score = 100, failure = null, warning = null;
  if (n < minPts) { score -= 55; failure = 'insufficient_density'; }
  else if (n < ideal) { score -= (1 - (n - minPts) / (ideal - minPts)) * 25; warning = 'sparse_for_range'; }
  if (coveragePct < 35) score -= 20;
  else if (coveragePct < 60) score -= 8;
  // extreme overcrowding (sub-pixel point spacing) — independent of the above
  if (n > 3 && g && g.plotW) {
    const pxPerPoint = g.plotW / (n - 1);
    if (pxPerPoint < 1.5) { score -= 15; warning = warning || 'overcrowded_points'; }
  }
  return { score: Math.max(0, Math.round(score)), failure, warning, detail: { points: n, minPts, coveragePct } };
}

// METRIC 5 — continuityScore. Does the curve tell a continuous visual story?
// Penalises untreated large temporal gaps and low window coverage (abrupt/partial
// curve). A gap is "untreated" because the current pipeline neither annotates nor
// segments regime changes — exactly what later phases will address.
function _aurixRcContinuityScore(coveragePct, largestGapPct) {
  let score = 100, failure = null, warning = null;
  if (largestGapPct > 60) { score -= 55; failure = 'untreated_large_gap'; }
  else if (largestGapPct > 40) { score -= 30; warning = 'large_gap'; }
  else if (largestGapPct > 25) { score -= 12; warning = 'moderate_gap'; }
  if (coveragePct < 35) { score -= 25; failure = failure || 'low_time_coverage'; }
  else if (coveragePct < 60) { score -= 10; warning = warning || 'partial_time_coverage'; }
  return { score: Math.max(0, Math.round(score)), failure, warning, detail: { coveragePct, largestGapPct } };
}

// PURE core — measures an already-resolved (range, series, dashboardValue, viewport)
// and returns the full render contract. Separated from getAurixRenderContract so the
// harness can drive it with synthetic series without any DOM.
function _aurixComputeRenderContract(range, series, dashboardValue, viewportWidth) {
  const r = String(range || '30d').toLowerCase();
  const pts = Array.isArray(series) ? series.filter(p => p && Number.isFinite(p.time) && Number.isFinite(p.value)) : [];
  const dash = Number.isFinite(dashboardValue) ? +dashboardValue : null;
  const thr = _AURIX_RC_QUALITY_THRESHOLD[r] || 90;

  const out = {
    range: r, viewportWidth: Math.max(240, Math.min(4000, Number(viewportWidth) || 390)),
    canonicalPoints: pts, visiblePoints: pts,         // no downsampling yet → visible === canonical
    firstPoint: pts.length ? { time: pts[0].time, value: +pts[0].value.toFixed(2) } : null,
    lastPoint: pts.length ? { time: pts[pts.length - 1].time, value: +pts[pts.length - 1].value.toFixed(2) } : null,
    dashboardValue: dash != null ? +dash.toFixed(2) : null,
    lastPointDeltaPct: null,
    pointCount: pts.length, visiblePointCount: pts.length,
    timeCoveragePct: 0, largestGapPct: 0, largestGapMs: 0,
    clusterScore: 0, straightnessScore: 0, verticalJumpScore: 0, densityScore: 0, continuityScore: 0,
    renderMode: 'building', qualityThreshold: thr, qualityScore: 0,
    failures: [], warnings: [],
  };

  // RULE — < 2 points cannot be a curve.
  if (pts.length < 2) {
    out.renderMode = 'building';
    out.failures.push('insufficient_points');
    return out;
  }

  // Coverage / gap on REAL timestamps (rule 2).
  const t0 = pts[0].time, t1 = pts[pts.length - 1].time;
  const span = (t1 - t0) || 1;
  const denom = (r === 'all') ? span : (_AURIX_RC_WINDOW_MS[r] || 2592e6);
  out.timeCoveragePct = +((span / denom) * 100).toFixed(1);
  let maxGapMs = 0; for (let i = 1; i < pts.length; i++) { const gp = pts[i].time - pts[i - 1].time; if (gp > maxGapMs) maxGapMs = gp; }
  out.largestGapMs = maxGapMs;
  out.largestGapPct = +((maxGapMs / denom) * 100).toFixed(1);

  // RULE 1 (NON-NEGOTIABLE) — last point must equal the dashboard within 0.5%.
  if (dash != null && dash > 0) {
    out.lastPointDeltaPct = +(((out.lastPoint.value - dash) / dash) * 100).toFixed(4);
    if (Math.abs(out.lastPoint.value - dash) / dash > _AURIX_RC_DASHBOARD_TOL) {
      out.failures.push('last_point_not_dashboard');
    }
  }

  // Visual scores on the scale-invariant geometry.
  const g = _aurixRenderContractGeometry(pts, out.viewportWidth);
  const mCluster   = _aurixRcClusterScore(g);
  const mStraight  = _aurixRcStraightnessScore(g);
  const mJump      = _aurixRcVerticalJumpScore(g);
  const mDensity   = _aurixRcDensityScore(r, pts.length, out.timeCoveragePct, g);
  const mContinu   = _aurixRcContinuityScore(out.timeCoveragePct, out.largestGapPct);
  out.clusterScore = mCluster.score; out.straightnessScore = mStraight.score;
  out.verticalJumpScore = mJump.score; out.densityScore = mDensity.score; out.continuityScore = mContinu.score;
  [mCluster, mStraight, mJump, mDensity, mContinu].forEach(m => {
    if (m.failure && out.failures.indexOf(m.failure) < 0) out.failures.push(m.failure);
    if (m.warning && out.warnings.indexOf(m.warning) < 0) out.warnings.push(m.warning);
  });
  out._detail = { cluster: mCluster.detail, straightness: mStraight.detail, verticalJump: mJump.detail, density: mDensity.detail, continuity: mContinu.detail };

  // qualityScore = blend of average and WORST dimension, so a single concrete
  // pathology drags the score down (an institutional chart is only as good as its
  // weakest visual property). Hard dashboard divergence forces 0 (rule 1).
  const scores = [out.clusterScore, out.straightnessScore, out.verticalJumpScore, out.densityScore, out.continuityScore];
  const avg = scores.reduce((s, x) => s + x, 0) / scores.length;
  const min = Math.min.apply(null, scores);
  let quality = Math.round(0.55 * avg + 0.45 * min);
  if (out.failures.indexOf('last_point_not_dashboard') >= 0) quality = 0;          // rule 1 override
  else if (out.failures.length > 0) quality = Math.min(quality, thr - 6);          // any concrete failure ⇒ sub-threshold
  out.qualityScore = Math.max(0, Math.min(100, quality));

  // renderMode verdict (this contract decides RENDER-READINESS; it does NOT render).
  if (out.failures.indexOf('last_point_not_dashboard') >= 0) out.renderMode = 'fail-dashboard-divergence';
  else if (out.qualityScore >= thr) out.renderMode = 'institutional';
  else out.renderMode = 'sub-institutional';
  return out;
}

// SPEC 1 ENTRY — getAurixRenderContract(range, viewportWidth). Resolves the canonical
// render series + the live dashboard value + the viewport, then measures. PURE READ.
function getAurixRenderContract(range, viewportWidth) {
  const r = String(range || (typeof activeRange !== 'undefined' ? activeRange : '30d')).toLowerCase();
  let series = [];
  try { series = getAurixRenderSeries(r) || []; } catch (_) { series = []; }
  let dash = NaN;
  try { dash = Number(investableValueBase()); } catch (_) {}
  let vw = Number(viewportWidth);
  if (!(vw > 0)) { try { vw = (typeof window !== 'undefined' && window.innerWidth) ? window.innerWidth : 390; } catch (_) { vw = 390; } }
  const contract = _aurixComputeRenderContract(r, series, dash, vw);
  // SPEC 2 (section 9) — NON-SCORING enrichment. Surface the visual-preparation
  // summary (gaps/clusters/redundancy/target vs actual density) WITHOUT touching
  // qualityScore / renderMode / failures. Guarded by a typeof check so it is a
  // no-op where prepareAurixVisualSeries is absent (keeps SPEC-1 harness green).
  try {
    if (typeof prepareAurixVisualSeries === 'function') {
      const prep = prepareAurixVisualSeries(r, vw);
      contract.preparation = {
        gaps: prep.gaps.length, clusters: prep.clusters.length,
        redundantPoints: prep.redundantPoints.length, capitalEvents: prep.capitalEvents.length,
        targetPointCount: prep.targetPointCount, actualPointCount: prep.actualPointCount,
      };
    }
  } catch (_) {}
  // SPEC 3 (section 12) — NON-SCORING enrichment from the Institutional Render
  // Engine (if present): point count after downsampling, interpolation, gap
  // segments, event markers, whether a path was generated, and overshoot. Same
  // typeof guard → never alters scoring, no-op where the engine is absent.
  try {
    if (typeof renderAurixInstitutionalChart === 'function') {
      const rc = renderAurixInstitutionalChart(r, vw);
      contract.institutionalRender = {
        pointCountAfter: rc.renderMeta.pointCountAfter,
        interpolation: rc.renderMeta.interpolation,
        gapSegments: rc.gapSegments.length,
        eventMarkers: rc.eventMarkers.length,
        pathGenerated: !!(rc.pathData && rc.pathData.length),
        overshootDetected: !!rc.renderMeta.overshootDetected,
      };
    }
  } catch (_) {}
  return contract;
}

// SPEC 1 DEBUG — single range + all ranges, printing the mandated table.
if (typeof window !== 'undefined') {
  window.debugAurixRenderContract = (range) => {
    const r = range || (typeof activeRange !== 'undefined' ? activeRange : '30d');
    const c = getAurixRenderContract(r);
    try {
      console.table([{
        range: c.range, dashboardValue: c.dashboardValue,
        lastPoint: c.lastPoint ? c.lastPoint.value : null, lastDeltaPct: c.lastPointDeltaPct,
        canonicalPoints: c.pointCount, visiblePoints: c.visiblePointCount,
        coveragePct: c.timeCoveragePct, largestGapPct: c.largestGapPct,
        clusterScore: c.clusterScore, straightnessScore: c.straightnessScore,
        verticalJumpScore: c.verticalJumpScore, densityScore: c.densityScore, continuityScore: c.continuityScore,
        qualityScore: c.qualityScore, renderMode: c.renderMode,
        failures: (c.failures || []).join(' | ') || '—',
      }]);
      if (c.warnings && c.warnings.length) console.log('[render-contract] warnings:', c.warnings.join(', '));
      console.log('[render-contract] detail:', c._detail);
    } catch (_) {}
    return c;
  };
  window.debugAurixRenderContractAll = () => {
    const rows = ['24h', '7d', '30d', '1y', 'all'].map(r => getAurixRenderContract(r));
    try {
      console.table(rows.map(c => ({
        range: c.range, dashboardValue: c.dashboardValue,
        lastPoint: c.lastPoint ? c.lastPoint.value : null, lastDeltaPct: c.lastPointDeltaPct,
        canonicalPoints: c.pointCount, visiblePoints: c.visiblePointCount,
        coveragePct: c.timeCoveragePct, largestGapPct: c.largestGapPct,
        cluster: c.clusterScore, straight: c.straightnessScore, vJump: c.verticalJumpScore,
        density: c.densityScore, continuity: c.continuityScore,
        quality: c.qualityScore, threshold: c.qualityThreshold, mode: c.renderMode,
        failures: (c.failures || []).join('|') || '—',
      })));
    } catch (_) {}
    return rows;
  };
}

// ════════════════════════════════════════════════════════════════════════
// AURIX — SPEC 2: VISUAL PREPARATION ENGINE
//
// A PURE preparation layer between the canonical series and the (future)
// Institutional Render Engine. It does NOT beautify the curve — it only MEASURES
// and CLASSIFIES so a later phase can draw a premium line without ever touching
// financial data. PURE READ: NEVER mutates assets / history / snapshots / write
// guard / PCE / dashboard / pricing / CSS / the canonical series.
//
// Output `preparedPoints` contains ONLY real existing points (no fabricated
// values, no aggressive deletion in this phase) → last point still == dashboard.
//
// Detects: temporal GAPS, visual CLUSTERS (timestamp + viewport px), REDUNDANT
// points (low shape contribution), CAPITAL EVENTS (read-only ledger) for future
// annotation, and the optimal targetPointCount per range × viewport.
// SPEC 6 — Adaptive Density: higher caps so more REAL local detail survives the
// downsample (less over-smoothing on 1A/TOTAL, richer microstructure on 24H/7D).
// Still bounded so the chart never becomes a noisy/over-dense mess. Pure render.
// RC1-B increment 4 (Fase 5 density): target = clamp(round(vw/5)=~200, min, max), so the
// long ranges were all floored at ~200 pts. Raise the long-range MIN (1y 180→280, all
// 200→320) so 1A reads "evolución consistente" and TOTAL reads a rich "historia de
// patrimonio" — never compressed. Calibration constant only: a FAITHFUL downsample keeps
// MORE real points (LTTB + local-extrema); first/last/extrema/values/timestamps invariant
// (equivalence holds); never fabricates points (users with less history render what exists).
const _AURIX_VP_DENSITY = {
  '24h': { min: 80,  max: 180 },
  '7d':  { min: 120, max: 240 },
  '30d': { min: 140, max: 300 },
  '1y':  { min: 280, max: 400 },
  'all': { min: 320, max: 450 },
};
// BUGFIX P0 — gap thresholds are ADAPTIVE, not fixed absolutes. The previous fixed
// values (24h:90min, 7d:8h, 30d:36h, 1y:21d) were far smaller than real snapshot
// cadence, so ordinary sampling intervals (overnight quiet, weekends, sparser old
// history) were misclassified as gaps and fragmented every range — and shattered
// the early 1A/TOTAL history into stubs (it read as "missing"). A gap now requires a
// hole that DWARFS the data's own rhythm (≥ MEDIAN_MULT × the median interval) AND
// exceeds a generous absolute floor — so continuous data is drawn continuous and
// only a genuine, large, documented outage breaks the line.
const _AURIX_VP_GAP_FLOOR_MS = {
  '24h': 8 * 36e5,     // 8 h   — an 8h+ hole in a 24h window
  '7d':  2 * 864e5,    // 2 d
  '30d': 7 * 864e5,    // 7 d
  '1y':  45 * 864e5,   // 45 d
  'all': 45 * 864e5,   // 45 d  (also floored to span/8 below)
};
const _AURIX_VP_GAP_MEDIAN_MULT = 8;   // a real gap is ≥ 8× the median inter-point interval
const _AURIX_VP_CAPITAL_KINDS = { deposit: 1, withdrawal: 1, asset_add: 1, asset_remove: 1, import_baseline: 1 };
const _AURIX_VP_CLUSTER_WIDTH_PX = 5;   // a band of ≤5px …
const _AURIX_VP_CLUSTER_MIN_PTS  = 4;   // … holding ≥4 points is a visual cluster
const _AURIX_VP_VALUE_EPS = 0.004;      // 0.4% of value span = "minimal value delta"

// SPEC 6 — targetPointCount ≈ viewport/5 (denser end of the viewport/5..viewport/7
// band → ~1 candidate point per 5 CSS px), clamped to the per-range [min,max].
// Deterministic in (range, viewportWidth). Pure render; never affects data.
function _aurixVpTargetPointCount(range, viewportWidth) {
  const band = _AURIX_VP_DENSITY[range] || _AURIX_VP_DENSITY['30d'];
  const vw = Math.max(240, Math.min(4000, Number(viewportWidth) || 390));
  const raw = Math.round(vw / 5);
  return Math.max(band.min, Math.min(band.max, raw));
}

// PURE core — measures a resolved (range, series, dashboard, viewport, flows).
// Separated from prepareAurixVisualSeries so the harness can drive it DOM-free.
function _aurixComputeVisualPreparation(range, series, dashboardValue, viewportWidth, capitalFlows) {
  const r = String(range || '30d').toLowerCase();
  const vw = Math.max(240, Math.min(4000, Number(viewportWidth) || 390));
  // Defensive copy + sanity filter — NEVER mutate the caller's array.
  const src = (Array.isArray(series) ? series : [])
    .filter(p => p && Number.isFinite(p.time) && Number.isFinite(p.value))
    .map(p => ({ time: p.time, value: p.value }))
    .sort((a, b) => a.time - b.time);
  const dash = Number.isFinite(dashboardValue) ? +dashboardValue : null;

  const out = {
    range: r, viewportWidth: vw,
    sourcePoints: src,
    preparedPoints: src.map(p => ({ time: p.time, value: p.value })),   // SPEC 2: real points only, no removal
    gaps: [], clusters: [], redundantPoints: [], capitalEvents: [],
    gapThresholdMs: 0, medianIntervalMs: 0,
    targetPointCount: _aurixVpTargetPointCount(r, vw),
    actualPointCount: src.length,
    firstPoint: src.length ? { time: src[0].time, value: +src[0].value.toFixed(2) } : null,
    lastPoint:  src.length ? { time: src[src.length - 1].time, value: +src[src.length - 1].value.toFixed(2) } : null,
    meta: {
      source: 'canonical', deterministic: true,
      lastValue: src.length ? +src[src.length - 1].value.toFixed(2) : null,
      dashboardValue: dash != null ? +dash.toFixed(2) : null,
      lastDeltaPct: null,
    },
  };
  if (out.lastPoint && dash != null && dash > 0) {
    out.meta.lastDeltaPct = +(((out.lastPoint.value - dash) / dash) * 100).toFixed(4);
  }
  const n = src.length;
  if (n < 2) return out;

  const t0 = src[0].time, t1 = src[n - 1].time, totalSpan = (t1 - t0) || 1;

  // ── §3 GAPS (real temporal holes; detect + report, do NOT cut) ─────────────
  // BUGFIX P0 — adaptive threshold: a gap must be ≥ MEDIAN_MULT × the median
  // inter-point interval AND exceed the per-range absolute floor. This keeps a
  // continuous (even if irregularly sampled) series continuous and only cuts on a
  // genuine, large outage. Every cut is reported with its threshold for debug.
  const intervals = []; for (let i = 1; i < n; i++) intervals.push(src[i].time - src[i - 1].time);
  const ivSorted = intervals.slice().sort((a, b) => a - b);
  const medianIv = ivSorted.length ? ivSorted[ivSorted.length >> 1] : 0;
  const floor = (r === 'all')
    ? Math.max(_AURIX_VP_GAP_FLOOR_MS.all, totalSpan / 8)
    : (_AURIX_VP_GAP_FLOOR_MS[r] || 7 * 864e5);
  const gapThr = Math.max(floor, medianIv * _AURIX_VP_GAP_MEDIAN_MULT);
  out.gapThresholdMs = gapThr; out.medianIntervalMs = medianIv;
  const gapAdjacent = new Set();
  for (let i = 1; i < n; i++) {
    const dur = src[i].time - src[i - 1].time;
    if (dur > gapThr) {
      out.gaps.push({ start: src[i - 1].time, end: src[i].time, durationMs: dur, threshold: gapThr, reason: 'time_gap' });
      gapAdjacent.add(i - 1); gapAdjacent.add(i);
    }
  }

  // ── §4 CLUSTERS (too many points in few px; real timestamp + viewport) ─────
  const g = _aurixRenderContractGeometry(src.map(p => ({ time: p.time, value: p.value })), vw);
  let ci = 0;
  while (ci < n) {
    let cj = ci;
    while (cj + 1 < n && (g.pts[cj + 1].x - g.pts[ci].x) <= _AURIX_VP_CLUSTER_WIDTH_PX) cj++;
    const count = cj - ci + 1;
    if (count >= _AURIX_VP_CLUSTER_MIN_PTS) {
      const widthPx = g.pts[cj].x - g.pts[ci].x;
      out.clusters.push({
        start: src[ci].time, end: src[cj].time, pointCount: count,
        widthPx: +widthPx.toFixed(2), density: +(count / Math.max(widthPx, 0.5)).toFixed(2),
        reason: 'visual_cluster',
      });
      ci = cj + 1;
    } else ci++;
  }

  // ── §7 CAPITAL EVENTS (read-only ledger; near the window → future annotation) ─
  const evPad = totalSpan * 0.05;
  const flows = Array.isArray(capitalFlows) ? capitalFlows : [];
  flows.forEach(f => {
    if (!f || !Number.isFinite(f.ts) || !Number.isFinite(f.amountUSD)) return;
    if (!_AURIX_VP_CAPITAL_KINDS[f.kind]) return;
    if (f.ts < t0 - evPad || f.ts > t1 + evPad) return;
    const relMag = (dash && dash > 0) ? Math.abs(f.amountUSD) / dash : 0;
    const visualPriority = (f.kind === 'import_baseline' || relMag >= 0.05) ? 'high' : (relMag >= 0.01 ? 'medium' : 'low');
    out.capitalEvents.push({ timestamp: f.ts, type: f.kind, amountUSD: +Number(f.amountUSD).toFixed(2), visualPriority });
  });
  out.capitalEvents.sort((a, b) => a.timestamp - b.timestamp);
  const eventNearMs = gapThr;

  // ── §5 REDUNDANT POINTS (classify only — never delete in SPEC 2) ───────────
  // A point contributes no visual shape when it is collinear with its neighbours
  // AND its value barely moves — provided it is not an extremum, endpoint, near a
  // capital event, or adjacent to a gap (those carry meaning even if "flat").
  const vspan = (g.vMax - g.vMin) || 1;
  const eps = g.plotH * 0.012;
  for (let i = 1; i < n - 1; i++) {
    const vPrev = src[i - 1].value, v = src[i].value, vNext = src[i + 1].value;
    const isMax = v > vPrev && v > vNext;
    const isMin = v < vPrev && v < vNext;
    if (isMax || isMin) continue;
    if (gapAdjacent.has(i)) continue;
    const valDelta = Math.max(Math.abs(v - vPrev), Math.abs(vNext - v)) / vspan;
    const dx = (g.pts[i + 1].x - g.pts[i - 1].x) || 1e-6;
    const chordY = g.pts[i - 1].y + (g.pts[i + 1].y - g.pts[i - 1].y) * ((g.pts[i].x - g.pts[i - 1].x) / dx);
    const chordDevPx = Math.abs(g.pts[i].y - chordY);
    const nearEvent = out.capitalEvents.some(e => Math.abs(e.timestamp - src[i].time) <= eventNearMs);
    if (nearEvent) continue;
    if (valDelta < _AURIX_VP_VALUE_EPS && chordDevPx < eps) {
      out.redundantPoints.push({ index: i, time: src[i].time, value: +v.toFixed(2), reason: 'low_shape_contribution' });
    }
  }

  return out;
}

// SPEC 2 ENTRY — prepareAurixVisualSeries(range, viewportWidth). Resolves the
// canonical render series + live dashboard + viewport + capital ledger, then
// measures. PURE READ — input series is never mutated.
function prepareAurixVisualSeries(range, viewportWidth) {
  const r = String(range || (typeof activeRange !== 'undefined' ? activeRange : '30d')).toLowerCase();
  let series = [];
  try { series = getAurixRenderSeries(r) || []; } catch (_) { series = []; }
  let dash = NaN;
  try { dash = Number(investableValueBase()); } catch (_) {}
  let vw = Number(viewportWidth);
  if (!(vw > 0)) { try { vw = (typeof window !== 'undefined' && window.innerWidth) ? window.innerWidth : 390; } catch (_) { vw = 390; } }
  let flows = [];
  try { flows = (typeof _aurixLoadCapitalFlows === 'function') ? _aurixLoadCapitalFlows() : []; } catch (_) { flows = []; }
  return _aurixComputeVisualPreparation(r, series, dash, vw, flows);
}

// SPEC 2 DEBUG — single range + all ranges.
if (typeof window !== 'undefined') {
  window.debugAurixVisualPreparation = (range) => {
    const r = range || (typeof activeRange !== 'undefined' ? activeRange : '30d');
    const p = prepareAurixVisualSeries(r);
    const status = (p.lastPoint && p.meta.lastDeltaPct != null && Math.abs(p.meta.lastDeltaPct) <= 0.5) ? 'ok'
      : (p.preparedPoints.length < 2 ? 'building' : 'review');
    try {
      console.table([{
        range: p.range, sourcePoints: p.sourcePoints.length, preparedPoints: p.preparedPoints.length,
        targetPointCount: p.targetPointCount, gaps: p.gaps.length, clusters: p.clusters.length,
        redundantPoints: p.redundantPoints.length, capitalEvents: p.capitalEvents.length,
        firstPoint: p.firstPoint ? p.firstPoint.value : null, lastPoint: p.lastPoint ? p.lastPoint.value : null,
        lastDeltaPct: p.meta.lastDeltaPct, status,
      }]);
      console.log('[visual-prep] gaps:', p.gaps, '| clusters:', p.clusters, '| capitalEvents:', p.capitalEvents);
    } catch (_) {}
    return p;
  };
  window.debugAurixVisualPreparationAll = () => {
    const rows = ['24h', '7d', '30d', '1y', 'all'].map(r => prepareAurixVisualSeries(r));
    try {
      console.table(rows.map(p => {
        const status = (p.lastPoint && p.meta.lastDeltaPct != null && Math.abs(p.meta.lastDeltaPct) <= 0.5) ? 'ok'
          : (p.preparedPoints.length < 2 ? 'building' : 'review');
        return {
          range: p.range, sourcePoints: p.sourcePoints.length, preparedPoints: p.preparedPoints.length,
          targetPointCount: p.targetPointCount, gaps: p.gaps.length, clusters: p.clusters.length,
          redundantPoints: p.redundantPoints.length, capitalEvents: p.capitalEvents.length,
          firstPoint: p.firstPoint ? p.firstPoint.value : null, lastPoint: p.lastPoint ? p.lastPoint.value : null,
          lastDeltaPct: p.meta.lastDeltaPct, status,
        };
      }));
    } catch (_) {}
    return rows;
  };
}

// ════════════════════════════════════════════════════════════════════════
// AURIX — SPEC 3: INSTITUTIONAL RENDER ENGINE
//
// Converts the output of prepareAurixVisualSeries() into a clean, premium,
// INSTITUTIONAL curve. This is the first phase allowed to improve the curve
// VISUALLY — but it still NEVER touches financial data.
//
// HARD INPUT CONTRACT: the engine reads ONLY the PreparedSeries object. It must
// NOT read localStorage / portfolio_history / category_history / wealth ledger /
// PCE / getChartData. It NEVER mutates assets / snapshots / write guard / PCE /
// dashboard / pricing / financial logic / global CSS. Pure & deterministic:
// downsampling returns only REAL points; timestamps & values are never altered;
// monotone interpolation cannot overshoot (falls back to a safe segment); the
// last point stays == dashboard.
//
// SAFE INTEGRATION (sections 10/14): this phase keeps the engine in PREVIEW/DEBUG
// only — it does NOT replace the visible WSC/V2 render (that is intentionally
// deferred to SPEC 4 to avoid production-visual risk). window.previewAurix* and
// debug accessors expose the rendered object for validation.
const _AURIX_IR_VALUE_MARGIN = 0.13;   // RC1-B increment 1 (Fase 2, perceptual scale): more institutional vertical air (0.10→0.13) so the curve never reads wall-to-wall. Calibration constant only — value-domain margin for Y-pixel mapping; point VALUES are untouched (equivalence/last-point/max-min invariant).
const _AURIX_IR_VPAD_FRAC    = 0.08;   // top/bottom plot padding (fraction of height)

// §3 — LTTB downsampling. Returns ONLY real existing points; preserves first,
// last and the global max/min; never alters a timestamp or value. If the source
// already fits the target it returns a sorted copy.
function downsampleAurixLTTB(points, targetPointCount) {
  const src = (Array.isArray(points) ? points : [])
    .filter(p => p && Number.isFinite(p.time) && Number.isFinite(p.value))
    .map(p => ({ time: p.time, value: p.value }))
    .sort((a, b) => a.time - b.time);
  const n = src.length;
  const target = Math.max(2, Math.floor(Number(targetPointCount) || n));
  if (n <= target) return src.slice();

  const t0 = src[0].time;                       // normalise x for stable triangle areas
  const tx = i => src[i].time - t0;
  const sampled = [src[0]];
  const bucketSize = (n - 2) / (target - 2);
  let a = 0;
  for (let i = 0; i < target - 2; i++) {
    let avgStart = Math.floor((i + 1) * bucketSize) + 1;
    let avgEnd = Math.min(Math.floor((i + 2) * bucketSize) + 1, n);
    let avgX = 0, avgY = 0; const avgLen = Math.max(1, avgEnd - avgStart);
    for (let j = avgStart; j < avgEnd; j++) { avgX += (src[j].time - t0); avgY += src[j].value; }
    avgX /= avgLen; avgY /= avgLen;
    const rangeStart = Math.floor(i * bucketSize) + 1;
    const rangeEnd = Math.min(Math.floor((i + 1) * bucketSize) + 1, n);
    const pax = tx(a), pay = src[a].value;
    let maxArea = -1, chosen = rangeStart;
    for (let j = rangeStart; j < rangeEnd; j++) {
      const area = Math.abs((pax - avgX) * (src[j].value - pay) - (pax - (src[j].time - t0)) * (avgY - pay)) * 0.5;
      if (area > maxArea) { maxArea = area; chosen = j; }
    }
    sampled.push(src[chosen]); a = chosen;
  }
  sampled.push(src[n - 1]);

  // Force-preserve the global extrema (LTTB usually keeps them, but guarantee it).
  let miIdx = 0, maIdx = 0;
  for (let i = 1; i < n; i++) { if (src[i].value < src[miIdx].value) miIdx = i; if (src[i].value > src[maIdx].value) maIdx = i; }
  const present = new Set(sampled.map(p => p.time));
  [miIdx, maIdx].forEach(idx => { if (!present.has(src[idx].time)) { sampled.push(src[idx]); present.add(src[idx].time); } });
  // de-dup by timestamp + sort (all entries are real points)
  const seen = new Set();
  return sampled.filter(p => { if (seen.has(p.time)) return false; seen.add(p.time); return true; })
    .sort((x, y) => x.time - y.time);
}

// SPEC 6 — significant LOCAL extrema (real points): a local max/min whose prominence
// (drop to the lower/higher neighbour) is ≥ minProminenceFrac × the value range. Used
// to guarantee relevant peaks/dips survive the downsample (anti over-smoothing).
function _aurixSignificantLocalExtrema(src, valueRange, minProminenceFrac) {
  const out = [];
  const thr = (valueRange || 1) * (minProminenceFrac || 0.03);
  for (let i = 1; i < src.length - 1; i++) {
    const v = src[i].value, a = src[i - 1].value, b = src[i + 1].value;
    if (v > a && v >= b && (v - Math.min(a, b)) >= thr) out.push(i);
    else if (v < a && v <= b && (Math.max(a, b) - v) >= thr) out.push(i);
  }
  return out;
}

// SPEC 6 — Adaptive Density downsampler. LTTB (shape-preserving) PLUS guaranteed
// significant local extrema, so high-movement zones keep their detail while quiet
// zones stay sparse. Returns ONLY real points; preserves first/last/global-max/min
// (LTTB) and significant local peaks/dips; never invents/alters a point. If the
// source already fits the target, returns the full sorted copy (no reduction).
function downsampleAurixAdaptive(points, targetPointCount) {
  const src = (Array.isArray(points) ? points : [])
    .filter(p => p && Number.isFinite(p.time) && Number.isFinite(p.value))
    .map(p => ({ time: p.time, value: p.value }))
    .sort((a, b) => a.time - b.time);
  const n = src.length;
  const target = Math.max(2, Math.floor(Number(targetPointCount) || n));
  if (n <= target) return src;                       // full detail, nothing to drop
  const base = downsampleAurixLTTB(src, target);
  let vMin = Infinity, vMax = -Infinity;
  for (const p of src) { if (p.value < vMin) vMin = p.value; if (p.value > vMax) vMax = p.value; }
  const range = (vMax - vMin) || 1;
  const extremaIdx = _aurixSignificantLocalExtrema(src, range, 0.03);
  const present = new Set(base.map(p => p.time));
  const extra = [];
  const maxExtra = Math.ceil(target * 0.5);          // bound so the curve never over-densifies
  for (const i of extremaIdx) {
    if (extra.length >= maxExtra) break;
    if (!present.has(src[i].time)) { extra.push(src[i]); present.add(src[i].time); }
  }
  if (!extra.length) return base;
  return base.concat(extra).sort((a, b) => a.time - b.time);
}

// SPEC 6.1 — PERCEPTUAL X DISTRIBUTION (fill-blend). Premium charts (TradingView /
// Wealthica) do NOT space points strictly by real time — that leaves "islands" of
// activity separated by big empty zones (recent detail crammed right, sparse history
// spread thin and smooth on the left). This maps each point's x to a BLEND of its
// real-time position and its ordinal (equal-spacing) position: idle gaps compress,
// active/dense regions expand, so the whole line is rich and the cursor finds a real
// point almost everywhere. PURE RENDER: points/timestamps/values are unchanged (the
// tooltip shows the real time/value); equivalence with the canonical series is
// unaffected — only the on-screen x of each REAL point changes. Monotone in time →
// order preserved, no overlaps. β per range (more fill on long ranges where islands
// appear). β=0 would be pure real-time.
// RC1-B perceptual-X fill (Fase 3 personality / Fase 5 fill). Calibration constant only
// — X-PIXEL mapping between real points; values/last-point (pinned to the right edge)/
// max/min/timestamps untouched (equivalence invariant). Betas rise with range length.
//   inc2: 24H 0.30→0.48 (alive, never empty overnight).
//   inc3: 7D  0.40→0.48 (Fase 3 "equilibrado/continuo"; removes the dip below 24H/30D
//         so the short→long fill progression reads consistent).
const _AURIX_X_FILL_BETA = { '24h': 0.48, '7d': 0.48, '30d': 0.50, '1y': 0.65, 'all': 0.70 };
function computeAurixAdaptiveXScale(points, viewportWidth, box, range) {
  const vw = Math.max(240, Math.min(4000, Number(viewportWidth) || 390));
  let left, right;
  if (box && Number.isFinite(box.left) && Number.isFinite(box.right)) { left = box.left; right = Math.max(box.left + 1, box.right); }
  else { const pad = vw * _AURIX_RC_PAD_FRAC; left = pad; right = Math.max(left + 1, vw - pad); }
  const width = right - left;
  const pts = Array.isArray(points) ? points : [];
  const n = pts.length;
  const xMin = n ? pts[0].time : 0, xMax = n ? pts[n - 1].time : 1, span = (xMax - xMin) || 1;
  const beta = Math.max(0, Math.min(1, (range && _AURIX_X_FILL_BETA[range] != null) ? _AURIX_X_FILL_BETA[range] : 0.5));
  const xs = new Array(n);
  if (n <= 1) { for (let i = 0; i < n; i++) xs[i] = left; return { xMin, xMax, left, right, width, xs, beta, mode: 'fill-blend', x: () => left }; }
  const equal = 1 / (n - 1);
  const shares = new Array(n - 1); let sum = 0;
  for (let i = 0; i < n - 1; i++) { const tw = (pts[i + 1].time - pts[i].time) / span; const s = (1 - beta) * tw + beta * equal; shares[i] = s; sum += s; }
  if (!(sum > 0)) sum = 1;
  xs[0] = left; let acc = 0;
  for (let i = 0; i < n - 1; i++) { acc += shares[i] / sum; xs[i + 1] = left + acc * width; }
  xs[n - 1] = right;                                   // pin the last point exactly to the right edge
  // x(t) — interpolate within the bracketing real points (for gap markers / arbitrary t).
  const x = t => {
    if (t <= pts[0].time) return left;
    if (t >= pts[n - 1].time) return right;
    let lo = 0, hi = n - 1;
    while (hi - lo > 1) { const m = (lo + hi) >> 1; if (pts[m].time <= t) lo = m; else hi = m; }
    const seg = (pts[hi].time - pts[lo].time) || 1;
    return xs[lo] + (xs[hi] - xs[lo]) * ((t - pts[lo].time) / seg);
  };
  return { xMin, xMax, left, right, width, xs, beta, mode: beta > 0 ? 'fill-blend' : 'time-linear', x };
}

// §4 — real timestamp scale. x is proportional to the real timestamp (NEVER the
// array index): equal durations map to equal pixel distances. (Kept for reference /
// direct callers; the engine uses computeAurixAdaptiveXScale for the visible chart.)
function computeAurixTimeScale(points, viewportWidth, box) {
  const vw = Math.max(240, Math.min(4000, Number(viewportWidth) || 390));
  let left, right;
  if (box && Number.isFinite(box.left) && Number.isFinite(box.right)) { left = box.left; right = Math.max(box.left + 1, box.right); }
  else { const pad = vw * _AURIX_RC_PAD_FRAC; left = pad; right = Math.max(left + 1, vw - pad); }
  const width = right - left;
  const xMin = points.length ? points[0].time : 0;
  const xMax = points.length ? points[points.length - 1].time : 1;
  const span = (xMax - xMin) || 1;
  return { xMin, xMax, left, right, width, x: ts => left + ((ts - xMin) / span) * width };
}

// SPEC 6 — Legible Y scale. DEFAULT is plain linear (honest, no distortion). ONLY
// when a single time-consecutive value move dominates the range (a real regime
// jump that would otherwise flatten everything else to a line) does it switch to a
// CONSERVATIVE monotone blend of the linear position and the value-distribution
// (quantile) position. The blend is:
//   • monotone & order-preserving (never reorders or hides a move),
//   • bounded (α small → the jump stays the dominant visual feature, never hidden),
//   • PURELY VISUAL — it maps value→pixel only; it never changes any value, and the
//     tooltip still shows the real value. The axis stays honest: labels are REAL
//     values placed at their true (possibly non-uniform) positions via invValueAtY.
const _AURIX_Y_JUMP_DOMINANCE = 0.45;   // a consecutive move ≥45% of range = "dominant"
const _AURIX_Y_LEGIBLE_ALPHA  = 0.35;   // blend weight toward quantile spread (conservative)
function computeAurixValueScale(points, viewportHeight, box) {
  const vh = Math.max(120, Math.min(2000, Number(viewportHeight) || 220));
  let top, bottom;
  if (box && Number.isFinite(box.top) && Number.isFinite(box.bottom)) { top = box.top; bottom = Math.max(box.top + 1, box.bottom); }
  else { const vpad = vh * _AURIX_IR_VPAD_FRAC; top = vpad; bottom = vh - vpad; }
  const band = Math.max(1, bottom - top);
  const pts = Array.isArray(points) ? points : [];
  let vMin = Infinity, vMax = -Infinity;
  for (const p of pts) { if (p.value < vMin) vMin = p.value; if (p.value > vMax) vMax = p.value; }
  if (!Number.isFinite(vMin)) { vMin = 0; vMax = 1; }
  let span = vMax - vMin; if (!(span > 0)) span = Math.abs(vMax) || 1;
  const margin = span * _AURIX_IR_VALUE_MARGIN;
  const yMin = vMin - margin, yMax = vMax + margin, domain = (yMax - yMin) || 1;

  // Detect a dominant consecutive jump (in time order).
  let maxJump = 0;
  for (let i = 1; i < pts.length; i++) { const d = Math.abs(pts[i].value - pts[i - 1].value); if (d > maxJump) maxJump = d; }
  const dominant = (span > 0) && (maxJump / span >= _AURIX_Y_JUMP_DOMINANCE);
  const alpha = dominant ? _AURIX_Y_LEGIBLE_ALPHA : 0;
  const mode = alpha > 0 ? 'legible-blend' : 'linear';

  const linFrac = v => Math.max(0, Math.min(1, (v - yMin) / domain));
  if (alpha <= 0) {
    return { yMin, yMax, dataMin: vMin, dataMax: vMax, top, bottom, height: band, mode,
      y: v => bottom - linFrac(v) * band,
      invValueAtY: y => yMin + Math.max(0, Math.min(1, (bottom - y) / band)) * domain };
  }

  // Quantile (value-distribution) position — monotone non-decreasing in v.
  const sv = pts.map(p => p.value).sort((a, b) => a - b);
  const L = sv.length;
  const rankFrac = v => {
    if (v <= sv[0]) return 0;
    if (v >= sv[L - 1]) return 1;
    let lo = 0, hi = L - 1;
    while (hi - lo > 1) { const mid = (lo + hi) >> 1; if (sv[mid] <= v) lo = mid; else hi = mid; }
    const seg = (sv[hi] - sv[lo]) || 1;
    return (lo + (v - sv[lo]) / seg) / (L - 1);
  };
  const frac = v => Math.max(0, Math.min(1, (1 - alpha) * linFrac(v) + alpha * rankFrac(v)));   // strictly monotone (linFrac strict, α<1)
  const y = v => bottom - frac(v) * band;
  // exact-enough inverse via bisection (monotone) — used for honest axis labels.
  const invValueAtY = yPix => {
    const tf = Math.max(0, Math.min(1, (bottom - yPix) / band));
    let lo = yMin, hi = yMax;
    for (let it = 0; it < 40; it++) { const mid = (lo + hi) / 2; if (frac(mid) < tf) lo = mid; else hi = mid; }
    return (lo + hi) / 2;
  };
  return { yMin, yMax, dataMin: vMin, dataMax: vMax, top, bottom, height: band, mode, y, invValueAtY };
}

// ════════════════════════════════════════════════════════════════════════════
// AURIX — ADAPTIVE RENDER REPRESENTATION (ARR)
//
// PRINCIPIO PERMANENTE DEL MOTOR:
//   «Nunca se sacrificarán datos financieros para mejorar la apariencia visual.
//    La serie canónica permanecerá siempre completa.
//    Únicamente podrá optimizarse la representación gráfica.»
//
// ARR no reduce información: optimiza la REPRESENTACIÓN visual del trazo. Cuando
// varias muestras caerían sobre los mismos píxeles (el efecto "mazacote"), ARR
// dibuja un subconjunto de vértices con un espaciado mínimo, conservando SIEMPRE
// los puntos significativos (endpoints del run, máximo/mínimo del run y extremos
// locales significativos). La serie preparada, `visiblePoints`, `visiblePixels`,
// el tooltip, el inspector móvil y la equivalencia render↔canónica conservan TODOS
// los puntos reales — ARR solo afecta al conjunto de vértices que se envían a
// _aurixMonotonePath / buildAurixAreaPath. Devuelve únicamente puntos reales del
// `run` (jamás inventa, mueve ni altera un punto).
//
// RC3-INC2 — RANGE + SHAPE AWARE ARR. Un spacing global único mejora rangos largos
// pero rompe 24H (ver docs/AURIX-GRAPH-ENGINE-TECHNICAL-BIBLE.md). ARR v2 es:
//   • range-aware  — cada temporalidad tiene su propio contrato visual (spacing,
//     prominencia de extremos, longitud del tramo final protegido);
//   • shape-aware  — el spacing varía por zona (calma / volatilidad / tramo final /
//     narrativa inicial) según la geometría REAL de la serie;
//   • contract-safe — sigue siendo representación pura: datos/visiblePoints/tooltip/
//     inspector/equivalencia conservan TODOS los puntos reales.
//
// _AURIX_PATH_RENDER_SPACING — fallback global (unidades VIEWBOX; viewBox=1000 +
