// render time exactly as getChartData() does for parity.
function _aurixDashFlag() {
  if (typeof window === 'undefined') return false;
  // CHART-4 (manual-testing phase): default ON. Set
  // window.__AURIX_CHART_V2 = false to opt out cleanly. The legacy
  // Chart.js chart remains the rendering fallback either way.
  return window.__AURIX_CHART_V2 !== false;
}
function _aurixDashReady() {
  return typeof window !== 'undefined'
      && typeof window.AurixCharts === 'object'
      && typeof window.AurixCharts.createChart === 'function'
      && typeof window.AurixCharts.isReady === 'function'
      && window.AurixCharts.isReady();
}
// CHART-4 hotfix: deferred-mount queue. The Aurix engine + Lightweight
// Charts CDN load via <script defer>, which means they only execute
// AFTER this synchronous app.js completes. initChart() runs during
// that synchronous phase, so AurixCharts is still undefined when we
// first try to mount. This helper polls _aurixDashReady() up to a
// 4-second ceiling and mounts as soon as the engine is available.
// On engine timeout it gives up silently; legacy Chart.js continues
// rendering. Every call is independently abort-safe.
function _aurixDashMountWhenReady(surface) {
  if (!_aurixDashFlag()) return;
  let attempts = 0;
  const tryMount = () => {
    if (_aurixDashReady()) {
      try { _aurixDashMount(surface); } catch (_) {}
      return;
    }
    if (++attempts > 40) return;  // ~4s ceiling
    setTimeout(tryMount, 100);
  };
  // setTimeout(0) puts us behind the current microtask + at least one
  // macrotask tick so defer-loaded scripts get a chance to execute.
  setTimeout(tryMount, 0);
}

// CHART-PARITY-1: the V2 dashboard series is now derived from the
// SAME unified pipeline (getChartData) that feeds the legacy desktop
// + mobile Chart.js instances. This eliminates the previous
// divergence where the V2 overlay's parallel filter+sort+toBase path
// produced a different shape than the legacy processSeries+grid+
// downsample path, which in turn made desktop and mobile screenshots
// show conflicting % deltas for the same portfolio + range. Both
// surfaces now read identical timestamps + values; the V2 overlay's
// own visualNormalization is intentionally disabled at mount time
// (see _aurixDashMount) so neither side smooths data the other does
// not. portfolioHistory itself is never mutated.
//
// ╔══════════════════════════════════════════════════════════════╗
// ║  CHART QA PASS — do not modify without explicit request.      ║
// ║  Dashboard chart engine (normalize / data-quality / dash      ║
// ║  series / reliability gate / FINAL-FIX / getChartData /       ║
// ║  updateChart) is frozen after iPhone QA. Touch only for a     ║
// ║  critical bug, and only when the user explicitly asks.        ║
// ╚══════════════════════════════════════════════════════════════╝
// ── AURIX-DASHBOARD-CHART-INSTITUTIONAL-1 ────────────────────────
// Display-only chart-series normalization. RAW snapshots / categoryHistory /
// portfolioHistory are NEVER mutated or persisted — this only shapes the
// in-memory series the chart + headline read (both go through _aurixDashSeries,
// so the line and the % can never diverge). Two protections:
//   • collapse near-duplicate-time points (per-range pixel bucket, last wins)
//     so clustered snapshots never stack into a vertical "spike";
//   • drop legacy/contaminated points grossly incompatible with the live value
//     (the reported 18–20k legacy points that paint a false -62% next to a real
//     ~7k portfolio). Bands are wide enough that ordinary volatility and
//     realistic moves are NEVER touched; long ranges (where large real growth is
