// ── Sticky header scroll elevation ────────────────────────
(function initScrollHeader() {
  const headerEl = document.querySelector('.header');
  if (!headerEl) return;
  window.addEventListener('scroll', () => {
    headerEl.classList.toggle('header--scrolled', window.scrollY > 8);
  }, { passive: true });
})();

// ── Language switcher ──────────────────────────────────────
(function initLangSwitcher() {
  document.querySelectorAll('[data-lang]').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.lang === lang);
    btn.addEventListener('click', () => switchLang(btn.dataset.lang));
  });
  // Apply TYPE_META labels for current lang (HTML is already in ES, only override for EN)
  applyTypeMetaLabels();
  if (lang !== 'es') applyI18n();
})();

// ── DSH.MENU.02 — personal menu identity (display name + membership badge) ──
// Display-only. Reads the auth user + existing plan tier; changes NO auth,
// language, currency, permission or Premium logic. Name rule: user_metadata
// display name → stored account name → text-before-@.
function _aurixMenuDisplayName() {
  try {
    const u = (typeof currentUser !== 'undefined') ? currentUser : null;
    const md = (u && u.user_metadata) || {};
    const dn = md.display_name || md.full_name || md.name;
    if (dn && String(dn).trim()) return String(dn).trim();
    let stored = null; try { stored = localStorage.getItem('aurix_display_name'); } catch (_) {}
    if (stored && stored.trim()) return stored.trim();
    const email = (u && u.email) || '';
    if (email.indexOf('@') > 0) return email.split('@')[0];
    if (email) return email;
  } catch (_) {}
  return (typeof lang !== 'undefined' && lang === 'en') ? 'You' : 'Tú';
}
function _aurixMenuTier() {
  try {
    const p = window.aurixEntitlements && window.aurixEntitlements.getPlan && window.aurixEntitlements.getPlan();
    const tier = p && p.tier;
    if (tier === 'founder' || tier === 'premium' || tier === 'free') return tier;
  } catch (_) {}
  return 'free';
}
function _aurixRenderMenuIdentity() {
  const nameEl = document.getElementById('menuUserName');
  const badgeEl = document.getElementById('menuUserBadge');
  if (nameEl) nameEl.textContent = _aurixMenuDisplayName();
  if (badgeEl) {
    const tier = _aurixMenuTier();
    badgeEl.setAttribute('data-tier', tier);
    badgeEl.textContent = tier === 'founder' ? 'FOUNDER' : tier === 'premium' ? 'PREMIUM' : 'FREE';
  }
  // PREMIUM-PREVIEW-FINAL — Aurix Premium menu item state. Owner (authenticated email) → normal, clickable.
  // Free → intrigue/coming-soon: subtly blurred golden, not clickable, no modal/navigation (guarded above).
  const premiumEl = document.getElementById('menuPremium');
  if (premiumEl) {
    const _premiumUser = (typeof hasAurixPremiumAccess === 'function') && hasAurixPremiumAccess(_aurixCurrentAuthUser());
    const _en = (function () { try { return (typeof lang !== 'undefined' && lang === 'en'); } catch (_) { return false; } })();
    if (_premiumUser) {
      premiumEl.classList.remove('menu-item--premium-locked');
      premiumEl.removeAttribute('aria-disabled');
      premiumEl.textContent = (typeof t === 'function') ? t('menuPremium') : '✨ Aurix Premium';
    } else {
      premiumEl.classList.add('menu-item--premium-locked');
      premiumEl.setAttribute('aria-disabled', 'true');
      premiumEl.innerHTML = 'Aurix Premium <span class="menu-premium-soon">' + (_en ? 'coming soon' : 'próximamente') + '</span>';
    }
  }
}

// ── Hamburger menu ─────────────────────────────────────────
(function initMenu() {
  const toggle = document.getElementById('menuToggle');
  const panel  = document.getElementById('menuPanel');
  const exit   = document.getElementById('menuExit');
  if (!toggle || !panel) return;

  function openMenu()  {
    try { _aurixRenderMenuIdentity(); } catch (_) {}   // DSH.MENU.02 — fresh name/badge each open
    panel.classList.add('open');
    toggle.classList.add('open');
    toggle.setAttribute('aria-expanded', 'true');
  }
  function closeMenu() {
    panel.classList.remove('open');
    toggle.classList.remove('open');
    toggle.setAttribute('aria-expanded', 'false');
  }
  function isOpen() { return panel.classList.contains('open'); }

  toggle.addEventListener('click', e => {
    e.stopPropagation();
    isOpen() ? closeMenu() : openMenu();
  });

  // Close on outside click
  document.addEventListener('click', e => {
    if (isOpen() && !panel.contains(e.target) && !toggle.contains(e.target)) closeMenu();
  });

  // Close on Escape
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && isOpen()) { closeMenu(); toggle.focus(); }
  });

  // Language items — switchLang already wired via initLangSwitcher; just close menu
  panel.querySelectorAll('.menu-item--lang').forEach(btn => {
    btn.addEventListener('click', () => closeMenu());
  });

  if (exit) {
    exit.addEventListener('click', () => { closeMenu(); signOut(); });
  }
})();


// ── Card drag & drop — single delegated listener ────────────
(function initCardDragDrop() {
  assetsListEl.addEventListener('touchstart', e => {
    if (activeCategory) return;                      // disabled in category detail view
    const card = e.target.closest('.asset-card[data-asset-id]');
    if (!card || e.touches.length !== 1) return;

    const t0     = e.touches[0];
    const startY = t0.clientY;
    let fired    = false;

    const timer = setTimeout(() => {
      fired = true;
      _ddBeginDrag(card, t0);
    }, 300);

    const onMove = ev => {
      if (fired) {
        _ddMove(ev);
      } else if (Math.abs(ev.touches[0].clientY - startY) > 8) {
        cancel(); // moved too early — treat as scroll, not long press
      }
    };

    const onEnd = () => { cancel(); if (fired) _ddEnd(); };

    function cancel() {
      clearTimeout(timer);
      document.removeEventListener('touchmove',   onMove);
      document.removeEventListener('touchend',    onEnd);
      document.removeEventListener('touchcancel', onEnd);
    }

    document.addEventListener('touchmove',   onMove, { passive: false });
    document.addEventListener('touchend',    onEnd,  { passive: true });
    document.addEventListener('touchcancel', onEnd,  { passive: true });
  }, { passive: true });
})();

// ── Cat-card drag & drop ────────────────────────────────────
(function initCatCardDragDrop() {
  const grid = document.getElementById('categoriesGrid');
  if (!grid) return;

  function saveCatOrder() {
    _catOrder = [...grid.querySelectorAll('.cat-card[data-type]')].map(c => c.dataset.type);
    localStorage.setItem(CAT_ORDER_KEY, JSON.stringify(_catOrder));
    try { if (typeof _touchUiState === 'function') _touchUiState(); } catch (_) {} // AURIX-ACCOUNT-SOURCE-OF-TRUTH-1 P1
  }

  // active:  hold timer has fired, drag is armed
  // started: card has actually moved (real drag, not a tap)
  let drag = {
    active: false,
    started: false,
    card: null,
    startX: 0,
    startY: 0,
    pressTimer: null,
  };

  function cleanup() {
    if (!drag.card) return;

    drag.card.style.transform     = '';
    drag.card.style.zIndex        = '';
    drag.card.style.transition    = '';
    drag.card.style.boxShadow     = '';
    drag.card.style.pointerEvents = '';
    drag.card.classList.remove('dragging');

    drag = {
      active: false,
      started: false,
      card: null,
      startX: 0,
      startY: 0,
      pressTimer: null,
    };

    window.removeEventListener('pointermove', onPointerMove);
    window.removeEventListener('pointerup',   onPointerUp);
    window.removeEventListener('pointercancel', onPointerCancel);

    // Restore scroll immediately after any drag interaction ends
    document.body.style.touchAction = 'auto';
  }

  // pointercancel fires when the browser takes over the gesture (e.g. scroll).
  // Clear the timer so drag never activates after a scroll starts.
  function onPointerCancel() {
    clearTimeout(drag.pressTimer);
    drag.card = null;
    window.removeEventListener('pointermove',   onPointerMove);
    window.removeEventListener('pointerup',     onPointerUp);
    window.removeEventListener('pointercancel', onPointerCancel);
  }

  function onPointerMove(e) {
    if (!drag.active) return;  // pointermove is only attached after hold, but guard anyway

    // Block scroll only while the card is actually being dragged
    e.preventDefault();

    drag.started = true;
    const card = drag.card;
    if (!card) return;
    card.style.transform =
      `translate(${e.clientX - drag.startX}px, ${e.clientY - drag.startY}px) scale(1.05)`;
  }

  function onPointerUp(e) {
    if (!drag.card) return;

    clearTimeout(drag.pressTimer);

    // Release any pointer capture so the browser resumes normal touch routing
    try { drag.card.releasePointerCapture(e.pointerId); } catch (_) {}

    const card = drag.card;

    if (!drag.started) {
      // Tap — let existing touchend/click handlers open the card
      cleanup();
      return;
    }

    // Real drag — ensure card is transparent so elementFromPoint sees through it
    card.style.pointerEvents = 'none';
    const el     = document.elementFromPoint(e.clientX, e.clientY);
    card.style.pointerEvents = '';
    const target = el?.closest('.cat-card[data-type]');

    if (target && target !== card) {
      const parent = card.parentNode;
      const nextA  = card.nextSibling;
      const nextB  = target.nextSibling;
      parent.insertBefore(card,   nextB);
      parent.insertBefore(target, nextA);
      saveCatOrder();
    }

    // Block the pointerup from propagating and prevent any default click action
    e.preventDefault();
    e.stopPropagation();

    // Set global flag — the document capture listener will swallow any click
    // that the browser fires in the next 100 ms as a result of this gesture
    justDragged = true;
    setTimeout(() => { justDragged = false; }, 150);

    cleanup();

    // Safety: ensure scroll is re-enabled even if cleanup had an edge case
    setTimeout(() => { document.body.style.touchAction = 'auto'; }, 50);
  }

  const isMobile = 'ontouchstart' in window;

  // ── Touch path (mobile) ────────────────────────────────────────────────────

  // Hard reset — always clears state regardless of intermediate failures
  function resetDrag() {
    clearTimeout(drag.pressTimer);
    if (drag.card) {
      drag.card.style.transform     = '';
      drag.card.style.zIndex        = '';
      drag.card.style.transition    = '';
      drag.card.style.boxShadow     = '';
      drag.card.style.pointerEvents = '';
      drag.card.classList.remove('dragging');
    }
    drag.active  = false;
    drag.started = false;
    drag.card    = null;
    document.body.style.touchAction = 'auto';
  }

  function onTouchStart(e) {
    if (activeCategory) return;
    if (drag.active) return;          // guard: another drag already armed
    drag.card = null;                 // clear any stale reference before starting
    const card = e.target.closest('.cat-card');
    if (!card) return;
    const touch = e.touches[0];
    drag.card    = card;
    drag.startX  = touch.clientX;
    drag.startY  = touch.clientY;
    drag.active  = false;
    drag.started = false;

    // Instant press feedback — user feels the touch immediately
    card.style.transition = 'transform 0.08s ease';
    card.style.transform  = 'scale(0.96)';
    if (navigator.vibrate) navigator.vibrate(5);

    drag.pressTimer = setTimeout(() => {
      if (!drag.card) return;
      drag.active                     = true;
      document.body.style.touchAction = 'none';
      card.style.transition           = 'all 0.15s ease';
      card.style.transform            = 'scale(1.05)';
      card.style.boxShadow            = '0 12px 30px rgba(0,0,0,0.25)';
      card.style.zIndex               = '9999';
      card.style.pointerEvents        = 'none';
      card.classList.add('dragging');
      if (navigator.vibrate) navigator.vibrate(15); // stronger pulse = drag armed
    }, 1500); // 1.5 s hold — optimal balance of speed and intent
  }

  function onTouchMove(e) {
    if (!drag.card) return;

    const touch = e.touches[0];
    const dx = touch.clientX - drag.startX;
    const dy = touch.clientY - drag.startY;

    // Any movement before the hold completes → cancel drag, let browser scroll
    if (!drag.active) {
      if (Math.abs(dx) > 5 || Math.abs(dy) > 5) {
        clearTimeout(drag.pressTimer);
        drag.card.style.transform = '';
        drag.card.style.transition = '';
        drag.card = null;
      }
      return;
    }

    // Hold confirmed — track the card
    drag.started = true;
    e.preventDefault();
    drag.card.style.transform = `translate(${dx}px, ${dy}px) scale(1.05)`;
  }

  function onTouchEnd(e) {
    clearTimeout(drag.pressTimer);
    if (!drag.card) return;
    // Released before hold completed — snap scale back
    if (!drag.active) {
      drag.card.style.transform  = '';
      drag.card.style.transition = '';
      drag.card = null;
      return;
    }
    if (drag.started) {
      const touch  = e.changedTouches[0];
      const el     = document.elementFromPoint(touch.clientX, touch.clientY);
      const target = el?.closest('.cat-card[data-type]');
      if (target && target !== drag.card) {
        const parent = drag.card.parentNode;
        const nextA  = drag.card.nextSibling;
        const nextB  = target.nextSibling;
        parent.insertBefore(drag.card, nextB);
        parent.insertBefore(target,    nextA);
        saveCatOrder();
      }
      justDragged = true;
      setTimeout(() => { justDragged = false; }, 150);
    }
    resetDrag();
  }

  // ── Pointer path (desktop) ──────────────────────────────────────────────────

  function onPointerDown(e) {
    if (activeCategory) return;        // disabled in category detail view
    if (drag.card) return;             // interaction already in progress
    const card = e.target.closest('.cat-card');
    if (!card) return;

    drag.card    = card;
    drag.startX  = e.clientX;
    drag.startY  = e.clientY;
    drag.started = false;
    drag.active  = false;

    // Arm drag after 220 ms hold. pointermove is intentionally NOT attached
    // here — adding it on pointerdown would make window non-passive and block
    // scroll even for taps. The browser scrolls freely until hold confirms drag.
    drag.pressTimer = setTimeout(() => {
      if (!drag.card) return; // cancelled by pointercancel before timer fired
      drag.active                     = true;
      document.body.style.touchAction = 'none';
      card.style.zIndex               = '9999';
      card.style.transition           = 'none';
      card.style.pointerEvents        = 'none';
      card.classList.add('dragging');
      // Only now attach pointermove — the non-passive listener no longer
      // blocks scroll because drag is already confirmed
      window.addEventListener('pointermove', onPointerMove);
    }, 220);

    // pointerup handles tap/drop; pointercancel handles browser-scroll takeover
    window.addEventListener('pointerup',     onPointerUp);
    window.addEventListener('pointercancel', onPointerCancel);
  }

  // ── Register whichever event set matches the device ────────────────────────
  if (isMobile) {
    document.addEventListener('touchstart',  onTouchStart, { passive: true });
    document.addEventListener('touchmove',   onTouchMove,  { passive: false });
    document.addEventListener('touchend',    onTouchEnd);
    document.addEventListener('touchcancel', resetDrag);
  } else {
    document.addEventListener('pointerdown', onPointerDown);
  }

  // Per-card click guard — blocks any synthetic click on a cat-card
  // that the browser fires within 150 ms of a drag gesture ending
  grid.querySelectorAll('.cat-card').forEach(card => {
    card.addEventListener('click', e => {
      if (justDragged) {
        e.preventDefault();
        e.stopPropagation();
      }
    });
  });
})();

// ── Watchlist Store (single source of truth) ───────────────
const watchlistStore = (() => {
  const KEY   = 'aurix_watchlist';
  const _subs = [];
  let _list;

  function _defaultList() {
    return (Array.isArray(assets) ? assets : [])
      .filter(a => a.qty > 0)
      .map(a => a.sym || a.name);
  }

  function _persist() { localStorage.setItem(KEY, JSON.stringify(_list)); }
  function _notify()  { _subs.forEach(fn => fn()); }
  // AURIX-PERSISTENCE-REMOTE-HISTORY-WATCHLIST-1: stamp the modification time
  // on every USER edit so last-write-wins can arbitrate between the Safari and
  // PWA storage containers (and so deletions stick). _hydrate (remote adoption
  // / migration) does NOT stamp — its caller owns the timestamp.
  function _touch() {
    try { localStorage.setItem(WATCHLIST_TS_KEY, String(Date.now())); } catch (_) {}
    // WATCHLIST-SYNC-1: prompt cross-device propagation (bypasses the 60s
    // throttle, debounced). scheduleStateFlush stays as the catch-all.
    try { if (typeof scheduleWatchlistFlush === 'function') scheduleWatchlistFlush(); } catch (_) {}
    try { if (typeof scheduleStateFlush === 'function') scheduleStateFlush(); } catch (_) {}
  }

  const _stored = localStorage.getItem(KEY);
  _list = _stored ? JSON.parse(_stored) : _defaultList();

  return {
    getWatchlist: ()  => [..._list],
    includes:     key => _list.includes(key),
    add(key)          { if (!_list.includes(key)) { _list = [..._list, key]; _persist(); _touch(); _notify(); } },
    remove(key)       { _list = _list.filter(k => k !== key); _persist(); _touch(); _notify(); },
    // Bulk-replace from remote without bumping the user-edit timestamp.
    _hydrate(list)    { _list = Array.isArray(list) ? [...list] : []; _persist(); _notify(); },
    subscribe:    fn  => _subs.push(fn),
  };
})();

// ── Global Watchlist API (thin wrappers over watchlistStore) ─
const WATCHLIST_KEY = 'aurix_watchlist'; // same key as watchlistStore

function normalizeSymbol(symbol) {
  if (!symbol) return '';
  return String(symbol)
    .toUpperCase()
    .replace(/\.[A-Z]{1,3}$/, '') // strip exchange suffixes: .US .L .DE .F etc.
    .replace(/\//g, '')
    .replace(/-/g, '')
    .replace(/^\^/, '')           // strip index prefix: ^GSPC → GSPC
    .trim();
}

function getWatchlist() {
  return watchlistStore.getWatchlist();
}

function setWatchlist(list) {
  const norm    = list.map(normalizeSymbol);
  const current = watchlistStore.getWatchlist();
  current.forEach(k => { if (!norm.includes(k)) watchlistStore.remove(k); });
  norm.forEach(k  => { if (!current.includes(k)) watchlistStore.add(k); });
}

function isInWatchlist(symbol) {
  return watchlistStore.includes(normalizeSymbol(symbol));
}

function toggleWatchlist(symbol) {
  const norm = normalizeSymbol(symbol);
  if (watchlistStore.includes(norm)) {
    watchlistStore.remove(norm);
    return false;
  }
  watchlistStore.add(norm);
  return true;
}

// ── ONBOARDING-WATCHLIST-2: starter watchlist seeder ───────
// Single source of truth: aurix_watchlist. When onboarding finishes
// and the user picked interests but has no portfolio and no
// pre-existing watchlist, we plant a curated 6-symbol starter list
// so dashboard + market light up immediately. Idempotent — a one-shot
// guard (aurix_watchlist_seeded) prevents reseeding across reloads
// and never overrides user edits.
const WATCHLIST_SEEDED_KEY = 'aurix_watchlist_seeded';

const _AURIX_WL_INTEREST_MAP = Object.freeze({
  crypto:      ['BTC', 'ETH'],
  stock:       ['AAPL', 'NVDA'],
  stocks:      ['AAPL', 'NVDA'],
  etf:         ['SPY', 'QQQ'],
  etfs:        ['SPY', 'QQQ'],
  fund:        ['SPY', 'QQQ'],
  funds:       ['SPY', 'QQQ'],
  metal:       ['XAU'],
  metals:      ['XAU'],
  gold:        ['XAU'],
  real_estate: ['VNQ'],
  realestate:  ['VNQ'],
  cash:        [],
});

// Build a balanced, interleaved starter watchlist from interests.
// Round-robins category by category so the result feels curated,
// never grouped. Caps at 6 symbols. Returns an empty array when no
// interests resolve to known symbols.
//
// Real-estate (VNQ) is included only when MARKET_DATA reports it as
// available. The spec says "skip if not supported", and a fresh-boot
// MARKET_DATA snapshot may still be loading — we err on the side of
// not surfacing an unpriced ETF that the user can't open.
function _aurixBuildStarterWatchlist(interests) {
  if (!Array.isArray(interests) || !interests.length) return { symbols: [], skipped: [] };
  const lanes  = [];
  const skipped = [];
  const norm = s => String(s || '').trim().toLowerCase();
  const _marketHas = sym => {
    try {
      if (!Array.isArray(MARKET_DATA)) return false;
      const wanted = normalizeSymbol(sym);
      return MARKET_DATA.some(d => normalizeSymbol(d.canonicalSymbol || d.symbol) === wanted);
    } catch (_) { return false; }
  };
  for (const raw of interests) {
    const key = norm(raw);
    const lane = _AURIX_WL_INTEREST_MAP[key];
    if (!lane) { skipped.push({ interest: raw, reason: 'unmapped' }); continue; }
    if (!lane.length) { skipped.push({ interest: raw, reason: 'no-watchlist-mapping' }); continue; }
    if (key === 'real_estate' || key === 'realestate') {
      // VNQ only when the live catalog actually carries it.
      const filtered = lane.filter(sym => _marketHas(sym));
      if (!filtered.length) {
        skipped.push({ interest: raw, reason: 'provider-unsupported' });
        continue;
      }
      lanes.push(filtered);
      continue;
    }
    lanes.push(lane.slice());
  }
  if (!lanes.length) return { symbols: [], skipped };
  const out = [];
  const MAX = 6;
  let progress = true;
  while (progress && out.length < MAX) {
    progress = false;
    for (const lane of lanes) {
      if (!lane.length) continue;
      const sym = lane.shift();
      const k = normalizeSymbol(sym);
      if (!k) continue;
      if (!out.includes(k)) out.push(k);
      progress = true;
      if (out.length >= MAX) break;
    }
  }
  return { symbols: out, skipped };
}

// Idempotent seeder. Returns a structured result so __aurixWatchlistDebug
// can report exactly what happened (and why we skipped).
function _aurixSeedStarterWatchlist(reason) {
  const out = {
    ran:        false,
    reason:     reason || 'unknown',
    skipped:    null,
    seededWith: [],
    interests:  [],
  };
  let alreadySeeded = false;
  try { alreadySeeded = localStorage.getItem(WATCHLIST_SEEDED_KEY) === '1'; } catch (_) {}
  if (alreadySeeded) { out.skipped = 'already-seeded'; return out; }

  const current = (typeof getWatchlist === 'function') ? getWatchlist() : [];
  if (current.length > 0) { out.skipped = 'watchlist-non-empty'; return out; }

  const assetCount = (Array.isArray(assets) ? assets.length : 0);
  if (assetCount > 0) { out.skipped = 'portfolio-non-empty'; return out; }

  let interests = [];
  try {
    const prefs = JSON.parse(localStorage.getItem('aurix_onboarding_preferences') || '{}') || {};
    if (Array.isArray(prefs.interests)) interests = prefs.interests.slice();
  } catch (_) {}
  if (!interests.length) {
    try {
      const snap = (typeof window !== 'undefined' && window.AurixOnboarding && typeof window.AurixOnboarding.getSnapshot === 'function')
        ? window.AurixOnboarding.getSnapshot() : null;
      if (snap && Array.isArray(snap.interests)) interests = snap.interests.slice();
    } catch (_) {}
  }
  out.interests = interests;
  if (!interests.length) { out.skipped = 'no-interests'; return out; }

  const built = _aurixBuildStarterWatchlist(interests);
  if (!built.symbols.length) {
    out.skipped = 'no-mapped-symbols';
    out.symbolsSkipped = built.skipped;
    return out;
  }

  for (const sym of built.symbols) watchlistStore.add(sym);
  try { localStorage.setItem(WATCHLIST_SEEDED_KEY, '1'); } catch (_) {}
  out.ran = true;
  out.seededWith = built.symbols.slice();
  out.symbolsSkipped = built.skipped;
  return out;
}

// DEBUG-HARDEN-1: predicate for development-only window helpers.
// Returns true on localhost, dev hostnames, or when the user has
// explicitly opted in via localStorage.aurix_debug = '1'. All QA /
// debug helpers MUST be gated through this so production never
// surfaces them on `window`.
function _aurixIsDebugHost() {
  try {
    const h = String((typeof window !== 'undefined' && window.location && window.location.hostname) || '').toLowerCase();
    if (h === 'localhost' || h === '127.0.0.1' || h === '0.0.0.0' || h === '::1') return true;
    if (h.endsWith('.local')) return true;
    if (h.startsWith('dev.') || h.startsWith('dev-') || h.includes('-dev.') || h.includes('.dev.')) return true;
  } catch (_) {}
  try {
    if (typeof localStorage !== 'undefined' && localStorage.getItem('aurix_debug') === '1') return true;
  } catch (_) {}
  return false;
}

if (typeof window !== 'undefined') {
  // Exposed for the engine bridge in app.js so onboarding completion
  // can plant the starter watchlist. NOT gated — production needs
  // this code path to actually fire.
  window.__aurixSeedStarterWatchlist = _aurixSeedStarterWatchlist;
}

// DEBUG-HARDEN-1: every helper below this guard is attached only on
// development hosts (localhost / *.local / dev hostnames) or when the
// user explicitly opts in via localStorage.aurix_debug = '1'. In
// production these names stay `undefined` on window.
if (typeof window !== 'undefined' && _aurixIsDebugHost()) {
  // ONBOARDING-WATCHLIST-2: developer probe. Reports the live state of
  // every surface the seed touches — useful when verifying that the
  // dashboard widget and the market watchlist tab actually mirror the
  // seeded symbols.
  window.__aurixWatchlistDebug = function () {
    let seeded = false;
    try { seeded = localStorage.getItem(WATCHLIST_SEEDED_KEY) === '1'; } catch (_) {}
    let interests = [];
    try {
      const prefs = JSON.parse(localStorage.getItem('aurix_onboarding_preferences') || '{}') || {};
      if (Array.isArray(prefs.interests)) interests = prefs.interests;
    } catch (_) {}
    const built = _aurixBuildStarterWatchlist(interests);
    const wl = (typeof getWatchlist === 'function') ? getWatchlist() : [];
    const wlNorm = wl.map(normalizeSymbol);
    // Market watchlist tab consumes MARKET_DATA filtered by getWatchlist().
    const marketHits = (Array.isArray(MARKET_DATA) ? MARKET_DATA : [])
      .filter(d => wlNorm.includes(normalizeSymbol(d.canonicalSymbol || d.symbol)))
      .map(d => d.symbol || d.canonicalSymbol);
    const editorRows = (typeof _aurixWatchlistRows === 'function') ? _aurixWatchlistRows() : [];
    return {
      watchlist:                 wl,
      seeded,
      sourceInterests:           interests,
      generatedSymbols:          built.symbols,
      skippedReasons:            built.skipped,
      dashboardVisibleSymbols:   wl,           // tracking card mirrors getWatchlist()
      marketWatchlistSymbols:    marketHits,
      editorVisibleSymbols:      editorRows.map(r => r.key),
      assetCount:                Array.isArray(assets) ? assets.length : 0,
      existingWatchlistCount:    wl.length,
    };
  };

  // WATCHLIST-SEED-QA-1: dev-only convenience for QA without forcing a
  // new email registration. Builds a starter watchlist from the
  // provided interests and applies it to the canonical store, with
  // safe defaults (does not clear current watchlist, does not mark
  // seeded). Pass { clear: true } to wipe first, { markSeeded: true }
  // to also set aurix_watchlist_seeded so reload paths reproduce a
  // post-onboarding state. Returns the structured result for
  // inspection.
  window.__aurixSeedStarterWatchlistForTest = function (interests, opts) {
    const o     = opts || {};
    const clear = !!o.clear;
    const mark  = !!o.markSeeded;
    const list  = Array.isArray(interests) ? interests : [];
    if (clear) {
      try {
        const current = watchlistStore.getWatchlist();
        current.forEach(k => watchlistStore.remove(k));
      } catch (_) {}
      try { localStorage.removeItem(WATCHLIST_SEEDED_KEY); } catch (_) {}
    }
    const built = _aurixBuildStarterWatchlist(list);
    const added = [];
    for (const sym of built.symbols) {
      if (!watchlistStore.includes(sym)) {
        watchlistStore.add(sym);
        added.push(sym);
      }
    }
    if (mark) {
      try { localStorage.setItem(WATCHLIST_SEEDED_KEY, '1'); } catch (_) {}
    }
    return {
      ran:        true,
      reason:     'manual-test',
      interests:  list,
      cleared:    clear,
      markedSeeded: mark,
      generated:  built.symbols,
      added,
      skipped:    built.skipped,
      watchlist:  watchlistStore.getWatchlist(),
    };
  };
}

// WATCHLIST-SEED-QA-1: unified row builder shared by the dashboard
// tracking card and the watchlist editor modal. Every entry in
// `aurix_watchlist` produces a row, even when there is no holding.
// Lookup precedence: owned asset (has live price + qty) → MARKET_DATA
// (curated catalog) → placeholder (ticker only, "—" price). The
// editor row is fully removable in every case so users can always
// take control of seeded items.
function _aurixWatchlistRows() {
  const wl = (typeof getWatchlist === 'function') ? getWatchlist() : [];
  if (!wl.length) return [];
  const ownedByKey = new Map();
  if (Array.isArray(assets)) {
    for (const a of assets) {
      if (!a) continue;
      const k = a.sym || a.name;
      if (k) ownedByKey.set(k, a);
    }
  }
  const out = [];
  for (const key of wl) {
    const owned = ownedByKey.get(key);
    if (owned) {
      out.push({
        key,
        sym:    owned.sym || key,
        name:   owned.name || key,
        type:   owned.type || 'asset',
        price:  Number(owned.price) || 0,
        source: 'owned',
      });
      continue;
    }
    let priced = 0, name = key, type = 'asset';
    try {
      if (Array.isArray(MARKET_DATA)) {
        const norm = normalizeSymbol(key);
        const m = MARKET_DATA.find(d => normalizeSymbol(d.canonicalSymbol || d.symbol) === norm);
        if (m) {
          priced = Number(m.price) || 0;
          name   = m.name || key;
          type   = m.type || 'asset';
        }
      }
    } catch (_) {}
    out.push({
      key,
      sym:    key,
      name,
      type,
      price:  priced,
      source: priced > 0 ? 'market' : 'placeholder',
    });
  }
  return out;
}

// ── Market Store (live prices + smooth interpolation) ──────
const marketStore = (() => {
  const POLL_MS = 5000;
  let _prices       = {};  // key → { price, prev, display, target, history, isReal }
  let _rafMap       = {};
  let _drawThrottle = {};
  let _timer        = null;

  // Random walk with momentum — 32 pts, organic, no straight segments
  function _genInitialHistory(base) {
    let v = base;
    const out = [];
    for (let i = 0; i < 32; i++) {
      const drift    = (Math.random() - 0.5) * base * 0.002;
      const momentum = i > 1 ? (out[i - 1] - out[i - 2]) * 0.35 : 0;
      v += drift + momentum;
      out.push(v);
    }
    return out;
  }

  function _smooth(data) {
    return data.map((curr, i, a) =>
      ((a[i - 1] ?? curr) + curr + (a[i + 1] ?? curr)) / 3
    );
  }

  // Best seed for a key — uses assets[] if available
  function _seedFor(key) {
    if (Array.isArray(assets)) {
      const a = assets.find(x => (x.sym || x.name) === key);
      if (a?.price > 0) return a.price;
    }
    return _prices[key]?.display ?? _prices[key]?.price ?? 100;
  }

  // ── Sparkline ────────────────────────────────────────────
  function _drawSpark(key, force) {
    const canvas = document.querySelector('.watchlist-spark[data-key="' + key + '"]');
    if (!canvas) return;

    // Lazy-init entry with fake history if it doesn't exist yet
    if (!_prices[key]) {
      const seed = _seedFor(key);
      _prices[key] = { price: null, prev: null, display: null, target: null,
                       history: _genInitialHistory(seed), isReal: false };
    }

    const { history, isReal } = _prices[key];

    // Throttle — only on real-data redraws; force bypasses
    if (!force && isReal) {
      const now = Date.now();
      if (now - (_drawThrottle[key] ?? 0) < 120) return;
      _drawThrottle[key] = now;
    }

    if (isReal) {
      canvas.classList.remove('placeholder');
      canvas.classList.add('ready');
    } else {
      canvas.classList.add('placeholder');
      canvas.classList.remove('ready');
    }

    const dpr = window.devicePixelRatio || 1;
    const W = 70, H = 22;
    canvas.width  = W * dpr;
    canvas.height = H * dpr;
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);

    // Smooth → midpoint interpolation (32 → ~60 pts)
    const smoothed = _smooth(history);
    const pts = [];
    for (let i = 0; i < smoothed.length - 1; i++) {
      pts.push(smoothed[i]);
      pts.push((smoothed[i] + smoothed[i + 1]) / 2);
    }
    pts.push(smoothed[smoothed.length - 1]);

    const min      = Math.min(...pts);
    const max      = Math.max(...pts);
    const price    = _prices[key].price ?? _prices[key].display ?? _seedFor(key);
    const range    = Math.max(max - min, price * 0.002) || 1;
    const delta    = pts[pts.length - 1] - pts[0];
    const isUp     = delta >  Math.max(Math.abs(max) * 0.001, 0.01);
    const isDown   = delta < -Math.max(Math.abs(max) * 0.001, 0.01);
    const color    = isReal
      ? (isUp ? '#22c55e' : isDown ? '#ef4444' : '#9ca3af')
      : '#9ca3af';

    const grad = ctx.createLinearGradient(0, 0, W, 0);
    grad.addColorStop(0, color + '55');
    grad.addColorStop(1, color + 'ff');

    const xs = pts.map((_, i) => (i / (pts.length - 1)) * W);
    const ys = pts.map(v => H - ((v - min) / range) * (H - 2) - 1);

    ctx.globalAlpha = 0.95;
    ctx.strokeStyle = grad;
    ctx.lineWidth   = 1.2;
    ctx.lineJoin    = 'round';
    ctx.lineCap     = 'round';

    ctx.beginPath();
    ctx.moveTo(xs[0], ys[0]);
    for (let i = 0; i < xs.length - 1; i++) {
      const xc = (xs[i] + xs[i + 1]) / 2;
      const yc = (ys[i] + ys[i + 1]) / 2;
      ctx.quadraticCurveTo(xs[i], ys[i], xc, yc);
    }
    ctx.lineTo(xs[xs.length - 1], ys[ys.length - 1]);
    ctx.stroke();

    // Live dot — only with real data
    if (isReal) {
      const lastY = ys[ys.length - 1];
      ctx.shadowBlur  = 3;
      ctx.shadowColor = color;
      ctx.globalAlpha = 0.9;
      ctx.beginPath();
      ctx.arc(W, lastY, 1.4, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();
      ctx.shadowBlur  = 0;
      ctx.globalAlpha = 1;
    }
  }

  // ── DOM helpers ──────────────────────────────────────────
  function _updateDOM(key, value) {
    const text = value ? formatBase(value) : '--';
    const dash = document.querySelector('.watchlist-price[data-key="' + key + '"]');
    if (dash) dash.textContent = text;
    const modal = document.querySelector('.watchlist-modal-row[data-key="' + key + '"] .watchlist-modal-price');
    if (modal) modal.textContent = text;
  }

  function _triggerFlash(key, from, to) {
    if (from === to) return;
    const cls = to > from ? 'price-up' : 'price-down';
    [
      document.querySelector('.watchlist-price[data-key="' + key + '"]'),
      document.querySelector('.watchlist-modal-row[data-key="' + key + '"] .watchlist-modal-price'),
    ].forEach(el => {
      if (!el) return;
      el.classList.remove('price-up', 'price-down');
      void el.offsetWidth;
      el.classList.add(cls);
    });
  }

  // ── Interpolation ────────────────────────────────────────
  function _animatePrice(key) {
    const item = _prices[key];
    if (!item) return;
    const from  = item.display;
    const to    = item.target;
    const delta = Math.abs(to - from);
    if (delta < 0.001) { item.display = to; _updateDOM(key, to); return; }

    if (_rafMap[key]) cancelAnimationFrame(_rafMap[key]);

    const duration = Math.min(400, Math.max(250, delta * 5));
    const start    = performance.now();

    function frame(now) {
      const t     = Math.min((now - start) / duration, 1);
      const eased = t * (2 - t);                        // quadratic ease-out
      const value = from + (to - from) * eased;
      item.display = value;
      _updateDOM(key, value);

      if (t < 1) {
        _rafMap[key] = requestAnimationFrame(frame);
      } else {
        item.display = to;
        delete _rafMap[key];
        _updateDOM(key, to);
        _triggerFlash(key, from, to);
      }
    }
    _rafMap[key] = requestAnimationFrame(frame);
  }

  // ── Price setter ─────────────────────────────────────────
  function _set(key, newPrice) {
    const entry = _prices[key];
    if (entry?.price === newPrice) return;
    // Skip sub-noise (< 0.03% change)
    if (entry?.price && Math.abs(newPrice - entry.price) / entry.price < 0.0003) return;

    const display = entry?.display ?? null;

    // Preserve existing history — continue, never reset
    let history = entry?.history;
    if (!history || history.length < 2) {
      history = _genInitialHistory(newPrice);
    } else if (!entry.isReal) {
      // Rescale fake history to real price range before first real push
      const center = history.reduce((s, v) => s + v, 0) / history.length;
      if (center > 0) history = history.map(v => v * (newPrice / center));
    }

    history.push(newPrice);
    if (history.length > 40) history.shift();

    _prices[key] = {
      price:   newPrice,
      prev:    display ?? entry?.price ?? newPrice,
      display: display ?? newPrice,
      target:  newPrice,
      history,
      isReal:  true,
    };
    _animatePrice(key);
    _drawSpark(key);
  }

  // Mirror non-crypto prices from main 30 s refresh cycle
  function syncFromRefresh() {
    if (!Array.isArray(assets)) return;
    watchlistStore.getWatchlist().forEach(key => {
      const a = assets.find(x => (x.sym || x.name) === key);
      if (a?.price > 0) _set(key, a.price);
    });
  }

  // Batch CoinGecko poll — crypto only, single request
  async function _pollCrypto() {
    if (!Array.isArray(assets)) return;
    const cryptos = watchlistStore.getWatchlist()
      .map(key => assets.find(a => (a.sym || a.name) === key && a.type === 'crypto' && a.coinId))
      .filter(Boolean);
    if (!cryptos.length) return;
    try {
      const coinIds = [...new Set(cryptos.map(a => a.coinId))];
      const data    = await fetchLivePrices(coinIds);
      // Stagger per-asset to feel like real market data arriving
      cryptos.forEach(a => {
        const usd = data[a.coinId]?.usd;
        if (usd > 0) {
          const delay = Math.round(Math.random() * Math.random() * 120);
          setTimeout(() => _set(a.sym || a.name, usd), delay);
        }
      });
    } catch {}
  }

  function _restartPolling() {
    if (_timer) clearInterval(_timer);
    syncFromRefresh();
    _pollCrypto();
    _timer = setInterval(_pollCrypto, POLL_MS);
  }

  watchlistStore.subscribe(_restartPolling);
  // WATCHLIST-SEED-QA-1: keep the Market screen in lockstep with the
  // canonical watchlist. Removing or adding a symbol from the editor
  // must instantly reflect on the Market "Watchlist" tab — otherwise
  // the user perceives stale state until they switch tabs.
  watchlistStore.subscribe(() => {
    try {
      if (typeof renderCurrentMarketView === 'function' &&
          typeof currentMarketTab === 'string' &&
          currentMarketTab === 'watchlist') {
        renderCurrentMarketView();
      }
    } catch (_) { /* never let a render miss break the polling loop */ }
  });

  return {
    getPrice:   key => _prices[key] ?? null,
    redrawAll:  ()  => watchlistStore.getWatchlist().forEach(k => _drawSpark(k, true)),
    syncFromRefresh,
    start:      _restartPolling,
  };
})();

// ── Tracking Card ──────────────────────────────────────────
(function initTrackingCard() {
  if (!window.matchMedia('(min-width: 1024px)').matches) return;

  const content = document.getElementById('trackingContent');
  if (!content) return;

  const TICKER_ASSETS = [
    { sym: 'BTC',  id: 'bitcoin' },
    { sym: 'ETH',  id: 'ethereum' },
    { sym: 'ORO',  price: '—', change: '—', positive: null },
    { sym: 'NVDA', price: '—', change: '—', positive: null },
    { sym: 'S&P',  price: '—', change: '—', positive: null },
  ];

  async function fetchTickerPrices() {
    const coinAssets = TICKER_ASSETS.filter(a => a.id);
    try {
      const data = await fetchLivePrices(coinAssets.map(a => a.id));
      TICKER_ASSETS.forEach(a => {
        if (!a.id || !data[a.id]) return;
        const usd = data[a.id].usd;
        const ch  = data[a.id].usd_24h_change;
        a.price    = usd != null ? '$' + usd.toLocaleString('en-US', { maximumFractionDigits: 0 }) : '—';
        a.change   = ch  != null ? (ch >= 0 ? '+' : '') + ch.toFixed(2) + '%' : '—';
        a.positive = ch  != null ? ch >= 0 : null;
      });
    } catch {}
  }

  function renderTicker() {
    const items = TICKER_ASSETS.map(a =>
      '<div class="ticker-item">' +
        '<span class="ticker-sym">' + a.sym + '</span>' +
        '<span class="ticker-price">' + (a.price || '—') + '</span>' +
      '</div>'
    ).join('');
    content.innerHTML =
      '<div class="tracking-ticker-wrap">' +
        '<div class="tracking-ticker">' + items + items + '</div>' +
      '</div>';
  }

  // ONBOARDING-WATCHLIST-2: dashboard tracking card now mirrors the
  // canonical watchlist even when the user has no holdings yet. Owned
  // assets keep their existing path (price comes from the asset row);
  // seeded entries fall back to MARKET_DATA, and finally to a "—"
  // placeholder so the row mounts without faking a price.
  function _buildWatchlistRows() {
    const keys = (typeof getWatchlist === 'function') ? getWatchlist() : [];
    const ownedByKey = new Map();
    if (Array.isArray(assets)) {
      for (const a of assets) {
        if (!a) continue;
        const k = a.sym || a.name;
        if (k) ownedByKey.set(k, a);
      }
    }
    const rows = [];
    for (const key of keys) {
      const owned = ownedByKey.get(key);
      if (owned && owned.price > 0) {
        rows.push({ key, name: owned.name || key, price: owned.price, source: 'owned' });
        continue;
      }
      let priced = 0, name = key;
      try {
        if (Array.isArray(MARKET_DATA)) {
          const norm = normalizeSymbol(key);
          const m = MARKET_DATA.find(d => normalizeSymbol(d.canonicalSymbol || d.symbol) === norm);
          if (m) {
            priced = Number(m.price) || 0;
            name   = m.name || key;
          }
        }
      } catch (_) {}
      rows.push({ key, name, price: priced, source: priced > 0 ? 'market' : 'placeholder' });
    }
    // Cap at 5 so the card stays compact.
    return rows.slice(0, 5);
  }

  function renderWatchlist() {
    const top = _buildWatchlistRows();

    if (top.length === 0) {
      content.innerHTML =
        '<div class="watchlist-empty">' +
          '<div class="watchlist-empty-dot"></div>' +
          '<span>' + t('watchlistTrackEmpty') + '</span>' +
        '</div>';
      return;
    }

    // Skip rebuild if structure is identical — animation loop keeps prices live.
    // LR.3 (H): the seeded "Sugerencia" tag now depends on source, so the skip
    // signature includes seeded state too — otherwise a seeded→owned transition
    // (user buys a watchlisted symbol) would leave a stale tag until the next
    // structural change.
    const sig  = top.map(r => r.key + (r.source && r.source !== 'owned' ? ':s' : ':o'));
    const rows = [...content.querySelectorAll('.watchlist-row[data-key]')];
    if (rows.length === top.length &&
        sig.every((s, i) => s === (rows[i]?.dataset.key + (rows[i]?.classList.contains('seeded') ? ':s' : ':o')))) return;

    const html = top.map(r => {
      const pd    = marketStore.getPrice(r.key);
      const price = pd?.display ?? pd?.price ?? r.price;
      // LR.3 (H): seeded/curated markets (source !== 'owned') carry a quiet
      // "Sugerencia" tag so they never read as positions the user owns. The
      // symbol + tag stay inside a single grid cell so the row layout (sym /
      // spark / price) is unchanged. Presentation only.
      const seeded  = (r.source && r.source !== 'owned');
      const symCell = seeded
        ? '<span class="watchlist-sym">' + r.key + '<span class="watchlist-seed-tag">' + t('watchlistSuggestions') + '</span></span>'
        : '<span class="watchlist-sym">' + r.key + '</span>';
      return '<div class="watchlist-row' + (seeded ? ' seeded' : '') + '" data-key="' + r.key + '">' +
        symCell +
        '<canvas class="watchlist-spark placeholder" data-key="' + r.key + '"></canvas>' +
        '<span class="watchlist-price" data-key="' + r.key + '">' + (price ? formatBase(price) : '—') + '</span>' +
      '</div>';
    }).join('');
    content.innerHTML = '<div class="watchlist-preview">' + html + '</div>';
    marketStore.redrawAll();
  }

  async function render() {
    const hasWatchlist = (typeof getWatchlist === 'function') && getWatchlist().length > 0;
    if (hasWatchlist) {
      // Either owned or seeded — single render path keeps dashboard +
      // market watchlist surfaces consistent.
      renderWatchlist();
    } else {
      await fetchTickerPrices();
      renderTicker();
    }
  }

  watchlistStore.subscribe(render);
  render();
})();

// ── Watchlist Modal ─────────────────────────────────────────
let _wlEditing   = false;
let _wlLastAdded = null;

function _wlRenderBody() {
  const body = document.getElementById('watchlistModalBody');
  if (!body) return;

  // WATCHLIST-SEED-QA-1: editor now iterates the canonical store so
  // seeded virtual items (no holdings yet) are listed and removable.
  // Rows are sorted: owned-first (richest first), then virtuals in
  // insertion order — keeps the user's own positions on top while
  // surfacing the curated suggestions just below.
  const all = (typeof _aurixWatchlistRows === 'function') ? _aurixWatchlistRows() : [];
  const owned    = all.filter(r => r.source === 'owned');
  const virtuals = all.filter(r => r.source !== 'owned');
  owned.sort((a, b) => {
    const av = a.price * (assets?.find(x => (x.sym || x.name) === a.key)?.qty || 0);
    const bv = b.price * (assets?.find(x => (x.sym || x.name) === b.key)?.qty || 0);
    return bv - av;
  });
  const tracked = [...owned, ...virtuals];

  if (tracked.length === 0) {
    body.innerHTML = '<div class="watchlist-modal-empty">' + t('watchlistEmpty') + '</div>';
  } else {
    // LR.3 (H): a single row renderer reused for both groups. Owned positions
    // render on top unlabelled; seeded/curated markets (source !== 'owned')
    // render below a "Sugerencias" divider so they never read as the user's
    // own holdings. Presentation only — no change to which keys are tracked.
    const _wlRow = (r) => {
      const key       = r.key;
      const pd        = marketStore.getPrice(key);
      const rawPrice  = pd?.display ?? pd?.price ?? r.price;
      const price     = rawPrice ? formatBase(rawPrice) : '—';
      const editClass = _wlEditing ? ' editing' : '';
      const removeBtn = _wlEditing
        ? '<button class="remove-btn" data-key="' + key + '">✕</button>'
        : '';
      const typeAttr  = r.type ? ' data-type="' + r.type + '"' : '';
      const seedClass = (r.source && r.source !== 'owned') ? ' seeded' : '';
      return '<div class="watchlist-modal-row' + editClass + seedClass + '" data-key="' + key + '"' + typeAttr + '>' +
        '<span class="watchlist-modal-sym">'   + (r.sym  || key) + '</span>' +
        '<span class="watchlist-modal-name">'  + (r.name || '')  + '</span>' +
        '<span class="watchlist-modal-price">' + price            + '</span>' +
        removeBtn +
      '</div>';
    };
    let _wlHtml = owned.map(_wlRow).join('');
    if (virtuals.length) {
      _wlHtml += '<div class="watchlist-modal-section">' + t('watchlistSuggestions') + '</div>';
      _wlHtml += virtuals.map(_wlRow).join('');
    }
    body.innerHTML = _wlHtml;

    // Animate newly added row
    if (_wlLastAdded) {
      const newRow = body.querySelector('[data-key="' + _wlLastAdded + '"]');
      if (newRow) {
        newRow.classList.add('new', 'highlight');
        setTimeout(() => newRow.classList.remove('highlight'), 400);
        newRow.addEventListener('animationend', () => newRow.classList.remove('new'), { once: true });
      }
      _wlLastAdded = null;
    }

    // Remove with exit animation
    body.querySelectorAll('.remove-btn').forEach(btn => {
      btn.addEventListener('click', e => {
        e.stopPropagation();
        const row = btn.closest('.watchlist-modal-row');
        row.classList.add('removing');
        setTimeout(() => {
          watchlistStore.remove(btn.dataset.key);
          _wlRenderBody();
          _wlRenderPanel();
        }, 180);
      });
    });
  }

  const addBtn = document.getElementById('watchlistAddBtn');
  if (addBtn) {
    addBtn.textContent = _wlEditing ? '✓' : '+';
    addBtn.classList.toggle('add-button--active', _wlEditing);
  }
}

function _wlRenderPanel() {
  const panel   = document.getElementById('addAssetPanel');
  const results = document.getElementById('addAssetResults');
  if (!panel || !results) return;

  panel.classList.toggle('hidden', !_wlEditing);
  if (!_wlEditing) return;

  const query  = (document.getElementById('addAssetInput')?.value || '').toLowerCase();
  const hidden = Array.isArray(assets)
    ? assets.filter(a => a.qty > 0 && !watchlistStore.includes(a.sym || a.name))
    : [];
  const filtered = hidden.filter(a =>
    !query ||
    (a.sym  || '').toLowerCase().includes(query) ||
    (a.name || '').toLowerCase().includes(query)
  );

  if (filtered.length === 0) {
    results.innerHTML = '<div class="watchlist-modal-empty" style="padding:8px 0 0">' +
      (hidden.length === 0 ? t('watchlistModalEmpty') : t('watchlistModalNoResults')) + '</div>';
  } else {
    results.innerHTML = filtered.map(a =>
      '<div class="add-asset-result" data-key="' + (a.sym || a.name) + '">' +
        '<span class="watchlist-modal-sym">'  + (a.sym  || '') + '</span>' +
        '<span class="watchlist-modal-name">' + (a.name || '') + '</span>' +
      '</div>'
    ).join('');

    results.querySelectorAll('.add-asset-result').forEach(el => {
      el.addEventListener('click', () => {
        _wlLastAdded = el.dataset.key;
        watchlistStore.add(el.dataset.key);
        _wlRenderBody();
        _wlRenderPanel();
      });
    });
  }
}

function toggleWatchlistEditMode() {
  _wlEditing = !_wlEditing;
  _wlRenderBody();
  _wlRenderPanel();
}

function openWatchlistModal() {
  const modal = document.getElementById('watchlist-modal');
  if (!modal) return;
  _wlEditing = false;
  modal.classList.remove('hidden');
  // Double rAF ensures display:flex is applied before transition starts
  requestAnimationFrame(() => requestAnimationFrame(() => modal.classList.add('open')));
  _wlRenderBody();
  _wlRenderPanel();
}

function closeWatchlistModal() {
  const modal = document.getElementById('watchlist-modal');
  if (!modal) return;
  modal.classList.remove('open');
  setTimeout(() => modal.classList.add('hidden'), 200);
  _wlEditing = false;
}

document.addEventListener('DOMContentLoaded', () => {
  enforceNavOrder();

  // SPEC 4.1B — mount the founder PCE-validation overlay (no-op unless founder
  // mode is enabled on this device). Never affects normal users.
  try { _aurixPceFounderInit(); } catch (_) {}

  const modal = document.getElementById('watchlist-modal');
  if (modal) modal.addEventListener('click', e => { if (e.target === modal) closeWatchlistModal(); });

  const card = document.querySelector('.watchlist-inner-card');
  if (card) card.addEventListener('click', openWatchlistModal);

  const input = document.getElementById('addAssetInput');
  if (input) input.addEventListener('input', _wlRenderPanel);

  // Hero CTA — dismiss hero, show dashboard
  const heroCta = document.getElementById('heroCtaBtn');
  if (heroCta) {
    heroCta.addEventListener('click', () => {
      switchView('dashboard');
      switchTab('home');
    });
  }

});

// ── Mobile FAB ─────────────────────────────────────────────
(function initFab() {
  const fab  = document.getElementById('portfolioFab');
  const menu = document.getElementById('fabMenuGlobal');
  if (!fab) return;

  fab.addEventListener('click', e => {
    e.stopPropagation();

    if (window.innerWidth <= 768) {
      openModal();
      return;
    }

    if (!menu) return;
    const rect = fab.getBoundingClientRect();
    menu.style.top  = (rect.bottom + 10) + 'px';
    menu.style.left = (rect.right - 190) + 'px';
    menu.classList.toggle('open');
  });

  if (menu) {
    document.addEventListener('click', e => {
      if (!fab.contains(e.target) && !menu.contains(e.target)) {
        menu.classList.remove('open');
      }
    });

    menu.querySelector('[data-action="asset"]').onclick    = openModal;
    menu.querySelector('[data-action="liquidity"]').onclick = openLiquidityModal;
  }
})();

if (IS_DEV) {
}

/* ══════════════════════════════════════════════════════════════════
   MARKET-8 — Real historical timeframes for Market list rows.
   Uses the existing AurixChartAdapters (Yahoo + CoinGecko proxies).
   Cache-first, concurrency-limited, generation-token-guarded.
   ══════════════════════════════════════════════════════════════════ */

// UI timeframe → adapter range code. Adapter accepts: 24h, 7d, 30d,
// 3m, 1y, all. 1M maps to 30d (closest match) and ALL to all.
const _MKT_HISTORY_RANGE_MAP = Object.freeze({
  '24H': '24h',
  '7D':  '7d',
  '1M':  '30d',
  '1Y':  '1y',
  'ALL': 'all',
});
// Per-range cache TTL in ms. Shorter periods refetch more often.
const _MKT_HISTORY_TTL = Object.freeze({
  '24h':  60 * 1000,
  '7d':   5 * 60 * 1000,
  '30d':  30 * 60 * 1000,
  '1y':   6  * 3600 * 1000,
  'all':  24 * 3600 * 1000,
});
const _marketHistoryCache  = new Map();          // key → entry
const _marketHistoryQueue  = { running: 0, max: 3, pending: [] };
let   _marketHistoryGen    = 0;                  // bumped on each render
let   _marketHistoryErrors = 0;

function _mktHistoryAdapterRange() {
  return _MKT_HISTORY_RANGE_MAP[_aurixMktTimeframe || '24H'] || '24h';
}
function _mktHistoryCacheKey(item, range) {
  // MARKET-8: cache keyed by NORMALIZED SYMBOL (BTC / AAPL / XAU)
  // rather than per-adapter id, so the sparkline cell can look up
  // entries directly via data-spark-key without re-deriving the
  // adapter shape. Adapter shape is still computed at fetch time.
  if (!item) return '';
  const sym = normalizeSymbol(item.symbol || item.ticker || '');
  if (!sym) return '';
  return `${sym}|${range}`;
}
function _mktHistoryCacheFresh(entry, range) {
  if (!entry) return false;
  const ttl = _MKT_HISTORY_TTL[range] || 60 * 1000;
  return (Date.now() - entry.ts) < ttl;
}
function _mktHistoryChangeForRow(item) {
  // 24H: prefer the live change24h that flows through the market store.
  // Other timeframes: read from the cache; null when not yet fetched.
  const tf = _aurixMktTimeframe || '24H';
  if (tf === '24H') {
    const live = item && (item.price_change_percentage_24h ?? item.change24h ?? item.change);
    return (live == null || !Number.isFinite(Number(live))) ? null : Number(live);
  }
  const range = _MKT_HISTORY_RANGE_MAP[tf] || '24h';
  const key   = _mktHistoryCacheKey(item, range);
  const entry = _marketHistoryCache.get(key);
  if (!entry) return null;
  if (!_mktHistoryCacheFresh(entry, range)) return null;
  return (entry.changePct == null || !Number.isFinite(entry.changePct))
    ? null
    : entry.changePct;
}
function _mktHistoryEntryForCell(cell) {
  // Cache lookup by normalized symbol + range. data-spark-tf is set
  // by renderMarketItem so we know which range to ask for.
  if (!cell || !cell.dataset) return null;
  const sym = cell.dataset.sparkKey;
  if (!sym) return null;
  const tf    = cell.dataset.sparkTf || '24H';
  const range = _MKT_HISTORY_RANGE_MAP[tf] || '24h';
  const ent   = _marketHistoryCache.get(`${sym}|${range}`);
  return (ent && _mktHistoryCacheFresh(ent, range)) ? ent : null;
}
function _mktHistoryEnqueue(job) {
  _marketHistoryQueue.pending.push(job);
  _mktHistoryDrain();
}
function _mktHistoryDrain() {
  while (_marketHistoryQueue.running < _marketHistoryQueue.max && _marketHistoryQueue.pending.length) {
    const job = _marketHistoryQueue.pending.shift();
    _marketHistoryQueue.running++;
    Promise.resolve()
      .then(job)
      .catch(err => { _marketHistoryErrors++; console.warn('[mkt-history] job fail:', err && err.message); })
      .finally(() => {
        _marketHistoryQueue.running--;
        _mktHistoryDrain();
      });
  }
}
function _mktHistoryAdaptersReady() {
  return typeof window !== 'undefined'
      && window.AurixChartAdapters
      && typeof window.AurixChartAdapters.yahooHistoryAdapter === 'function'
      && typeof window.AurixChartAdapters.cryptoHistoryAdapter === 'function';
}
async function _mktHistoryFetchOne(item, range, gen) {
  const adapter = _aurixMktPickAdapter(item);
  if (!adapter) return;
  const key = _mktHistoryCacheKey(item, range);
  if (!key) return;
  // Guard against double-fire when render runs back-to-back.
  if (_mktHistoryCacheFresh(_marketHistoryCache.get(key), range)) return;
  const fn = adapter.kind === 'crypto'
    ? window.AurixChartAdapters.cryptoHistoryAdapter
    : window.AurixChartAdapters.yahooHistoryAdapter;
  const args = Object.assign({}, adapter.args, { range });
  let result = null;
  try { result = await fn(args); }
  catch (_) { _marketHistoryErrors++; }
  if (gen !== _marketHistoryGen) return; // stale — user moved on
  const ok = result && Array.isArray(result.series) && result.series.length >= 2;
  let entry;
  if (!ok) {
    entry = { ts: Date.now(), series: [], meta: (result && result.meta) || null, changePct: null };
  } else {
    const s = result.series;
    let first = null, last = null;
    for (let i = 0; i < s.length; i++) {
      const v = Number(s[i].value);
      if (Number.isFinite(v) && v > 0) { first = v; break; }
    }
    for (let i = s.length - 1; i >= 0; i--) {
      const v = Number(s[i].value);
      if (Number.isFinite(v) && v > 0) { last = v; break; }
    }
    const changePct = (first != null && last != null && first > 0)
      ? ((last - first) / first) * 100
      : null;
    entry = { ts: Date.now(), series: s, meta: result.meta || null, changePct };
  }
  _marketHistoryCache.set(key, entry);
  _mktHistoryApplyToRow(item, range, entry, gen);
}
function _mktHistoryApplyToRow(item, range, entry, gen) {
  if (gen !== _marketHistoryGen) return;
  if (range !== _mktHistoryAdapterRange()) return;
  const list = document.getElementById('marketList');
  if (!list) return;
  const sym = normalizeSymbol(item.symbol);
  const rows = list.querySelectorAll(`.market-row[data-symbol="${sym}"]`);
  if (!rows.length) return;
  rows.forEach(row => {
    const cell = row.querySelector('.col-change');
    if (cell) {
      cell.classList.remove('is-loading');
      const v = entry.changePct;
      if (v == null || !Number.isFinite(v)) {
        cell.classList.remove('is-up', 'is-down', 'is-flat');
        cell.innerHTML = '<span class="col-change-empty">—</span>';
      } else {
        cell.classList.toggle('is-up',   v > 0);
        cell.classList.toggle('is-down', v < 0);
        cell.classList.toggle('is-flat', v === 0);
        cell.textContent = (typeof safeChange === 'function') ? safeChange(v) : (v.toFixed(2) + '%');
      }
    }
    // Sparkline: replace synthetic mount with real series (engine path).
    const sparkCell = row.querySelector('.col-chart[data-spark-key]');
    if (sparkCell && entry.series && entry.series.length >= 2 &&
        window.AurixCharts && typeof window.AurixCharts.createSparkline === 'function') {
      sparkCell.classList.remove('is-loading');
      const r = sparkCell.getBoundingClientRect();
      if (r.width > 0 && r.height > 0) {
        const key = sparkCell.dataset.sparkKey;
        if (key && _aurixMarketSpark.has(key)) {
          try { _aurixMarketSpark.get(key).destroy(); } catch (_) {}
          _aurixMarketSpark.delete(key);
        }
        sparkCell.innerHTML = '';
        try {
          const v = entry.changePct == null ? 0 : entry.changePct;
          const ctrl = window.AurixCharts.createSparkline(sparkCell, {
            colorMode: v > 0.005 ? 'positive' : v < -0.005 ? 'negative' : 'neutral',
            height:    sparkCell.clientHeight || 32,
          });
          ctrl.setData(entry.series, entry.meta || {
            source: 'history', currency: 'USD', granularity: '1d',
            isSynthetic: false, completeness: 1, asOf: Date.now(),
          });
          if (key) _aurixMarketSpark.set(key, ctrl);
        } catch (_) {}
      }
    } else if (sparkCell) {
      sparkCell.classList.remove('is-loading');
    }
  });
}
function _mktHistoryFetchVisible(dataset) {
  if (!_mktHistoryAdaptersReady()) return;
  const range = _mktHistoryAdapterRange();
  // Bump generation so any in-flight responses from a previous render
  // (different tab / different timeframe) are silently dropped.
  _marketHistoryGen++;
  const gen = _marketHistoryGen;
  // The dataset arg from renderCurrentMarketView already represents the
  // currently visible universe (filtered by tab + search). For aggregate
  // tabs (all/watchlist) it's the composed dataset.
  const items = Array.isArray(dataset) ? dataset : [];
  if (!items.length) return;
  // For 24H we only enqueue when the cache is stale AND a sparkline
  // upgrade is desired. To keep 24H rendering instant (using live
  // change24h), we still backfill the sparkline asynchronously.
  for (const item of items) {
    if (!item || !item.symbol) continue;
    const key = _mktHistoryCacheKey(item, range);
    if (!key) continue;
    if (_mktHistoryCacheFresh(_marketHistoryCache.get(key), range)) {
      // Cache fresh — apply now so re-renders with stale DOM rehydrate.
      _mktHistoryApplyToRow(item, range, _marketHistoryCache.get(key), gen);
      continue;
    }
    _mktHistoryEnqueue(() => _mktHistoryFetchOne(item, range, gen));
  }
}

// RESET-2: storage audit helper. Reports the count/size of every
// known persistence key plus the reset tombstone — useful from the
// console when verifying reset coverage.
if (typeof window !== 'undefined') {
  window.__aurixStorageDebug = function () {
    const KEYS = [
      'portfolio_assets', 'portfolio_history', 'category_history',
      'portfolio_card_order', 'portfolio_cat_order',
      'aurix_watchlist', 'aurix_assets', 'aurix_holdings',
      'aurix.workspace.v1', 'aurix_insights_memory',
      'aurix_user_profile', 'aurix_behavior', 'aurix_decisions',
      'aurix_data_backup', 'aurix_data_version',
      'aurix_identity', 'aurix_evolution',
      // Preserved across reset:
      'portfolio_lang', 'portfolio_base_currency', 'aurix_plan',
      // Tombstone:
      'aurix_reset_at',
    ];
    const out = {};
    for (const k of KEYS) {
      const raw = (function () { try { return localStorage.getItem(k); } catch (_) { return null; } })();
      if (raw == null) { out[k] = null; continue; }
      let count = null;
      try {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) count = parsed.length;
        else if (parsed && typeof parsed === 'object') {
          if (Array.isArray(parsed.assets)) count = parsed.assets.length;
          else count = Object.keys(parsed).length;
        }
      } catch (_) {}
      out[k] = { bytes: raw.length, count };
    }
    out.__inMemory = {
      assets:           Array.isArray(assets)           ? assets.length           : null,
      portfolioHistory: Array.isArray(portfolioHistory) ? portfolioHistory.length : null,
      categoryHistory:  Array.isArray(categoryHistory)  ? categoryHistory.length  : null,
    };
    // RESET-5: surface the orchestrator's runtime state so callers
    // can verify the atomic flow worked end-to-end.
    out.__reset = {
      resetInProgress: !!_aurixResetInProgress,
      resetGeneration: _aurixResetGeneration,
      resetAt:         _aurixResetAt(),
    };
    out.__charts = {
      // truthy when a controller is currently alive
      donut:           !!(typeof donutChart !== 'undefined' && donutChart),
      donutMobile:     !!(typeof donutChartMobile !== 'undefined' && donutChartMobile),
      detailChart:     !!(typeof _detailChart !== 'undefined' && _detailChart),
      marketSparklines: (typeof _aurixMarketSpark !== 'undefined' && _aurixMarketSpark && _aurixMarketSpark.size) || 0,
    };
    out.__dashboardEmptyStateValid = (function () {
      try {
        return Array.isArray(assets) && assets.length === 0
            && Array.isArray(portfolioHistory) && portfolioHistory.length === 0
            && Array.isArray(categoryHistory)  && categoryHistory.length  === 0;
      } catch (_) { return false; }
    })();
    return out;
  };

  window.__aurixMarketHistoryDebug = function () {
    return {
      cacheSize:       _marketHistoryCache.size,
      activeRange:     _mktHistoryAdapterRange(),
      activeTimeframe: _aurixMktTimeframe,
      pending:         _marketHistoryQueue.pending.length,
      running:         _marketHistoryQueue.running,
      errors:          _marketHistoryErrors,
      gen:             _marketHistoryGen,
      adaptersReady:   _mktHistoryAdaptersReady(),
    };
  };

  // RESET-HISTORY-1: portfolio-history probe. Run `__aurixHistoryDebug()`
  // in devtools to verify the reset epoch is wiring through everything:
  // raw vs. filtered counts, whether any pre-epoch points still live
  // in memory, and what basis the current PnL calculation rests on.
  // DEBUG-HARDEN-1: gated to dev hosts only.
  if (_aurixIsDebugHost()) window.__aurixHistoryDebug = function () {
    const resetAt = (function () {
      try { return parseInt(localStorage.getItem(RESET_AT_KEY) || '0', 10) || 0; }
      catch (_) { return 0; }
    })();
    const epoch = _aurixPortfolioEpoch();
    const raw = Array.isArray(portfolioHistory) ? portfolioHistory : [];
    const validRaw = raw.filter(p =>
      p && typeof p.ts === 'number' && typeof p.value === 'number' &&
      isFinite(p.value) && p.value > 0
    );
    const filtered = epoch ? validRaw.filter(p => p.ts >= epoch) : validRaw.slice();
    const ignored  = validRaw.length - filtered.length;
    const oldest = arr => arr.length ? arr[0] : null;
    const newest = arr => arr.length ? arr[arr.length - 1] : null;
    const sortedRaw = validRaw.slice().sort((a, b) => a.ts - b.ts);
    const sortedFil = filtered.slice().sort((a, b) => a.ts - b.ts);
    const fmt = p => p ? { ts: p.ts, iso: new Date(p.ts).toISOString(), value: p.value } : null;
    let currentValue = 0;
    try { currentValue = (typeof totalValueUSD === 'function') ? totalValueUSD() : 0; } catch (_) {}
    // Mirrors the perf-basis logic in computeRangePnL: post-epoch
    // history with <2 points → null (neutral). When 'all' range is
    // active we surface cost basis instead.
    let dashboardPerfBasis = null;
    try {
      const data = (typeof getChartData === 'function') ? getChartData(activeRange) : null;
      if (data && Array.isArray(data.values) && data.values.length >= 2) {
        dashboardPerfBasis = {
          range:     activeRange,
          mode:      'history',
          basePoint: data.values[0],
          points:    data.values.length,
        };
      } else if (activeRange === 'all') {
        const inv = (typeof totalCostBasisBase === 'function') ? totalCostBasisBase() : 0;
        dashboardPerfBasis = { range: 'all', mode: inv > 0 ? 'costBasis' : 'neutral', basePoint: inv };
      } else {
        dashboardPerfBasis = { range: activeRange, mode: 'neutral', basePoint: null };
      }
    } catch (_) {}
    return {
      resetAt,
      portfolioEpoch:                 epoch,
      portfolioHistoryRawCount:       validRaw.length,
      portfolioHistoryFilteredCount:  filtered.length,
      oldestRawPoint:                 fmt(oldest(sortedRaw)),
      newestRawPoint:                 fmt(newest(sortedRaw)),
      oldestFilteredPoint:            fmt(oldest(sortedFil)),
      newestFilteredPoint:            fmt(newest(sortedFil)),
      currentPortfolioValue:          currentValue,
      dashboardPerfBasis,
      ignoredOldPointsCount:          ignored,
    };
  };

  // AURIX-CHARTS-1 PHASE 1 — chart-layer probe. Combines the
  // history-side facts (raw vs filtered counts, epoch, ignored
  // points) with what the dashboard chart pipeline actually fed
  // the renderer. Useful for proving the post-reset path is clean
  // from history → series → chart.
  if (_aurixIsDebugHost()) window.__aurixChartDebug = function () {
    const epoch = _aurixPortfolioEpoch();
    const raw   = Array.isArray(portfolioHistory) ? portfolioHistory : [];
    const validRaw = raw.filter(p =>
      p && typeof p.ts === 'number' && typeof p.value === 'number' &&
      isFinite(p.value) && p.value > 0
    );
    const postEpoch = epoch ? validRaw.filter(p => p.ts >= epoch) : validRaw.slice();
    const ignored   = validRaw.length - postEpoch.length;
    let v2Series = [];
    try { v2Series = (typeof _aurixDashSeries === 'function') ? _aurixDashSeries(activeRange) : []; } catch (_) {}
    let legacy = null;
    try {
      const d = (typeof getChartData === 'function') ? getChartData(activeRange) : null;
      legacy = d && Array.isArray(d.values)
        ? { points: d.values.length, first: d.values[0], last: d.values[d.values.length - 1] }
        : null;
    } catch (_) {}
    let currentValue = 0;
    try { currentValue = (typeof totalValueBase === 'function') ? Number(totalValueBase()) : 0; } catch (_) {}
    const v2First = v2Series.length ? v2Series[0] : null;
    const v2Last  = v2Series.length ? v2Series[v2Series.length - 1] : null;
    const isBaselineFlat = v2Series.length === 2 && v2First && v2Last && v2First.value === v2Last.value;
    return {
      portfolioEpoch:               epoch,
      activeRange,
      rawHistoryCount:              validRaw.length,
      postEpochHistoryCount:        postEpoch.length,
      ignoredPreEpochCount:         ignored,
      currentPortfolioValueBase:    currentValue,
      v2FedSeriesCount:             v2Series.length,
      v2FirstPoint:                 v2First,
      v2LastPoint:                  v2Last,
      v2BaselineFlatActive:         isBaselineFlat,
      legacyChartData:              legacy,
      v2ControllerDesktopActive:    !!_aurixDashDesktop,
      v2ControllerMobileActive:     !!_aurixDashMobile,
      chartV2FlagEnabled:           (typeof window !== 'undefined') ? window.__AURIX_CHART_V2 !== false : null,
    };
  };
}

/* ══════════════════════════════════════════════════════════════════
   SETTINGS-1 — General panel, plan foundation, safe reset, export.
   ══════════════════════════════════════════════════════════════════ */

/* ──────────────────────────────────────────────────────────────────
   AURIX-MONETIZATION-1 — Plans & entitlements (built, kept DORMANT).
   --------------------------------------------------------------------
   The full commercial model (Free / Founder / Premium) lives here as a
   real, launch-ready product skeleton. It is wired end-to-end but stays
   completely inert until launch, governed by ONE compile-time switch:

       ENFORCE_ENTITLEMENTS = false

   Design contract (do not break):
   • While the switch is false, EVERY feature is unlocked for EVERY tier.
     Total access in prelaunch depends on this switch ALONE — never on a
     user's tier. Nobody is silently forced to 'founder' to keep access.
   • Tiers stay honest: a user's stored tier is their real commercial tier
     (default 'free'). Flipping the switch to true at launch activates the
     real Free/Founder/Premium gating with zero rearchitecture — no data
     migration, no feature rewrites; call sites already use hasFeature().
   • This module performs NO payments, NO Stripe, NO real subscriptions,
     NO paywalls. Those are separate, later, signalled steps.
   ────────────────────────────────────────────────────────────────── */

// MASTER SWITCH — the single source of truth for whether gating is live.
// false = prelaunch / development: everything unlocked. Flip to true to launch.
const ENFORCE_ENTITLEMENTS = false;

const PLAN_KEY = 'aurix_plan';

// Premium feature catalog — the surfaces that become paid at launch. New premium
// modules (Wealth Evolution, Portfolio Intelligence, …) register their key here
// and gate themselves with hasFeature(<key>); nothing else needs to change.
const PREMIUM_FEATURES = Object.freeze([
  'wealth_evolution',
  'portfolio_intelligence',
  'portfolio_health',
  'monthly_reports',
  'advanced_exports',
  'ai_wealth_assistant',
  'workspace_advanced',
]);

// Tier → entitled feature set. Founder and Premium both unlock the full premium
// catalog; Founder additionally carries the early-adopter commercial perks
// (lifetime price), expressed in PLAN_CATALOG rather than as extra features.
const PLAN_FEATURES = Object.freeze({
  free:    new Set([]),
  founder: new Set(PREMIUM_FEATURES),
  premium: new Set(PREMIUM_FEATURES),
});

// Commercial plan metadata — display + future checkout. No enforcement here.
const PLAN_CATALOG = Object.freeze({
  free: {
    id: 'free', name: 'Aurix Free', price: null, period: null,
  },
  founder: {
    id: 'founder', name: 'Aurix Founder', price: 14.99, period: 'year',
    priceLabel: { es: '14,99 € / año', en: '€14.99 / year' },
    lifetimePrice: true, earlyAccess: true,
  },
  premium: {
    id: 'premium', name: 'Aurix Premium', price: null, period: 'year',
  },
});

// Asset limits kept UNLIMITED for every tier on purpose: Aurix differentiates by
// intelligence, not by capping how much wealth you can track. The structure is
// retained so a future lever could exist, but there is no cap and no UI today.
const PLAN_LIMITS = Object.freeze({
  free:    { maxAssets: Infinity },
  founder: { maxAssets: Infinity },
  premium: { maxAssets: Infinity },
});

function _planDefault() {
  return {
    tier: 'free',           // real commercial tier (free | founder | premium)
    status: 'active',       // active | trialing | past_due | canceled | expired
    startedAt: Date.now(),
    renewsAt: null,
    expiresAt: null,
    canceledAt: null,
    trialEndsAt: null,
    promoCode: null,
    source: 'default',      // default | promo | manual | stripe
    founderEligible: true,  // early-adopter eligibility (commercial flag)
  };
}

function loadPlan() {
  let plan = null;
  try {
    const raw = JSON.parse(localStorage.getItem(PLAN_KEY) || 'null');
    if (raw && typeof raw === 'object' && typeof raw.tier === 'string') {
      plan = Object.assign(_planDefault(), raw);
    }
  } catch (_) {}
  if (!plan) {
    plan = _planDefault();
    try { localStorage.setItem(PLAN_KEY, JSON.stringify(plan)); } catch (_) {}
  }
  // Normalize the legacy 'pro' tier name to 'premium' (no behavior change).
  if (plan.tier === 'pro') plan.tier = 'premium';
  // Unknown tier → fall back to the real default tier, never to a paid one.
  if (!PLAN_FEATURES[plan.tier]) plan.tier = 'free';
  return plan;
}
function getPlan() { return loadPlan(); }

// Persist a plan object and stamp it for last-write-wins remote sync.
function savePlan(plan) {
  try { localStorage.setItem(PLAN_KEY, JSON.stringify(plan)); } catch (_) {}
  try { if (typeof _touchSubscription === 'function') _touchSubscription(); } catch (_) {}
  return plan;
}
// Set/replace the active tier. The single entry point used by promo redemption,
// manual grants and the future Stripe webhook bridge — dormant in prelaunch but
// fully wired, so activation needs no new plumbing.
function setPlanTier(tier, patch) {
  const next = (tier === 'pro') ? 'premium' : tier;
  if (!PLAN_FEATURES[next]) return getPlan();
  const plan = Object.assign(getPlan(), { tier: next }, patch || {});
  return savePlan(plan);
}

function planTierName(tier) {
  const key = (tier === 'pro') ? 'premium' : tier;
  const c = PLAN_CATALOG[key];
  return (c && c.name) ? c.name : 'Aurix Free';
}
function isPremiumTier(tier) {
  const t = tier || getPlan().tier;
  return t === 'founder' || t === 'premium';
}
function planStatus() { return getPlan().status || 'active'; }

// ── THE entitlement gate ──────────────────────────────────────────
// Every premium surface asks this one question. While ENFORCE_ENTITLEMENTS is
// false it always returns true (prelaunch: everything unlocked for everyone,
// regardless of tier). When true, the real per-tier entitlement applies. No
// other code in the app needs to know the switch exists.
function hasFeature(feature) {
  if (!ENFORCE_ENTITLEMENTS) return true;
  const set = PLAN_FEATURES[getPlan().tier] || PLAN_FEATURES.free;
  return set.has(feature);
}
// Expose the entitlement surface for other modules (premium features, the
// future checkout bridge) without reaching into internals.
try {
  window.aurixEntitlements = {
    ENFORCE_ENTITLEMENTS: ENFORCE_ENTITLEMENTS,
    hasFeature: hasFeature,
    getPlan: getPlan,
    setPlanTier: setPlanTier,
    isPremiumTier: isPremiumTier,
    planStatus: planStatus,
    PREMIUM_FEATURES: PREMIUM_FEATURES,
    PLAN_CATALOG: PLAN_CATALOG,
  };
} catch (_) {}

/* ──────────────────────────────────────────────────────────────────
   AURIX-MONETIZATION-1 · Phase 3 — Promo codes (architecture, DORMANT).
   --------------------------------------------------------------------
   The redemption schema and resolver are defined now so codes can be
   honoured the day checkout goes live, with no rearchitecture. Nothing
   here charges money or flips entitlements on its own; applyPromoCode is
   the single, explicit entry point and it only mutates the local plan
   (which then syncs). Real validation will move server-side alongside
   Stripe — resolvePromoCode is the seam for that swap.
   ────────────────────────────────────────────────────────────────── */
const PROMO_CODE_TYPES = Object.freeze(['percent', 'fixed', 'free', 'founder']);

// Seed catalog — illustrative and INERT. No prelaunch UI redeems these; real
// codes will be validated server-side. Shape: { type, value, grantsTier, expiresAt? }.
const PROMO_CODES = Object.freeze({
  FOUNDER100:  { type: 'founder', value: 0,   grantsTier: 'founder', note: 'Founder access, 100% off' },
  EARLYACCESS: { type: 'percent', value: 100, grantsTier: 'premium', note: 'Early-access full unlock' },
  PARTNER:     { type: 'free',    value: 0,   grantsTier: 'premium', note: 'Partner comp access' },
});

// Resolve a code to its effect WITHOUT applying it. Returns null if unknown,
// malformed or expired. This is the seam to later swap for a server-side check.
function resolvePromoCode(code) {
  if (!code || typeof code !== 'string') return null;
  const key = code.trim().toUpperCase();
  const def = PROMO_CODES[key];
  if (!def) return null;
  if (def.expiresAt && Date.now() > def.expiresAt) return null;
  if (!PROMO_CODE_TYPES.includes(def.type)) return null;
  return Object.assign({ code: key }, def);
}

// Apply a resolved code to the local plan. Explicit, opt-in, dormant: nothing in
// the prelaunch UI calls this yet. When wired, it records the grant + promo code
// on the plan and lets the normal sync carry it. Returns the updated plan or null.
function applyPromoCode(code) {
  const effect = resolvePromoCode(code);
  if (!effect) return null;
  return setPlanTier(effect.grantsTier, { promoCode: effect.code, source: 'promo' });
}
try {
  if (window.aurixEntitlements) {
    window.aurixEntitlements.resolvePromoCode = resolvePromoCode;
    window.aurixEntitlements.applyPromoCode = applyPromoCode;
  }
} catch (_) {}

// ── Settings panel open / close + populate ────────────────────────
function _settingsT(key) {
  try { return (T && T[lang] && T[lang][key]) || key; } catch (_) { return key; }
}
function _settingsPopulate() {
  const plan  = getPlan();

  const tierEl   = document.getElementById('planTierName');
  const emailEl  = document.getElementById('settingsAccountEmail');
  const statusEl = document.getElementById('settingsAccountStatus');

  if (tierEl) tierEl.textContent = planTierName(plan.tier);

  // Tier-aware description for the current-plan card (replaces the old asset
  // usage meter, removed in AURIX-MONETIZATION-1 · Phase 7 — Aurix does not cap
  // the number of assets). Painted dynamically so it stays correct per tier.
  const descEl = document.getElementById('planCurrentDesc');
  if (descEl) {
    descEl.textContent = isPremiumTier(plan.tier)
      ? (lang === 'es' ? 'Acceso completo a todas las herramientas premium.' : 'Full access to every premium tool.')
      : (lang === 'es' ? 'Seguimiento completo de tu patrimonio. Sin límite de activos.' : 'Full wealth tracking. No asset limit.');
  }

  // AURIX-MONETIZATION-1 · Phase 7 — Account reflects the REAL Supabase session.
  // currentUser is the single source of truth (set in the auth-restore handler).
  // The legacy window.__aurixSession path was never populated, so the email and
  // status fields were stuck on "Sin sesión" even with an active session.
  const session = (typeof currentUser !== 'undefined' && currentUser) ? currentUser : null;
  if (emailEl) {
    emailEl.textContent = (session && session.email)
      ? session.email
      : (lang === 'es' ? 'Sin sesión' : 'No session');
  }
  if (statusEl) {
    // Drop the static data-i18n binding ("Local · sin sesión") so a later
    // applyI18n() pass can't overwrite the live value, then paint real status.
    try { statusEl.removeAttribute('data-i18n'); } catch (_) {}
    statusEl.textContent = session
      ? (lang === 'es' ? 'Sesión activa' : 'Active session')
      : (lang === 'es' ? 'Sin sesión' : 'No session');
  }

  // DSH.SETTINGS.02 — "Nombre visible" (display name, same rule as the menu
  // identity header) + a membership tier chip on the plan card. Display-only.
  // DSH.SETTINGS.04 — editable display name. The input shows the resolved name
  // (displayName → saved local name → email-before-@); saving writes the local
  // override and refreshes the menu identity. No auth write.
  const nameInput = document.getElementById('settingsNameInput');
  if (nameInput && document.activeElement !== nameInput) {
    nameInput.value = (typeof _aurixMenuDisplayName === 'function')
      ? _aurixMenuDisplayName()
      : (session && session.email && session.email.indexOf('@') > 0 ? session.email.split('@')[0] : '');
    // Baseline for blur-if-changed saving.
    nameInput.dataset.baseline = nameInput.value;
  }
  // Membership tier chips (plan card + the new Cuenta "Membresía" row).
  ['settingsTierChip', 'settingsAccountTier'].forEach(id => {
    const chip = document.getElementById(id);
    if (chip) {
      const tk = plan.tier;
      chip.setAttribute('data-tier', tk);
      chip.textContent = tk === 'founder' ? 'FOUNDER' : tk === 'premium' ? 'PREMIUM' : 'FREE';
    }
  });

  // DSH.SETTINGS.TOGGLE.01 — paint Idioma/Moneda active + aria-pressed on open so
  // exactly one option is always lit (never both/neither). Clicks are handled by
  // the delegated handler that calls switchLang / _applyCurrencyChange.
  if (typeof _aurixSyncLangCurrencyButtons === 'function') _aurixSyncLangCurrencyButtons();

  // SETTINGS-INVESTOR-PROFILE-1 — paint the three investor-profile
  // chip rows from the current profile (or safe defaults if none is
  // stored). Reuses the read helper from INVESTOR-PROFILE-1 so the
  // displayed selection always matches what Signals actually consume.
  _settingsPaintProfile();
}

function _settingsPaintProfile() {
  const profile = (typeof _aurixInvestorProfile === 'function')
    ? _aurixInvestorProfile()
    : { experience: 'intermediate', riskProfile: 'balanced', ageBand: 'prefer_not_say' };
  document.querySelectorAll('[data-settings-risk]').forEach(el => {
    el.classList.toggle('is-active', el.dataset.settingsRisk === profile.riskProfile);
  });
  document.querySelectorAll('[data-settings-experience]').forEach(el => {
    el.classList.toggle('is-active', el.dataset.settingsExperience === profile.experience);
  });
  document.querySelectorAll('[data-settings-age]').forEach(el => {
    el.classList.toggle('is-active', el.dataset.settingsAge === profile.ageBand);
  });
}

// Persist a single profile facet and refresh any surface that reads
// it. Source of truth: AurixOnboarding.savePreferences (same API the
// onboarding step uses), so settings + onboarding land in the same
// localStorage blob. Signal copy is repainted in-place — no reload.
function _settingsSaveProfile(patch) {
  try {
    if (typeof window !== 'undefined' && window.AurixOnboarding
        && typeof window.AurixOnboarding.savePreferences === 'function') {
      window.AurixOnboarding.savePreferences(patch);
    } else {
      // Fallback for an environment where the engine hasn't loaded
      // yet — mirror the prefs blob directly so the data still lands.
      const raw = localStorage.getItem('aurix_onboarding_preferences');
      const cur = raw ? (JSON.parse(raw) || {}) : {};
      const next = Object.assign({}, cur, patch);
      localStorage.setItem('aurix_onboarding_preferences', JSON.stringify(next));
    }
  } catch (_) { /* best-effort */ }
  // Re-paint the Settings chip row immediately so the click feels
  // confirmed even if the engine emit hasn't fired yet.
  _settingsPaintProfile();
  // Re-render the dashboard health teaser in place so any state change
  // surfaces on the next frame.
  try { if (typeof renderAurixSignal === 'function') renderAurixSignal(); } catch (_) {}
}

// DSH.SETTINGS.05 — persist the editable display name. Saves to localStorage
// ('aurix_display_name', the same key _aurixMenuDisplayName reads), then repaints
// the menu identity so the new name shows everywhere immediately. Inline in the
// row: no Save button — Enter saves, blur-if-changed saves. No auth/backend write.
function _settingsSaveDisplayName(opts) {
  const input = document.getElementById('settingsNameInput');
  if (!input) return;
  const v = (input.value || '').trim().slice(0, 40);
  try {
    if (v) localStorage.setItem('aurix_display_name', v);
    else   localStorage.removeItem('aurix_display_name');
  } catch (_) {}
  // Reflect the resolved value (empty input falls back to email-before-@).
  input.value = (typeof _aurixMenuDisplayName === 'function') ? _aurixMenuDisplayName() : v;
  input.dataset.baseline = input.value;
  try { if (typeof _aurixRenderMenuIdentity === 'function') _aurixRenderMenuIdentity(); } catch (_) {}
  if (opts && opts.blur) { try { input.blur(); } catch (_) {} }
}

// Delegated click handler — wired once. Closes over no state.
if (typeof document !== 'undefined') {
  document.addEventListener('click', e => {
    const ov = document.getElementById('settingsOverlay');
    if (!ov || !ov.classList.contains('open')) return;
    const r = e.target.closest && e.target.closest('[data-settings-risk]');
    if (r) { _settingsSaveProfile({ riskProfile: r.dataset.settingsRisk }); return; }
    const x = e.target.closest && e.target.closest('[data-settings-experience]');
    if (x) { _settingsSaveProfile({ experience: x.dataset.settingsExperience }); return; }
    const a = e.target.closest && e.target.closest('[data-settings-age]');
    if (a) { _settingsSaveProfile({ ageBand: a.dataset.settingsAge }); return; }
  });
  // Enter inside the name field saves + blurs (never submits a form / reloads).
  document.addEventListener('keydown', e => {
    if (e.key !== 'Enter') return;
    if (e.target && e.target.id === 'settingsNameInput') {
      e.preventDefault();
      _settingsSaveDisplayName({ blur: true });
    }
  });
  // Blur (focusout bubbles) saves the name only if it actually changed.
  document.addEventListener('focusout', e => {
    const input = e.target;
    if (!input || input.id !== 'settingsNameInput') return;
    if ((input.value || '').trim() !== (input.dataset.baseline || '')) _settingsSaveDisplayName();
  });
}
// DSH.SETTINGS.01 — desktop/tablet side-nav: show one pane at a time. On mobile
// the rail is hidden (CSS) and every section is shown, so this is a no-op there.
function _settingsSelectPane(pane) {
  if (!pane) return;
  document.querySelectorAll('.settings-nav-item').forEach(btn => {
    const on = btn.dataset.settingsPane === pane;
    btn.classList.toggle('is-current', on);
    btn.setAttribute('aria-selected', on ? 'true' : 'false');
  });
  document.querySelectorAll('.settings-panes > .settings-section').forEach(sec => {
    sec.classList.toggle('is-active', sec.dataset.pane === pane);
  });
  // Reset the pane scroll so each section opens from the top.
  const panes = document.querySelector('.settings-panes');
  if (panes) { try { panes.scrollTop = 0; } catch (_) {} }
}
// Single delegated listener for the rail (attached once).
if (typeof window !== 'undefined' && !window.__aurixSettingsNavWired) {
  window.__aurixSettingsNavWired = true;
  document.addEventListener('click', e => {
    const item = e.target.closest && e.target.closest('.settings-nav-item');
    if (item && item.dataset.settingsPane) _settingsSelectPane(item.dataset.settingsPane);
  });
}

function openSettingsPanel() {
  const ov = document.getElementById('settingsOverlay');
  if (!ov) return;
  _settingsPopulate();
  _settingsSelectPane('account');   // always open on Cuenta
  ov.classList.add('open');
  document.body.classList.add('modal-open');
}
function closeSettingsPanel() {
  const ov = document.getElementById('settingsOverlay');
  if (!ov) return;
  ov.classList.remove('open');
  // Only release body lock if the reset confirm overlay isn't itself open.
  const reset = document.getElementById('resetConfirmOverlay');
  if (!reset || !reset.classList.contains('open')) {
    document.body.classList.remove('modal-open');
  }
}

// ── Reset confirm overlay ─────────────────────────────────────────
function openResetConfirm() {
  const ov = document.getElementById('resetConfirmOverlay');
  const input = document.getElementById('resetConfirmInput');
  const btn   = document.getElementById('resetConfirmBtn');
  if (!ov) return;
  if (input) input.value = '';
  if (btn)   btn.disabled = true;
  ov.classList.add('open');
  document.body.classList.add('modal-open');
  setTimeout(() => { try { input && input.focus(); } catch (_) {} }, 60);
}
function closeResetConfirm() {
  const ov = document.getElementById('resetConfirmOverlay');
  if (!ov) return;
  ov.classList.remove('open');
  const settings = document.getElementById('settingsOverlay');
  if (!settings || !settings.classList.contains('open')) {
    document.body.classList.remove('modal-open');
  }
}

// ── Safe reset ────────────────────────────────────────────────────
// Clears portfolio-related state only. Preserves: language, base
// currency, and the plan placeholder. Idempotent — safe to call twice.
// RESET-2: tombstone marker so that any future load path (Supabase
// remote, legacy migration, in-memory cache) can detect that the user
// intentionally wiped their portfolio and must not resurrect old data.
// Persisted in localStorage; cleared once remote sync confirms the
// empty state has propagated.
const RESET_AT_KEY = 'aurix_reset_at';

// RESET-5: atomic reset transaction state. While `_aurixResetInProgress`
// is true, autosave / sparkline mount / async dashboard refreshes must
// bail. `_aurixResetGeneration` lets consumers detect stale responses
// from before the reset (bump on every reset call, compare on return).
let _aurixResetInProgress = false;
let _aurixResetGeneration = 0;
function _aurixIsResetStale(gen) {
  return gen !== _aurixResetGeneration;
}

// RESET-6: sane defaults restored after a fresh-start reset (and
// applied at boot when the tombstone is set). Single source of truth
// so the post-reset state is deterministic across reloads.
const AURIX_FRESH_DEFAULTS = Object.freeze({
  dashboardRange:   '24h',
  dashboardPerfMode:'%',
  marketTab:        'all',
  marketTimeframe:  '24H',
  marketSort:       'featured',
  marketSearch:     '',
  selectedCategory: null,
});

function _applyFreshDefaults() {
  // Runtime variables — reassign the module-level lets. Each is
  // wrapped in try/catch because at boot time some may not yet be
  // initialized (depending on load order via tombstone-guarded path).
  try { activeRange         = AURIX_FRESH_DEFAULTS.dashboardRange;    } catch (_) {}
  try { activePerfMode      = AURIX_FRESH_DEFAULTS.dashboardPerfMode; } catch (_) {}
  try { currentMarketTab    = AURIX_FRESH_DEFAULTS.marketTab;         } catch (_) {}
  try { _aurixMktTimeframe  = AURIX_FRESH_DEFAULTS.marketTimeframe;   } catch (_) {}
  try { _aurixMktSortBy     = AURIX_FRESH_DEFAULTS.marketSort;        } catch (_) {}
  try { _marketSearchQuery  = AURIX_FRESH_DEFAULTS.marketSearch;      } catch (_) {}
  try { activeCategory      = AURIX_FRESH_DEFAULTS.selectedCategory;  } catch (_) {}

  // DOM sync — keep the range / perf toggle visuals consistent with
  // the new state. The market screen DOM is rebuilt by render() so
  // its active classes hydrate automatically from the variables above.
  try {
    document.querySelectorAll('.range-btn').forEach(b => {
      b.classList.toggle('active', b.dataset && b.dataset.range === AURIX_FRESH_DEFAULTS.dashboardRange);
    });
    document.querySelectorAll('.perf-btn').forEach(b => {
      b.classList.toggle('active', b.dataset && b.dataset.perf === AURIX_FRESH_DEFAULTS.dashboardPerfMode);
    });
  } catch (_) {}

  // Reset any open filter sheet / market preview / search overlay so
  // the post-reset UI is a clean slate.
  try {
    const filterOv = document.getElementById('mktFilterOverlay');
    if (filterOv && filterOv.classList.contains('open')) {
      filterOv.classList.remove('open');
      setTimeout(() => { if (!filterOv.classList.contains('open')) filterOv.hidden = true; }, 260);
    }
  } catch (_) {}
  try {
    const previewOv = document.getElementById('marketPreviewOverlay');
    if (previewOv && previewOv.classList.contains('open')) previewOv.classList.remove('open');
  } catch (_) {}
  try {
    const searchOv = document.getElementById('globalSearchOverlay');
    if (searchOv && !searchOv.hidden) {
      if (typeof closeGlobalSearch === 'function') closeGlobalSearch();
    }
  } catch (_) {}

  // Clear search input if present.
  try {
    const searchInput = document.getElementById('marketSearchInput');
    if (searchInput) searchInput.value = '';
  } catch (_) {}
}

function _aurixResetAt() {
  try { return parseInt(localStorage.getItem(RESET_AT_KEY) || '0', 10) || 0; }
  catch (_) { return 0; }
}
function _shouldDistrustRemote(remoteData) {
  // True when local reset tombstone is newer than remote's updated_at —
  // meaning the user wiped their portfolio after this remote snapshot
  // was written. Used by initPortfolioData so stale remote rows
  // never resurrect deleted assets.
  try {
    const tombstone = _aurixResetAt();
    if (!tombstone) return false;
    const remoteAt = (remoteData && remoteData.updated_at)
      ? new Date(remoteData.updated_at).getTime()
      : 0;
    return remoteAt < tombstone;
  } catch (_) { return false; }
}

async function _pushEmptyPortfolioToBackend() {
  // Best-effort push of empty assets/holdings to Supabase so the
  // remote row immediately reflects the local wipe. If offline or
  // unauthenticated, the tombstone alone protects future reads via
  // _shouldDistrustRemote until autoSave can drain.
  try {
    if (!supabaseClient || !currentUser) return;
    await supabaseClient
      .from('user_portfolios')
      .upsert({
        user_id:    currentUser.id,
        assets:     [],
        holdings:   [],
        // AURIX-PERSISTENCE-REMOTE-HISTORY-WATCHLIST-1: a reset must also wipe
        // the remote history + watchlist, else the union-by-ts merge would
        // resurrect pre-reset history on the next load. (The epoch filter is a
        // second line of defence; this clears the source.)
        portfolio_history:    [],
        category_history:     [],
        watchlist:            [],
        watchlist_updated_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      }, { onConflict: 'user_id' });
    // Clear tombstone once remote is in sync — local + remote both empty.
    try { localStorage.removeItem(RESET_AT_KEY); } catch (_) {}
  } catch (e) {
    console.warn('[reset] remote clear failed:', e && e.message);
  }
}

function performSafeReset() {
  // RESET-2: tombstone FIRST, before clearing any storage. If the
  // user reloads mid-reset (e.g. unhandled error below), the marker
  // alone is enough to prevent remote resurrection.
  // RESET-HISTORY-1: also stamp the portfolio epoch — every history
  // read filters strictly by `ts >= epoch` so stale localStorage or
  // remote sync from before this moment can never re-appear in the
  // dashboard chart or PnL math.
  const RESET_AT = Date.now();
  try { localStorage.setItem(RESET_AT_KEY, String(RESET_AT)); } catch (_) {}
  try { localStorage.setItem(PORTFOLIO_EPOCH_KEY, String(RESET_AT)); } catch (_) {}

  // AUTH-ISOLATION-1: PORTFOLIO_KEYS hoisted to module scope so the
  // SIGNED_OUT handler clears the same set. See declaration near the
  // auth listener at the top of this file.
  PORTFOLIO_KEYS.forEach(k => { try { localStorage.removeItem(k); } catch (_) {} });

  // ONBOARDING-1: notify the engine so its in-memory mirror is cleared
  // and the next eligibility check returns true again. Engine listens
  // for 'aurix:reset' and calls clearOnboardingState().
  try {
    window.dispatchEvent(new CustomEvent('aurix:reset'));
  } catch (_) {}

  try { assets = []; } catch (_) {}
  try { portfolioHistory = []; } catch (_) {}
  try { categoryHistory  = []; } catch (_) {}
  try { _cardOrder = []; } catch (_) {}
  try { _catOrder  = []; } catch (_) {}
  try { activeCategory = null; } catch (_) {}
  // RESET-HISTORY-1: clear snapshot cadence state so the next
  // recordSnapshot writes a fresh point at the new baseline instead
  // of getting absorbed into a stale 5s dedup window.
  try { lastSnapshotMs = 0; } catch (_) {}

  // Persist the empty state via the canonical save path so the
  // schema-version flag and migration vars stay consistent.
  try { if (typeof save === 'function') save('reset'); } catch (_) {}

  // Fire-and-forget remote wipe — does not block UI. Tombstone above
  // is the real safety net; this is the happy-path acceleration.
  try { _pushEmptyPortfolioToBackend(); } catch (_) {}

  // Re-render dashboard so the donut, KPIs and asset list all
  // reflect the empty state immediately.
  try { if (typeof recomputeDerivedFinancialState === 'function') recomputeDerivedFinancialState('reset'); } catch (_) {}
  try { if (typeof render === 'function') render(); } catch (_) {}

  // Notify watchlist subscribers (sparkline mounts, market UI) so
  // they refresh without a reload.
  try {
    if (typeof watchlistStore !== 'undefined' && watchlistStore && typeof watchlistStore.getWatchlist === 'function') {
      const cur = watchlistStore.getWatchlist();
      cur.forEach(k => watchlistStore.remove(k));
    }
  } catch (_) {}
}

// ── RESET-5: atomic fresh start orchestrator ──────────────────────
// Owns the entire reset lifecycle. Closes the modal first so the user
// sees a clean transition, then tears down every chart controller,
// wipes storage + memory via performSafeReset, and renders a single
// stable empty dashboard frame.
function _aurixTearDownAllCharts() {
  // Dashboard chart V2 (desktop + mobile surfaces)
  try { if (typeof _aurixDashTeardown === 'function') { _aurixDashTeardown('desktop'); _aurixDashTeardown('mobile'); } } catch (_) {}
  // Market sparklines (per row)
  try { if (typeof _aurixSparkDestroyAll === 'function') _aurixSparkDestroyAll(); } catch (_) {}
  // Asset detail chart V2
  try { if (typeof _aurixAssetTeardown === 'function') _aurixAssetTeardown(); } catch (_) {}
  // Category chart V2
  try { if (typeof _aurixCategoryTeardown === 'function') _aurixCategoryTeardown(); } catch (_) {}
  // CATEGORY-DETAIL-CHARTS-2 — premium performance panel.
  try { if (typeof _aurixCategoryPerfTeardown === 'function') _aurixCategoryPerfTeardown(); } catch (_) {}
  // Market preview chart
  try { if (typeof _aurixMktTeardown === 'function') _aurixMktTeardown(); } catch (_) {}
  // Legacy Chart.js detail sparkline
  try { if (typeof _detailChart !== 'undefined' && _detailChart) { _detailChart.destroy(); _detailChart = null; } } catch (_) {}
  // Donut: keep instance, just clear data (re-renders cleanly on render())
  try {
    if (typeof donutChart !== 'undefined' && donutChart) {
      donutChart.data.labels = [];
      donutChart.data.datasets[0].data = [];
      donutChart.update('none');
    }
  } catch (_) {}
  try {
    if (typeof donutChartMobile !== 'undefined' && donutChartMobile) {
      donutChartMobile.data.labels = [];
      donutChartMobile.data.datasets[0].data = [];
      donutChartMobile.update('none');
    }
  } catch (_) {}
}

function _aurixShowToast(message, opts) {
  // Minimal premium toast — body-level transient. Auto-disappears.
  // Sits above the bottom nav safe area on mobile.
  try {
    const o = opts || {};
    const variant = String(o.variant || 'success'); // success | info | error
    const ms      = Math.max(1500, Math.min(6000, Number(o.duration) || 2400));
    let host = document.getElementById('aurixToastHost');
    if (!host) {
      host = document.createElement('div');
      host.id = 'aurixToastHost';
      host.className = 'aurix-toast-host';
      document.body.appendChild(host);
    }
    const el = document.createElement('div');
    el.className = `aurix-toast aurix-toast--${variant}`;
    el.textContent = String(message || '');
    host.appendChild(el);
    // Trigger CSS transition on next frame.
    requestAnimationFrame(() => el.classList.add('is-open'));
    setTimeout(() => {
      el.classList.remove('is-open');
      setTimeout(() => { try { el.remove(); } catch (_) {} }, 360);
    }, ms);
  } catch (_) {}
}

// AURIX-PREMIUM-CONFIRM-DIALOG-1: premium replacement for native confirm().
// Returns a Promise<boolean> (true = confirmed, false = cancelled). Dark-blue
// Aurix sheet, soft glow, Escape/backdrop = cancel, Enter = confirm. The cancel
// button is focused by default so a destructive action is never the accidental
// path. Falls back to window.confirm if DOM construction ever fails. UI-only —
// no persistence/data/engine touched.
function _aurixConfirm(opts) {
  const o = opts || {};
  return new Promise(resolve => {
    try {
      const danger = o.danger !== false; // destructive styling by default
      const prev = document.getElementById('aurixConfirmHost');
      if (prev) { try { prev.remove(); } catch (_) {} }
      const host = document.createElement('div');
      host.id = 'aurixConfirmHost';
      host.className = 'aurix-confirm-host';
      host.innerHTML =
        `<div class="aurix-confirm-backdrop"></div>` +
        `<div class="aurix-confirm" role="alertdialog" aria-modal="true" aria-labelledby="aurixConfirmTitle" aria-describedby="aurixConfirmMsg">` +
          `<div class="aurix-confirm-title" id="aurixConfirmTitle">${escHtml(o.title || '')}</div>` +
          `<div class="aurix-confirm-msg" id="aurixConfirmMsg">${escHtml(o.message || '')}</div>` +
          `<div class="aurix-confirm-actions">` +
            `<button type="button" class="aurix-confirm-btn aurix-confirm-cancel">${escHtml(o.cancelLabel || 'Cancelar')}</button>` +
            `<button type="button" class="aurix-confirm-btn ${danger ? 'aurix-confirm-danger' : 'aurix-confirm-primary'}">${escHtml(o.confirmLabel || 'OK')}</button>` +
          `</div>` +
        `</div>`;
      document.body.appendChild(host);
      requestAnimationFrame(() => host.classList.add('is-open'));
      let done = false;
      const cleanup = (val) => {
        if (done) return; done = true;
        host.classList.remove('is-open');
        document.removeEventListener('keydown', onKey, true);
        setTimeout(() => { try { host.remove(); } catch (_) {} }, 240);
        resolve(val);
      };
      const onKey = (e) => {
        if (e.key === 'Escape') { e.preventDefault(); cleanup(false); }
        else if (e.key === 'Enter') { e.preventDefault(); cleanup(true); }
      };
      host.querySelector('.aurix-confirm-cancel').addEventListener('click', () => cleanup(false));
      host.querySelector('.aurix-confirm-danger, .aurix-confirm-primary').addEventListener('click', () => cleanup(true));
      host.querySelector('.aurix-confirm-backdrop').addEventListener('click', () => cleanup(false));
      document.addEventListener('keydown', onKey, true);
      setTimeout(() => { try { host.querySelector('.aurix-confirm-cancel').focus(); } catch (_) {} }, 30);
    } catch (_) {
      try { resolve(window.confirm(o.message || '')); } catch (_e) { resolve(false); }
    }
  });
}

async function performAtomicFreshStartReset() {
  if (_aurixResetInProgress) return false;
  _aurixResetInProgress = true;
  _aurixResetGeneration++;
  const gen = _aurixResetGeneration;

  try {
    // 1. Close the confirm + settings modals first so the user sees
    //    the dashboard during the cleanup (no double-render with
    //    overlays still mounted).
    try { if (typeof closeResetConfirm   === 'function') closeResetConfirm();   } catch (_) {}
    try { if (typeof closeSettingsPanel  === 'function') closeSettingsPanel();  } catch (_) {}

    // 2. Tear down every chart controller before storage wipe. Stops
    //    deferred resize/update callbacks from touching stale assets.
    _aurixTearDownAllCharts();

    // 3. Storage + memory wipe + tombstone + remote push (the legacy
    //    safe path — already idempotent and well-tested via RESET-1/2).
    try { performSafeReset(); } catch (e) {
      console.warn('[reset] safe reset failed:', e && e.message);
    }
    if (_aurixIsResetStale(gen)) return false; // a newer reset took over

    // 4. RESET-6: apply sane defaults BEFORE the empty-state render
    //    so dashboard range / perf mode / market tab / sort all reset
    //    deterministically in the same paint frame.
    try { _applyFreshDefaults(); } catch (e) {
      console.warn('[reset] apply defaults failed:', e && e.message);
    }

    // 5. Single stable empty-state render after a paint tick. This
    //    ensures the assets list, donut, KPIs, and any reactive
    //    derived state all flush together — no half-empty UI.
    await new Promise(r => requestAnimationFrame(() => r()));
    try { if (typeof recomputeDerivedFinancialState === 'function') recomputeDerivedFinancialState('reset-frame2'); } catch (_) {}
    try { if (typeof render === 'function') render(); } catch (_) {}

    // AURIX-EMPTY-1: render() owns the hero + asset-list empty state,
    // but the donut + category grid + chart placeholder are driven by
    // onPortfolioChange. Without this call the ghost ring + new
    // empty-mode copy would only appear on the next price-tick, leaving
    // a brief stale frame after reset.
    try { if (typeof onPortfolioChange === 'function') onPortfolioChange(false); } catch (_) {}

    // 5. After the render commits, let the chart engine settle its
    //    layout (resize observers / dvh changes) on the next frame.
    await new Promise(r => requestAnimationFrame(() => r()));

    // 6. Success toast.
    const isEs = (typeof lang !== 'undefined' && lang === 'es');
    _aurixShowToast(isEs ? 'Cartera reiniciada' : 'Portfolio reset', { variant: 'success' });

    // 7. ONBOARDING-1B §2: reset must feel like a completed clean
    //    action, NOT shove the user into another modal immediately.
    //    The portfolio is wiped and the onboarding flag is cleared
    //    (via 'aurix:reset' → engine.clearOnboardingState), so the
    //    flow is re-eligible. We only auto-show if the project opts
    //    in via an explicit window flag — default is OFF so a clean
    //    empty dashboard is the post-reset experience. The next
    //    authenticated boot will surface onboarding naturally.
    if (window.AURIX_SHOW_ONBOARDING_AFTER_RESET === true) {
      setTimeout(() => {
        if (typeof window.maybeShowOnboarding === 'function') {
          window.maybeShowOnboarding();
        }
      }, 280);
    }
    return true;
  } finally {
    _aurixResetInProgress = false;
  }
}

// ── Export data (download as JSON file) ───────────────────────────
function _todayStamp() {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm   = String(d.getMonth() + 1).padStart(2, '0');
  const dd   = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}
function exportPortfolioBackup() {
  const payload = {
    schema:        'aurix.backup.v1',
    exportedAt:    new Date().toISOString(),
    baseCurrency:  baseCurrency,
    lang:          lang,
    plan:          getPlan(),
    assets:        Array.isArray(assets) ? assets : [],
    portfolioHistory: Array.isArray(portfolioHistory) ? portfolioHistory : [],
    categoryHistory:  Array.isArray(categoryHistory)  ? categoryHistory  : [],
    watchlist:     (typeof getWatchlist === 'function') ? getWatchlist() : [],
  };
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = `aurix-backup-${_todayStamp()}.json`;
  document.body.appendChild(a);
  a.click();
  setTimeout(() => { try { URL.revokeObjectURL(url); a.remove(); } catch (_) {} }, 0);
}

// ── Wiring: open from menu, close, reset, export, type-RESET gate ─
(function _initSettingsPanel() {
  // Menu entry
  document.addEventListener('click', e => {
    const trigger = e.target.closest && e.target.closest('#menuGeneral');
    if (trigger) {
      e.stopPropagation();
      // Close hamburger menu if open
      const panel = document.getElementById('menuPanel');
      const toggle = document.getElementById('menuToggle');
      if (panel && panel.classList.contains('open')) panel.classList.remove('open');
      if (toggle) toggle.setAttribute('aria-expanded', 'false');
      openSettingsPanel();
    }
  });

  // Settings overlay interactions (close, export, reset)
  document.addEventListener('click', e => {
    if (e.target.closest && e.target.closest('#settingsClose')) {
      closeSettingsPanel();
      return;
    }
    // Backdrop click on settings overlay closes it (clicking outside the modal box).
    const settingsOv = document.getElementById('settingsOverlay');
    if (settingsOv && settingsOv.classList.contains('open') &&
        e.target === settingsOv) {
      closeSettingsPanel();
      return;
    }
    if (e.target.closest && e.target.closest('#settingsExportBtn')) {
      try { exportPortfolioBackup(); } catch (err) { console.warn('[settings] export fail:', err && err.message); }
      return;
    }
    if (e.target.closest && e.target.closest('#settingsResetBtn')) {
      openResetConfirm();
      return;
    }

    // Reset confirm overlay
    if (e.target.closest && e.target.closest('#resetConfirmClose')) {
      closeResetConfirm();
      return;
    }
    const resetOv = document.getElementById('resetConfirmOverlay');
    if (resetOv && resetOv.classList.contains('open') && e.target === resetOv) {
      closeResetConfirm();
      return;
    }
    if (e.target.closest && e.target.closest('#resetConfirmBtn')) {
      const btn = document.getElementById('resetConfirmBtn');
      if (btn && btn.disabled) return;
      // RESET-5: hand off to the atomic orchestrator. It owns the
      // modal close, chart teardown, storage wipe, remote push,
      // single empty render, and success toast. Button disables to
      // prevent double-click during the brief async window.
      if (btn) btn.disabled = true;
      Promise.resolve()
        .then(() => performAtomicFreshStartReset())
        .catch(err => console.warn('[settings] reset fail:', err && err.message));
      return;
    }
  });

  // Type-RESET gate
  document.addEventListener('input', e => {
    if (!e.target || e.target.id !== 'resetConfirmInput') return;
    const v   = String(e.target.value || '').trim().toUpperCase();
    const btn = document.getElementById('resetConfirmBtn');
    if (btn) btn.disabled = (v !== 'RESET');
  });

  // Escape closes the topmost open overlay
  document.addEventListener('keydown', e => {
    if (e.key !== 'Escape') return;
    const resetOv    = document.getElementById('resetConfirmOverlay');
    const settingsOv = document.getElementById('settingsOverlay');
    if (resetOv && resetOv.classList.contains('open'))      { closeResetConfirm();   return; }
    if (settingsOv && settingsOv.classList.contains('open')) { closeSettingsPanel(); return; }
  });
})();

/* ──────────────────────────────────────────────────────────────────
   AURIX-MONETIZATION-1 · Phases 4/5/6/8 — Founder page + upgrade gate.
   --------------------------------------------------------------------
   Presentation + a dormant gate. No payments, no Stripe, no paywall.
   requireFeature() is the seam premium surfaces will call; while
   ENFORCE_ENTITLEMENTS=false it always runs the allowed path, so the
   upgrade modal never appears. The Founder page is reachable from the
   menu and the settings plan card. The main dashboard is left untouched.
   ────────────────────────────────────────────────────────────────── */

// Localized labels for premium features — drives the Founder benefits list and
// the upgrade modal headline. New premium modules add their key + label here.
const FEATURE_LABELS = {
  wealth_evolution:       { es: 'Wealth Evolution',        en: 'Wealth Evolution' },
  portfolio_intelligence: { es: 'Portfolio Intelligence',  en: 'Portfolio Intelligence' },
  workspace_advanced:     { es: 'Workspace avanzado',      en: 'Advanced Workspace' },
  portfolio_health:       { es: 'Portfolio Health',        en: 'Portfolio Health' },
  monthly_reports:        { es: 'Informes mensuales',      en: 'Monthly reports' },
  advanced_exports:       { es: 'Exportaciones avanzadas', en: 'Advanced exports' },
  ai_wealth_assistant:    { es: 'AI Wealth Assistant',     en: 'AI Wealth Assistant' },
};
// Display order for the Founder "Incluye" list (matches the product framing).
const FOUNDER_BENEFIT_ORDER = [
  'wealth_evolution', 'portfolio_intelligence', 'workspace_advanced',
  'portfolio_health', 'monthly_reports', 'advanced_exports', 'ai_wealth_assistant',
];
function _featureLabel(key) {
  const l = FEATURE_LABELS[key];
  if (!l) return key;
  return (typeof lang !== 'undefined' && l[lang]) ? l[lang] : l.es;
}

function _renderFounderBenefits() {
  const ul = document.getElementById('founderBenefitsList');
  if (!ul) return;
  const futureLabel = (typeof lang !== 'undefined' && lang === 'en')
    ? 'Future premium tools' : 'Futuras herramientas premium';
  const items = FOUNDER_BENEFIT_ORDER.map(k => _featureLabel(k)).concat([futureLabel]);
  ul.innerHTML = items.map(() =>
    '<li class="founder-benefit"><span class="founder-benefit-check" aria-hidden="true">✓</span>' +
    '<span class="founder-benefit-label"></span></li>').join('');
  // Set text safely (labels are trusted, but textContent keeps it injection-proof).
  const labels = ul.querySelectorAll('.founder-benefit-label');
  items.forEach((label, i) => { if (labels[i]) labels[i].textContent = label; });
}

function openFounderPage() {
  const ov = document.getElementById('founderOverlay');
  if (!ov) return;
  _renderFounderBenefits();
  const priceEl = document.getElementById('founderPriceAmount');
  try {
    const c = (typeof PLAN_CATALOG !== 'undefined') ? PLAN_CATALOG.founder : null;
    if (priceEl && c && c.priceLabel) priceEl.textContent = c.priceLabel[lang] || c.priceLabel.es;
  } catch (_) {}
  if (typeof applyI18n === 'function') applyI18n();
  ov.classList.add('open');
  ov.setAttribute('aria-hidden', 'false');
  document.body.classList.add('modal-open');
}
function closeFounderPage() {
  const ov = document.getElementById('founderOverlay');
  if (!ov) return;
  ov.classList.remove('open');
  ov.setAttribute('aria-hidden', 'true');
  // Keep the body lock if the settings panel that launched it is still open.
  const settings = document.getElementById('settingsOverlay');
  if (!settings || !settings.classList.contains('open')) {
    document.body.classList.remove('modal-open');
  }
}

function openUpgradeModal(feature) {
  const ov = document.getElementById('upgradeOverlay');
  if (!ov) return;
  const nameEl = document.getElementById('upgradeFeatureName');
  if (nameEl) {
    nameEl.textContent = feature
      ? _featureLabel(feature)
      : (lang === 'en' ? 'Premium feature' : 'Función premium');
  }
  if (typeof applyI18n === 'function') applyI18n();
  ov.classList.add('open');
  ov.setAttribute('aria-hidden', 'false');
  document.body.classList.add('modal-open');
}
function closeUpgradeModal() {
  const ov = document.getElementById('upgradeOverlay');
  if (!ov) return;
  ov.classList.remove('open');
  ov.setAttribute('aria-hidden', 'true');
  document.body.classList.remove('modal-open');
}

// The seam every premium surface will call. While ENFORCE_ENTITLEMENTS=false,
// hasFeature() is always true → onAllowed runs and the upgrade modal never
// shows. Returns true if access was granted. Deliberately NOT wired into the
// dashboard in prelaunch (the main dashboard stays untouched).
function requireFeature(feature, onAllowed) {
  if (hasFeature(feature)) {
    if (typeof onAllowed === 'function') onAllowed();
    return true;
  }
  openUpgradeModal(feature);
  return false;
}
try {
  if (window.aurixEntitlements) {
    window.aurixEntitlements.requireFeature = requireFeature;
    window.aurixEntitlements.openFounderPage = openFounderPage;
    window.aurixEntitlements.openUpgradeModal = openUpgradeModal;
  }
} catch (_) {}

(function _initFounderUI() {
  if (typeof document === 'undefined') return;
  document.addEventListener('click', e => {
    // WN.P1 — Menu entry → Aurix Premium modal (also closes the hamburger menu).
    // Repointed from the old Founder page; the Founder page stays reachable from
    // the settings plan card and the upgrade modal (those entrypoints unchanged).
    if (e.target.closest && e.target.closest('#menuPremium')) {
      e.stopPropagation();
      // PREMIUM-PREVIEW-FINAL — Free users see an intrigue/coming-soon state: clicking does NOTHING
      // (no modal, no navigation, no error). Owner (authenticated email) gets the normal clickable item.
      const _premiumUser = (typeof hasAurixPremiumAccess === 'function') && hasAurixPremiumAccess(_aurixCurrentAuthUser());
      if (!_premiumUser) { e.preventDefault(); return; }
      const panel = document.getElementById('menuPanel');
      const toggle = document.getElementById('menuToggle');
      if (panel && panel.classList.contains('open')) panel.classList.remove('open');
      if (toggle) toggle.setAttribute('aria-expanded', 'false');
      if (typeof window !== 'undefined' && window.openAurixPremiumModal) window.openAurixPremiumModal({ source: 'settings-menu' });
      return;
    }
    // Settings membership card CTA → canonical Aurix Premium modal (same surface
    // as the menu). DSH.SETTINGS.01 visual naming alignment; premium logic and
    // entitlements untouched. Founder page kept as fallback if the modal is absent.
    if (e.target.closest && e.target.closest('#planFounderCta')) {
      if (typeof window !== 'undefined' && window.openAurixPremiumModal) {
        window.openAurixPremiumModal({ source: 'settings-membership' });
      } else {
        openFounderPage();
      }
      return;
    }
    // Upgrade modal → Founder page.
    if (e.target.closest && e.target.closest('#upgradeFounderBtn')) {
      closeUpgradeModal(); openFounderPage(); return;
    }
    // Closes.
    if (e.target.closest && e.target.closest('#founderClose')) { closeFounderPage(); return; }
    if (e.target.closest && e.target.closest('#upgradeClose'))  { closeUpgradeModal(); return; }
    // Backdrop closes.
    const fov = document.getElementById('founderOverlay');
    if (fov && fov.classList.contains('open') && e.target === fov) { closeFounderPage(); return; }
    const uov = document.getElementById('upgradeOverlay');
    if (uov && uov.classList.contains('open') && e.target === uov) { closeUpgradeModal(); return; }
  });
  // Escape closes whichever monetization overlay is on top.
  document.addEventListener('keydown', e => {
    if (e.key !== 'Escape') return;
    const uov = document.getElementById('upgradeOverlay');
    const fov = document.getElementById('founderOverlay');
    if (uov && uov.classList.contains('open')) { closeUpgradeModal(); return; }
    if (fov && fov.classList.contains('open')) { closeFounderPage();  return; }
  });
})();

// ── WN.P1 — Aurix Premium modal (reusable conversion layer) ────────────────
// Frontend-only. A centered premium dialog opened from the settings menu (and
// later from any conversion point) via openAurixPremiumModal({source}). No
// route change, no payment, no backend — just the reusable invitation UI.
// Founder slot numbers are static placeholders wired so real values can be fed
// in later. Self-contained: DOM is built lazily, all classes are .aurix-premium-*.
(function _initAurixPremiumModal() {
  if (typeof document === 'undefined') return;
  const FOUNDER = { founderSlotsTotal: 50, founderSlotsTaken: 10, founderSlotsRemaining: 40 };
  let _open = false, _lastSource = null, _trigger = null, _el = null;
  const esc = s => String(s == null ? '' : s).replace(/[&<>"]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
  const log = (action, extra) => { try { console.log('[premium-modal]', Object.assign({ action, source: _lastSource }, extra || {})); } catch (_) {} };

  // All copy is i18n-keyed → the modal renders 100% in the active language
  // (rebuilt on every open). Localized terms only (no hybrid ES/EN strings).
  const FREE_K = ['ap_f_dash', 'ap_f_evo', 'ap_f_assets', 'ap_f_dist', 'ap_f_track', 'ap_f_market', 'ap_f_metals', 'ap_f_re', 'ap_f_liq', 'ap_f_wsbasic', 'ap_f_viz'];
  const PREM_K = ['ap_p_health', 'ap_p_intel', 'ap_p_risk', 'ap_p_conc', 'ap_p_div', 'ap_p_drivers', 'ap_p_liq', 'ap_p_timeline', 'ap_p_ws', 'ap_p_goals', 'ap_p_reports', 'ap_p_future'];
  const IND_K = ['ap_ind_risk', 'ap_ind_conc', 'ap_ind_liq', 'ap_ind_div', 'ap_ind_evo'];
  const STD_B = ['ap_std_b1', 'ap_std_b2', 'ap_std_b3', 'ap_std_b4'];
  const FND_B = ['ap_founder_b1', 'ap_founder_b2', 'ap_founder_b3', 'ap_founder_b4'];
  const li = (keys, cls) => keys.map(k => `<li class="${cls}">${esc(t(k))}</li>`).join('');

  function _buildHtml() {
    const tk = FOUNDER.founderSlotsTaken, tot = FOUNDER.founderSlotsTotal, rem = FOUNDER.founderSlotsRemaining;
    const pct = Math.round((tk / tot) * 100);
    const scar = esc(t('ap_scarcity')).replace('{taken}', tk).replace('{total}', tot).replace('{rem}', rem);
    return `
      <div class="aurix-premium-modal" role="dialog" aria-modal="true" aria-labelledby="aurixPremiumTitle">
        <button type="button" class="aurix-premium-close" aria-label="${esc(t('ap_close'))}">✕</button>
        <header class="aurix-premium-header">
          <span class="aurix-premium-eyebrow">${esc(t('ap_eyebrow'))}</span>
          <h2 id="aurixPremiumTitle" class="aurix-premium-tagline">${esc(t('ap_hero_title'))}</h2>
          <p class="aurix-premium-sub">${esc(t('ap_hero_sub'))}</p>
        </header>

        <div class="aurix-premium-comparison">
          <div class="aurix-premium-compare-col is-free">
            <span class="aurix-premium-compare-tier">${esc(t('ap_free_tier'))}</span>
            <p class="aurix-premium-card-desc">${esc(t('ap_free_desc'))}</p>
            <ul class="aurix-premium-list is-2col">${li(FREE_K, 'is-free')}</ul>
          </div>
          <div class="aurix-premium-compare-col is-premium">
            <span class="aurix-premium-compare-tier">${esc(t('ap_premium_tier'))}</span>
            <p class="aurix-premium-card-desc">${esc(t('ap_std_text'))}</p>
            <ul class="aurix-premium-list is-2col">${li(PREM_K, 'is-prem')}</ul>
          </div>
        </div>

        <div class="aurix-premium-plans">
          <div class="aurix-premium-plan aurix-premium-standard">
            <h3 class="aurix-premium-plan-title">${esc(t('ap_std_title'))}</h3>
            <ul class="aurix-premium-benefits">${li(STD_B, 'is-prem')}</ul>
            <div class="aurix-premium-price"><span class="aurix-premium-price-amount">59€</span><span class="aurix-premium-price-per">${esc(t('ap_per_year'))}</span></div>
            <p class="aurix-premium-plan-note">${esc(t('ap_std_sub'))}</p>
            <button type="button" class="aurix-premium-cta is-premium" data-premium-cta="premium_annual">${esc(t('ap_std_cta'))}</button>
            <button type="button" class="aurix-premium-cta is-monthly" data-premium-cta="premium_monthly">${esc(t('ap_std_monthly'))}</button>
          </div>

          <div class="aurix-premium-plan aurix-premium-founder">
            <div class="aurix-premium-plan-top">
              <h3 class="aurix-premium-plan-title">${esc(t('ap_founder_title'))}</h3>
              <span class="aurix-premium-badge">${esc(t('ap_founder_badge'))}</span>
            </div>
            <span class="aurix-premium-seat">${esc(t('ap_founder_seat')).replace('{n}', tk).replace('{tot}', tot)}</span>
            <p class="aurix-premium-plan-desc">${esc(t('ap_founder_text'))}</p>
            <ul class="aurix-premium-benefits">${li(FND_B, 'is-founder')}</ul>
            <div class="aurix-premium-price"><span class="aurix-premium-price-amount">39€</span><span class="aurix-premium-price-per">${esc(t('ap_per_year'))}</span></div>
            <p class="aurix-premium-plan-note">${esc(t('ap_founder_note'))}</p>
            <div class="aurix-premium-scarcity">
              <div class="aurix-premium-scarcity-bar"><span style="width:${pct}%"></span></div>
              <span class="aurix-premium-scarcity-txt">${scar}</span>
            </div>
            <button type="button" class="aurix-premium-cta is-founder" data-premium-cta="founder">${esc(t('ap_founder_cta'))}</button>
          </div>
        </div>

        <footer class="aurix-premium-footer">
          <p class="aurix-premium-trust-1">${esc(t('ap_trust_1'))}</p>
          <p class="aurix-premium-microcopy">${esc(t('ap_trust_2'))}</p>
        </footer>
      </div>`;
  }

  function _ctaState(btn) {
    if (!btn || btn.dataset.done === '1') return;
    btn.dataset.done = '1';
    btn.textContent = (typeof lang !== 'undefined' && lang === 'en') ? "We'll notify you soon" : 'Te avisaremos pronto';
    btn.classList.add('is-done');
  }

  function _wire(el) {
    el.addEventListener('click', e => {
      if (e.target === el) { closeAurixPremiumModal(); return; }                 // outside click
      if (e.target.closest('.aurix-premium-close')) { closeAurixPremiumModal(); return; }
      const cta = e.target.closest('[data-premium-cta]');
      if (cta) { log('cta_click', { plan: cta.getAttribute('data-premium-cta') }); _ctaState(cta); return; }
    });
    // Focus trap (Tab cycles within the modal while open).
    el.addEventListener('keydown', e => {
      if (e.key !== 'Tab' || !_open) return;
      const f = el.querySelectorAll('button, [href], [tabindex]:not([tabindex="-1"])');
      if (!f.length) return;
      const first = f[0], last = f[f.length - 1];
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
    });
  }

  function openAurixPremiumModal(options) {
    options = options || {};
    _lastSource = options.source || 'unknown';
    log('open');
    _trigger = (document.activeElement && document.activeElement.focus) ? document.activeElement : null;
    if (!_el) {
      _el = document.createElement('div');
      _el.className = 'aurix-premium-overlay';
      document.body.appendChild(_el);
      _wire(_el);   // delegated listeners on _el persist across innerHTML rebuilds
    }
    // Rebuild every open so the modal renders in the CURRENTLY active language
    // (and starts from a fresh, un-clicked CTA state).
    _el.innerHTML = _buildHtml();
    _el.style.display = 'flex';
    requestAnimationFrame(() => _el.classList.add('is-open'));
    document.body.classList.add('aurix-premium-lock');
    _open = true;
    const closeBtn = _el.querySelector('.aurix-premium-close');
    if (closeBtn) closeBtn.focus();
  }

  function closeAurixPremiumModal() {
    if (!_el || !_open) return;
    _open = false;
    _el.classList.remove('is-open');
    document.body.classList.remove('aurix-premium-lock');
    log('close');
    const el = _el;
    setTimeout(() => { if (!_open && el) el.style.display = 'none'; }, 220);
    if (_trigger && _trigger.focus) { try { _trigger.focus(); } catch (_) {} }
  }

  document.addEventListener('keydown', e => { if (_open && e.key === 'Escape') { e.stopPropagation(); closeAurixPremiumModal(); } });

  // Canonical entry points (Part 10) — every future Premium button reuses these.
  window.openPremiumModal = openAurixPremiumModal;
  window.closePremiumModal = closeAurixPremiumModal;
  // Back-compat aliases (settings-menu hook + earlier call sites).
  window.openAurixPremiumModal = openAurixPremiumModal;
  window.closeAurixPremiumModal = closeAurixPremiumModal;
  window.aurixPremiumModal = { open: openAurixPremiumModal, close: closeAurixPremiumModal };
  window.debugAurixPremiumModal = () => ({
    installed: true, isOpen: _open, lastSource: _lastSource,
    founderSlotsTotal: FOUNDER.founderSlotsTotal, founderSlotsTaken: FOUNDER.founderSlotsTaken, founderSlotsRemaining: FOUNDER.founderSlotsRemaining,
    ctasAvailable: ['founder', 'premium_annual', 'premium_monthly'],
    menuHookInstalled: !!document.getElementById('menuPremium'),
  });
})();

// ── ONBOARDING-1: activation UI wiring ─────────────────────────────
// State machine + persistence live in services/onboarding-engine.js.
// This IIFE only binds DOM → engine and engine → DOM. No state lives here.
(function _initOnboardingUI() {
  if (!window.AurixOnboarding) {
    console.warn('[onboarding] engine not loaded — UI disabled');
    return;
  }

  const Eng       = window.AurixOnboarding;
  const STATES    = Eng.STATES;
  let pendingLang = null;        // chosen on LANGUAGE step, applied on continue
  let pendingExp  = null;        // selected experience (UI-only mirror)
  let awaitingAsset = false;     // ACTIVATION → add-asset → SUCCESS handoff
  // ONBOARDING-1B §3: only allow ONE auto-return to Activation per
  // session. If the user closes Add Asset without adding anything we
  // restore the onboarding modal once; further dismissals leave them
  // on the dashboard, where Skip + manual reopen remain available.
  let _activationAddAttempted = false;

  function _ov() { return document.getElementById('onboardingOverlay'); }
  function _modal() { return document.querySelector('#onboardingOverlay .modal'); }

  function _closeConflictingOverlays() {
    // Spec §23: ensure no other overlay is sitting under onboarding.
    [
      'modalOverlay', 'marketPreviewOverlay', 'globalSearchOverlay',
      'mktFilterOverlay', 'settingsOverlay', 'resetConfirmOverlay',
    ].forEach(id => {
      const el = document.getElementById(id);
      if (el && el.classList.contains('open')) el.classList.remove('open');
    });
    document.body.classList.remove('modal-open');
  }

  function _openOnboardingOverlay() {
    const ov = _ov();
    if (!ov) return;
    _closeConflictingOverlays();
    ov.classList.add('open');
    ov.setAttribute('aria-hidden', 'false');
    document.body.classList.add('modal-open');
    // Make sure data-step on .modal reflects the engine's truth.
    const snap = Eng.getSnapshot();
    if (snap.state && snap.state !== STATES.COMPLETED) {
      _modal()?.setAttribute('data-step', snap.state);
    }
    // Re-apply i18n in case language was switched after initial render.
    if (typeof applyI18n === 'function') applyI18n();
    _syncSelectionsFromState();
  }

  function _hideOnboardingOverlay() {
    const ov = _ov();
    if (!ov) return;
    ov.classList.remove('open');
    ov.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('modal-open');
  }

  function _syncSelectionsFromState() {
    const snap = Eng.getSnapshot();
    // Language cards
    document.querySelectorAll('[data-onb-lang]').forEach(el => {
      const sel = (pendingLang || snap.language) === el.dataset.onbLang;
      el.classList.toggle('is-selected', !!sel);
    });
    const langCta = document.getElementById('onbLangContinue');
    if (langCta) langCta.disabled = !(pendingLang || snap.language);

    // Interests chips
    const set = new Set(snap.interests || []);
    document.querySelectorAll('[data-onb-interest]').forEach(el => {
      el.classList.toggle('is-selected', set.has(el.dataset.onbInterest));
    });

    // Experience cards
    document.querySelectorAll('[data-onb-exp]').forEach(el => {
      el.classList.toggle('is-selected', (pendingExp || snap.experience) === el.dataset.onbExp);
    });

    // ONBOARDING-PROFILE-UI-1 — risk profile + age band selection
    // mirror. Defaults apply visually when nothing is stored yet:
    // balanced is highlighted in the markup; prefer_not_say carries
    // is-active. We override both with the engine's stored value
    // when present so a reload mid-flow restores the user's pick.
    const riskNow = snap.riskProfile || 'balanced';
    document.querySelectorAll('[data-onb-risk]').forEach(el => {
      const sel = el.dataset.onbRisk === riskNow;
      el.classList.toggle('is-selected', sel);
      el.classList.toggle('is-active',   sel);
    });
    const ageNow = snap.ageBand || 'prefer_not_say';
    document.querySelectorAll('[data-onb-age]').forEach(el => {
      const sel = el.dataset.onbAge === ageNow;
      el.classList.toggle('is-selected', sel);
      el.classList.toggle('is-active',   sel);
    });
  }

  // ONBOARDING-2 / 2B: success step body + count chip reflect the
  // current asset count. n=1 → "Has añadido tu primer activo. …";
  // n>=2 → "Puedes seguir construyendo …". The chip carries the
  // numeric proof ("Tienes 1 activo" / "Tienes 3 activos") so the
  // user sees their progress at a glance.
  function _updateSuccessCopy() {
    const body = document.getElementById('onbSuccessBody');
    const chip = document.getElementById('onbSuccessChip');
    const n = Array.isArray(assets) ? assets.length : 0;
    if (body) {
      if (n <= 1) {
        body.textContent = t('onbSuccessBody1') || '';
      } else {
        const fn = t('onbSuccessBodyN');
        body.textContent = (typeof fn === 'function') ? fn(n) : '';
      }
    }
    if (chip) {
      const fn = t('onbSuccessCount');
      chip.textContent = (typeof fn === 'function') ? fn(n) : '';
      chip.hidden = (n <= 0);
    }
  }

  // ONBOARDING-2B §17: expose UI-level flags so the engine's debug
  // helper can surface them. Read-only snapshot — never mutate from
  // outside the closure.
  window._aurixOnbUiState = function () {
    return {
      awaitingAsset:           awaitingAsset,
      activationAddAttempted:  _activationAddAttempted,
      pendingLang:             pendingLang,
      pendingExp:              pendingExp,
      assetCount:              Array.isArray(assets) ? assets.length : 0,
    };
  };

  // ── Step navigation handlers ───────────────────────────────────
  // Language selection
  document.addEventListener('click', e => {
    const langBtn = e.target.closest && e.target.closest('[data-onb-lang]');
    if (langBtn && _ov()?.classList.contains('open')) {
      pendingLang = langBtn.dataset.onbLang;
      _syncSelectionsFromState();
      return;
    }

    // Language CTA — apply language, advance.
    const langContinue = e.target.closest && e.target.closest('#onbLangContinue');
    if (langContinue && _ov()?.classList.contains('open')) {
      const chosen = pendingLang || Eng.getSnapshot().language;
      if (!chosen) return;
      // Apply to the app immediately so subsequent screens render in the
      // user's chosen language. switchLang already persists portfolio_lang.
      try {
        if (typeof switchLang === 'function' && chosen !== lang) switchLang(chosen);
        else if (typeof applyI18n === 'function') applyI18n();
      } catch (_) {}
      Eng.setLanguage(chosen);
      Eng.nextStep();
      return;
    }

    // Interest chip toggle (multi-select)
    const chip = e.target.closest && e.target.closest('[data-onb-interest]');
    if (chip && _ov()?.classList.contains('open')) {
      const snap = Eng.getSnapshot();
      const key = chip.dataset.onbInterest;
      const cur = new Set(snap.interests || []);
      if (cur.has(key)) cur.delete(key); else cur.add(key);
      Eng.savePreferences({ interests: Array.from(cur) });
      return;
    }

    // Experience card (single-select)
    const expCard = e.target.closest && e.target.closest('[data-onb-exp]');
    if (expCard && _ov()?.classList.contains('open')) {
      pendingExp = expCard.dataset.onbExp;
      Eng.savePreferences({ experience: pendingExp });
      _syncSelectionsFromState();
      return;
    }

    // ONBOARDING-PROFILE-UI-1 — risk profile chip (single-select).
    // Persists immediately so a "back" navigation never loses the
    // selection. Continue handler is the generic [data-onb-next].
    const riskChip = e.target.closest && e.target.closest('[data-onb-risk]');
    if (riskChip && _ov()?.classList.contains('open')) {
      Eng.savePreferences({ riskProfile: riskChip.dataset.onbRisk });
      _syncSelectionsFromState();
      return;
    }
    // Age band chip (single-select, optional).
    const ageChip = e.target.closest && e.target.closest('[data-onb-age]');
    if (ageChip && _ov()?.classList.contains('open')) {
      Eng.savePreferences({ ageBand: ageChip.dataset.onbAge });
      _syncSelectionsFromState();
      return;
    }

    // Generic next / back
    if (e.target.closest && e.target.closest('[data-onb-next]') && _ov()?.classList.contains('open')) {
      Eng.nextStep();
      return;
    }
    if (e.target.closest && e.target.closest('[data-onb-back]') && _ov()?.classList.contains('open')) {
      Eng.previousStep();
      return;
    }

    // ACTIVATION CTA — open the existing add-asset modal, leave the
    // onboarding modal visually hidden but the engine state intact.
    // The 'aurix:asset-added' listener re-opens onboarding at SUCCESS.
    if (e.target.closest && e.target.closest('#onbAddAssetBtn') && _ov()?.classList.contains('open')) {
      // ONBOARDING-1B §3: only the first attempt arms the auto-return
      // path. Subsequent reopens (e.g. user closed add-asset and pressed
      // the CTA again manually) do not re-arm — they remain a normal
      // open, so closing the add-asset modal leaves the user wherever
      // they choose without a forced loop.
      awaitingAsset = !_activationAddAttempted;
      _activationAddAttempted = true;
      _hideOnboardingOverlay();
      try {
        if (typeof openModal === 'function') openModal();
      } catch (err) {
        console.warn('[onboarding] failed to open add-asset modal:', err && err.message);
        awaitingAsset = false;
        _openOnboardingOverlay();
      }
      return;
    }

    // Skip
    if (e.target.closest && e.target.closest('#onbSkipBtn') && _ov()?.classList.contains('open')) {
      Eng.skipOnboarding();
      _hideOnboardingOverlay();
      return;
    }

    // ONBOARDING-2: SUCCESS step — "+ Añadir otro activo".
    // Multi-asset loop. Unlike the ACTIVATION CTA we don't gate this
    // with _activationAddAttempted because rapid successive adds are
    // the desired behaviour here. The asset-added listener above
    // re-mounts the overlay once the user submits or cancels.
    if (e.target.closest && e.target.closest('#onbAddAnotherBtn') && _ov()?.classList.contains('open')) {
      awaitingAsset = true;
      _hideOnboardingOverlay();
      try {
        if (typeof openModal === 'function') openModal();
      } catch (err) {
        console.warn('[onboarding] failed to open add-asset modal:', err && err.message);
        awaitingAsset = false;
        _openOnboardingOverlay();
      }
      return;
    }

    // ONBOARDING-2: SUCCESS step — "Ir al dashboard".
    // User opted out of the loop. completeOnboarding flips the engine
    // to COMPLETED; the state listener tears the overlay down.
    if (e.target.closest && e.target.closest('#onbGoDashboardBtn') && _ov()?.classList.contains('open')) {
      Eng.completeOnboarding();
      _hideOnboardingOverlay();
      return;
    }
  });

  // ── Engine → UI bridge ────────────────────────────────────────
  window.addEventListener('aurix:onboarding-state', e => {
    const snap = e && e.detail ? e.detail : Eng.getSnapshot();
    const modal = _modal();
    if (modal && snap.state && snap.state !== STATES.COMPLETED) {
      modal.setAttribute('data-step', snap.state);
    }
    _syncSelectionsFromState();

    // ONBOARDING-2: SUCCESS step waits for an explicit user choice.
    // We re-open the overlay (the add-asset modal closed it during
    // the handoff) and write the current count copy. The two CTAs
    // ("+ Add another" / "Go to dashboard") drive the next step —
    // no automatic timer here.
    if (snap.state === STATES.SUCCESS) {
      awaitingAsset = false;
      _updateSuccessCopy();
      if (!_ov()?.classList.contains('open')) _openOnboardingOverlay();
    }
    if (snap.state === STATES.COMPLETED) {
      _hideOnboardingOverlay();
      // ONBOARDING-WATCHLIST-2: plant the starter watchlist the moment
      // onboarding finishes — only fires if assets and watchlist are
      // both empty and a prior seed hasn't already run. The dashboard
      // tracking card subscribes to watchlistStore changes, so the new
      // symbols light up without a reload.
      try {
        if (typeof window.__aurixSeedStarterWatchlist === 'function') {
          window.__aurixSeedStarterWatchlist('onboarding-completed');
        }
      } catch (e) {
        console.warn('[onboarding] watchlist seed failed:', e && e.message);
      }
    }
  });

  // ONBOARDING-2: multi-asset loop. Engine transitions ACTIVATION →
  // SUCCESS on the first asset (handled by its own listener). For the
  // 2nd+ asset the engine stays on SUCCESS and emits no state event,
  // so we listen for asset-added directly and refresh the counter +
  // re-mount the overlay if the add-asset modal closed it.
  window.addEventListener('aurix:asset-added', () => {
    if (!window._aurixOnboardingInProgress) return;
    const snap = Eng.getSnapshot();
    if (snap.state !== STATES.SUCCESS) return;
    awaitingAsset = false;
    _updateSuccessCopy();
    if (!_ov()?.classList.contains('open')) _openOnboardingOverlay();
  });

  // ── Add-asset modal close handoff ─────────────────────────────
  // If the user opened the add-asset modal from the ACTIVATION step
  // and then closed it WITHOUT adding anything, restore the onboarding
  // overlay so they don't get stranded on the dashboard mid-flow.
  // ONBOARDING-1B §3: `awaitingAsset` is single-use — it's cleared
  // the moment we observe the add-asset modal close so a second close
  // (e.g. user reopened add-asset manually) never re-mounts onboarding.
  const _addAssetOv = document.getElementById('modalOverlay');
  if (_addAssetOv && typeof MutationObserver !== 'undefined') {
    const mo = new MutationObserver(() => {
      if (!awaitingAsset) return;
      const isOpen = _addAssetOv.classList.contains('open');
      if (isOpen) return;
      // Closed. Consume the awaiting flag FIRST so further mutations
      // can't re-enter this branch. The reopen target depends on which
      // step we're in — ONBOARDING-2 needs to also handle the SUCCESS
      // multi-asset loop where the user might cancel the modal.
      awaitingAsset = false;
      const snap = Eng.getSnapshot();
      if (snap.completed) return;
      if (snap.state === STATES.ACTIVATION || snap.state === STATES.SUCCESS) {
        _openOnboardingOverlay();
      }
    });
    mo.observe(_addAssetOv, { attributes: true, attributeFilter: ['class'] });
  }

  // ── Entry point — called from boot after auth + portfolio load ──
  async function maybeShowOnboarding() {
    try {
      // ONBOARDING-1B §6: existing-user guarantee runs BEFORE we even
      // hydrate — if the portfolio already has assets in localStorage,
      // mark onboarding complete and bail. We do not show the overlay
      // even for an instant. shouldShowOnboarding does the same check
      // later, but doing it here keeps the overlay element from ever
      // entering the DOM mount path for returning users.
      const earlyLen = (Array.isArray(window.assets) && window.assets.length) ||
        (function () {
          try {
            const raw = localStorage.getItem('aurix_assets');
            if (raw) { const arr = JSON.parse(raw); if (Array.isArray(arr)) return arr.length; }
          } catch (_) {}
          return 0;
        })();
      if (earlyLen > 0) {
        // Hydrate (so debug helper has truth) then mark complete silently.
        await Eng.hydrateOnboardingState();
        if (!Eng.getSnapshot().completed) Eng.completeOnboarding({ silent: true });
        return;
      }

      await Eng.hydrateOnboardingState();
      const user = (typeof currentUser !== 'undefined' && currentUser)
        ? { authenticated: true, id: currentUser.id }
        : null;
      if (!user) return;
      if (!Eng.shouldShowOnboarding(user, assets)) return;

      // ONBOARDING-1B §5: LANGUAGE is always the first onboarding
      // screen, even if the app already has a language set. We
      // preselect the current `lang` so a single Continue tap moves on.
      const snap = Eng.getSnapshot();
      const inFlight = snap.state && snap.state !== STATES.NOT_STARTED &&
                       snap.state !== STATES.COMPLETED;
      const currentAppLang = (typeof lang === 'string' && lang) ? lang : null;
      if (!snap.language && currentAppLang) {
        pendingLang = currentAppLang;
      } else if (snap.language) {
        pendingLang = snap.language;
      }

      if (inFlight) {
        window._aurixOnboardingInProgress = true;
        _openOnboardingOverlay();
      } else {
        Eng.startOnboarding();
        _openOnboardingOverlay();
      }
    } catch (err) {
      console.warn('[onboarding] maybe show failed:', err && err.message);
    }
  }

  window.maybeShowOnboarding = maybeShowOnboarding;
})();

// ── AURIX-SIGNALS-1 / -3: lightweight dashboard smart signals ──────
// Deterministic, local-only computation. No network, no observers, no
// AI dependency. Surfaces awareness — never financial advice. The
// dashboard rotates one signal at a time from the pool below; the
// Health panel consumes the primary (highest-priority) one.
function computeAurixSignalPool() {
  // AURIX-INVESTABLE-WEALTH-1 — signals/recommendations analyse INVESTABLE wealth
  // only. Shadowing `assets` with the investable subset (real estate excluded)
  // makes every composition rule below (concentration, single-asset, low-div,
  // liquidity, performance/loss) read investable wealth; the real-estate signal
  // (rePct, from getInvestableDistribution) reads 0 → stays inert. totalValueUSD/
  // getDistribution (total) are untouched globally.
  const assets = (typeof investableAssets === 'function') ? investableAssets() : [];
  if (!Array.isArray(assets) || assets.length === 0) return [];

  const totUSD = (typeof investableValueUSD === 'function') ? investableValueUSD() : 0;
  if (totUSD <= 0) return [];

  const pool = [];
  const seen = new Set();
  const push = (entry) => {
    if (seen.has(entry.kind)) return;
    seen.add(entry.kind);
    pool.push(entry);
  };

  // Single-asset top reference is also needed by several signal copies.
  let topAsset = null, topAssetUsd = 0;
  for (const a of assets) {
    const v = (typeof assetValueUSD === 'function') ? assetValueUSD(a) : 0;
    if (v > topAssetUsd) { topAssetUsd = v; topAsset = a; }
  }
  const topPct = (topAssetUsd / totUSD) * 100;
  // INVESTABLE distribution (real estate excluded) → category/crypto/cash signals
  // reflect the manageable portfolio; the rePct rule below reads 0 and stays inert.
  const dist = (typeof getInvestableDistribution === 'function') ? (getInvestableDistribution() || []) : [];
  const cryptoPct = (dist.find(d => d.type === 'crypto') || {}).pct || 0;
  const cashPct   = (dist.find(d => d.type === 'cash')   || {}).pct || 0;

  // SIGNAL-MOBILE-2: shorter ticker form for the dominant-asset signal
  // on phones. Tickers fall back to the first word of the name if the
  // entry has no ticker attribute.
  const shortDomName = (() => {
    if (!topAsset) return '';
    if (topAsset.ticker) return topAsset.ticker;
    const n = (topAsset.name || '').split(' ');
    return n[0] || '—';
  })();

  // REAL-ESTATE-INTEL: detect whether the dominant weight is real
  // estate so we can swap the alarmist "concentration" / "dominant"
  // copy for the calmer property-aware narrative. RE is illiquid,
  // long-term, low daily volatility — comparing its weight to a single
  // altcoin would mislead the user.
  const topIsRealEstate     = !!(topAsset && topAsset.type === 'real_estate');
  const topCatIsRealEstate  = !!(dist.length && dist[0].type === 'real_estate');
  // WORKSPACE-LIQUIDITY-LOGIC-1: cash/currency is not a volatile asset.
  // A 70% EUR weight should never trigger "EUR domina la cartera" — the
  // cashPct signal (rule 6 below) carries the meaningful interpretation
  // for high liquidity. RE was already excluded via topIsRealEstate.
  const topIsCash           = !!(topAsset && topAsset.type === 'cash');
  const topCatIsCash        = !!(dist.length && dist[0].type === 'cash');

  // 1) CONCENTRATION — top asset > 60% (and 2+ assets — single-asset
  //    portfolios get a more specific signal below).
  if (topPct > 60 && assets.length >= 2 && !topIsRealEstate && !topIsCash) {
    push({
      kind: 'concentration',
      msg: 'signalConcentrationBody',
      msgMobile: 'signalConcentrationBodyMobile',
      cta: 'signalConcentrationCta',
    });
    // 1b) Companion "X domina tu cartera." for rotation variety.
    if (topAsset) {
      const name = topAsset.name || topAsset.ticker || '—';
      const dominantFn       = t('signalDominantBody');
      const dominantMobileFn = t('signalDominantBodyMobile');
      push({
        kind: 'dominant',
        msgRaw:       (typeof dominantFn === 'function')       ? dominantFn(name)               : `${name} domina tu cartera.`,
        msgRawMobile: (typeof dominantMobileFn === 'function') ? dominantMobileFn(shortDomName) : `${shortDomName} domina`,
        cta:  'signalConcentrationCta',
      });
    }
  }

  // 2) CATEGORY CONCENTRATION — top category > 60%.
  //    WORKSPACE-LIQUIDITY-LOGIC-1: cash as a category is liquidity, not
  //    "category concentration"; the cashPct signal owns that narrative.
  if (dist.length && dist[0].pct > 60 && !topCatIsRealEstate && !topCatIsCash) {
    push({
      kind: 'category',
      msg: 'signalCategoryBody',
      msgMobile: 'signalCategoryBodyMobile',
      cta: 'signalCryptoCta',
    });
  }

  // 2b) REAL ESTATE — calm informative signal when property weight is
  //     high. We do NOT call this overexposure; we describe what's
  //     happening (low liquidity, long-term anchor) and let the user
  //     read on. Threshold matches the spec (≥ 70% triggers narrative).
  const rePct = Math.round((dist.find(d => d.type === 'real_estate') || {}).pct || 0);
  if (rePct >= 70) {
    push({
      kind: 'real_estate',
      msg: 'signalRealEstateBody',
      msgMobile: 'signalRealEstateBodyMobile',
      cta: 'signalRealEstateCta',
    });
  }

  // 3) CRYPTO EXPOSURE — > 50%. Soft variant when crypto is the
  //    *only* class (single-asset already covered); the pool surface
  //    swaps copy via `msgSoft` when only one entry remains.
  if (cryptoPct > 50) {
    push({
      kind: 'crypto',
      msg: 'signalCryptoBody', msgSoft: 'signalCryptoBodySoft',
      msgMobile: 'signalCryptoBodyMobile', msgMobileSoft: 'signalCryptoBodyMobileSoft',
      cta: 'signalCryptoCta',
    });
  }

  // 4) SINGLE ASSET — dependency on a single holding.
  if (assets.length === 1) {
    push({
      kind: 'single',
      msg: 'signalSingleBody',
      msgMobile: 'signalSingleBodyMobile',
      cta: 'signalSingleCta',
    });
  }

  // 5) LOW DIVERSIFICATION — 2–3 assets OR a single category.
  if ((assets.length >= 2 && assets.length <= 3) || (dist.length === 1 && assets.length >= 2)) {
    push({
      kind: 'lowdiv',
      msg: 'signalLowDivBody',
      msgMobile: 'signalLowDivBodyMobile',
      cta: 'signalSingleCta',
    });
  }

  // 6) LIQUIDITY — high cash OR no cash at all.
  if (cashPct > 40) {
    push({
      kind: 'cash',
      msg: 'signalCashBody',
      msgMobile: 'signalCashBodyMobile',
      cta: 'signalCashCta',
    });
  } else if (cashPct === 0 && assets.length >= 2) {
    push({
      kind: 'nocash',
      msg: 'signalNoCashBody',
      msgMobile: 'signalNoCashBodyMobile',
      cta: 'signalCashCta',
    });
  }

  // 7) PERFORMANCE — strongest 24h change > +15%.
  let maxChange = -Infinity;
  for (const a of assets) {
    if (typeof a.change24h === 'number' && a.change24h > maxChange) {
      maxChange = a.change24h;
    }
  }
  if (Number.isFinite(maxChange) && maxChange > 15) {
    push({
      kind: 'performance',
      msg: 'signalPerformanceBody',
      msgMobile: 'signalPerformanceBodyMobile',
      cta: 'signalPerformanceCta',
    });
  }

  // 8) LOSS PRESSURE — weakest 24h change < -12%.
  let minChange = Infinity;
  for (const a of assets) {
    if (typeof a.change24h === 'number' && a.change24h < minChange) {
      minChange = a.change24h;
    }
  }
  if (Number.isFinite(minChange) && minChange < -12) {
    push({
      kind: 'loss',
      msg: 'signalLossBody',
      msgMobile: 'signalLossBodyMobile',
      cta: 'signalLossCta',
    });
  }

  // SIGNAL-HOTFIX: with assets present and a positive total, the bar
  // must never disappear. If none of the rules above fired, surface a
  // generic intelligence entry so the module stays mounted and the
  // user can still open the Health panel.
  if (!pool.length) {
    push({
      kind: 'insights',
      msg: 'signalInsightsBody',
      msgMobile: 'signalInsightsBodyMobile',
      cta: 'signalInsightsCta',
    });
  }

  return pool.slice(0, 5);
}

// Backwards-compatible single-signal helper. Returns the highest-
// priority entry, or null.
function computeAurixSignal() {
  const pool = computeAurixSignalPool();
  return pool[0] || null;
}

// AURIX-SIGNALS-2 / HEALTH-2: build a lightweight snapshot of the
// portfolio that feeds the Health panel. Pure computation against the
// existing `assets` array + getDistribution()/totalValueUSD(); no
// risk-engine duplication, no extra observers. All percentages are
// rounded to integer for premium glanceability.
function _aurixHealthSnapshot() {
  const out = {
    totUSD:        0,
    topAsset:      null,    // { name, ticker, type, pctTotal }
    // WORKSPACE-LIQUIDITY-LOGIC-1: largest NON-LIQUIDITY holding. Cash /
    // currency entries are not the same shape of risk as crypto, equity
    // or commodities — they don't oscillate, so they should not drive
    // "X domina la cartera" copy. Workspace concentration narratives
    // read from this field; the original topAsset stays unchanged for
    // any caller that genuinely needs the absolute largest holding.
    topInvestedAsset: null, // { name, ticker, type, pctTotal }
    topCategory:   null,    // { type, label, pctTotal }
    categoryCount: 0,
    assetCount:    0,
    cashPct:       0,
    cryptoPct:     0,
    // REAL-ESTATE-INTEL: track property weight separately so the
    // intelligence layer can interpret concentration calmly when the
    // dominant asset is a primary residence or investment property
    // — long-term, illiquid, not marked-to-market daily.
    realEstatePct: 0,
    // Liquid net worth view — total net worth excluding real estate.
    // A user with a 200K property + 10K stocks has "total wealth" 210K
    // but "investable / liquid portfolio" of just 10K. Surfacing both
    // is key for serious investors.
    liquidUSD:     0,
    liquidPct:     0,    // % of total that is liquid (non-RE)
    worstAsset:    null,    // { name, ticker, change24h }
    bestAsset:     null,    // { name, ticker, change24h }
  };
  // AURIX-INVESTABLE-WEALTH-1 — Workspace intelligence analyses INVESTABLE wealth
  // only (real estate lives in its own card/category). Shadowing `assets` with the
  // investable subset makes EVERY loop, count and guard below operate on investable
  // wealth, so liquidity/concentration/diversification/exposure are never distorted
  // by a dominant property. EXCEPTION (WE.1): the realEstatePct / liquidUSD / liquidPct
  // block below intentionally steps OUTSIDE this investable shadow — it reads real
  // estate from the full active set and divides by TOTAL wealth, because property
  // weight is only meaningful against total patrimony, not the investable subset.
  // totalValueUSD/getDistribution (total) are untouched globally; here we read the
  // investable equivalents for everything except that RE block.
  const assets = (typeof investableAssets === 'function') ? investableAssets() : [];
  if (!Array.isArray(assets) || assets.length === 0) return out;
  const totUSD = (typeof investableValueUSD === 'function') ? investableValueUSD() : 0;
  out.totUSD     = totUSD;
  out.assetCount = assets.length;
  if (totUSD <= 0) return out;

  // REAL-ESTATE-INTEL: property weight + liquid net worth, measured against
  // TOTAL wealth (RE + investable) — the insight reads "inmuebles representan
  // el X% de tu patrimonio".
  // WE.1 (parity-safe fix): `assets`/`totUSD` above are the INVESTABLE shadow
  // (real estate excluded), so the previous `for (a of assets)` loop could
  // never see a real_estate asset → reUSD was always 0 → realEstatePct stuck
  // at 0 and the RE-aware intelligence branch (realEstatePct >= 70) never
  // fired. Read real estate from the full active set and divide by TOTAL wealth
  // so the % is real. Note total = investable + real_estate (isInvestableAsset
  // excludes only real_estate), so liquidUSD collapses back to the investable
  // total — internally consistent. No displayed Dashboard figure changes; this
  // only un-sticks a 0 the intelligence layer was designed to consume.
  let reUSD = 0;
  const _allActiveAssets = (typeof activeAssets === 'function') ? activeAssets() : [];
  for (const a of _allActiveAssets) {
    if (!a || a.type !== 'real_estate') continue;
    const v = (typeof assetValueUSD === 'function') ? assetValueUSD(a) : 0;
    if (Number.isFinite(v) && v > 0) reUSD += v;
  }
  const _totalWealthUSD = (typeof totalValueUSD === 'function') ? totalValueUSD() : (totUSD + reUSD);
  out.realEstatePct = _totalWealthUSD > 0 ? Math.round((reUSD / _totalWealthUSD) * 100) : 0;
  out.liquidUSD     = Math.max(0, _totalWealthUSD - reUSD);
  out.liquidPct     = _totalWealthUSD > 0 ? Math.round((out.liquidUSD / _totalWealthUSD) * 100) : 0;

  // Top single asset (by value) + best/worst 24h change pass.
  let topUsd = -1;
  let topRef = null;
  // WORKSPACE-LIQUIDITY-LOGIC-1: parallel pass for the largest non-cash
  // holding. Cheaper than a second loop and keeps the snapshot pure.
  let topInvUsd = -1;
  let topInvRef = null;
  let bestRef = null, bestCh = -Infinity;
  let worstRef = null, worstCh = Infinity;
  for (const a of assets) {
    const v = (typeof assetValueUSD === 'function') ? assetValueUSD(a) : 0;
    if (v > topUsd) { topUsd = v; topRef = a; }
    if (a && a.type !== 'cash' && v > topInvUsd) {
      topInvUsd = v; topInvRef = a;
    }
    if (typeof a.change24h === 'number') {
      if (a.change24h > bestCh)  { bestCh  = a.change24h; bestRef  = a; }
      if (a.change24h < worstCh) { worstCh = a.change24h; worstRef = a; }
    }
  }
  if (topRef) {
    out.topAsset = {
      name:     topRef.name || topRef.ticker || '—',
      ticker:   topRef.ticker || '',
      type:     topRef.type,
      pctTotal: Math.round((topUsd / totUSD) * 100),
    };
  }
  if (topInvRef) {
    out.topInvestedAsset = {
      name:     topInvRef.name || topInvRef.ticker || '—',
      ticker:   topInvRef.ticker || '',
      type:     topInvRef.type,
      pctTotal: Math.round((topInvUsd / totUSD) * 100),
    };
  }
  if (bestRef && Number.isFinite(bestCh)) {
    out.bestAsset = { name: bestRef.name || bestRef.ticker, ticker: bestRef.ticker || '', change24h: bestCh };
  }
  if (worstRef && Number.isFinite(worstCh)) {
    out.worstAsset = { name: worstRef.name || worstRef.ticker, ticker: worstRef.ticker || '', change24h: worstCh };
  }
  // Top category + crypto/cash percentages — INVESTABLE distribution (real
  // estate excluded), so exposure/diversification reflect the manageable portfolio.
  const dist = (typeof getInvestableDistribution === 'function') ? (getInvestableDistribution() || []) : [];
  out.categoryCount = dist.length;
  if (dist.length) {
    const head = dist[0];
    const meta = (typeof TYPE_META !== 'undefined' && TYPE_META[head.type]) || null;
    out.topCategory = {
      type:     head.type,
      label:    meta ? meta.label : head.type,
      pctTotal: Math.round(head.pct),
    };
  }
  const cryptoEntry = dist.find(d => d.type === 'crypto');
  const cashEntry   = dist.find(d => d.type === 'cash');
  if (cryptoEntry) out.cryptoPct = Math.round(cryptoEntry.pct);
  if (cashEntry)   out.cashPct   = Math.round(cashEntry.pct);
  return out;
}

// HEALTH-2: deterministic health score. Starts at 100, applies the
// fixed deductions from the spec, clamps to [0, 100]. Returns the
// numeric score, a human-readable label and a `tone` token that maps
// to the ring + tag colour palette in CSS.
function _aurixHealthScore(snap) {
  if (!snap || snap.assetCount === 0 || snap.totUSD <= 0) {
    return { score: null, label: t('healthScoreEmpty') || '—', tone: 'solid', explain: '' };
  }
  // REAL-ESTATE-INTEL: real estate is illiquid, long-term, low daily
  // volatility — treating a single property the same as a single
  // altcoin for the "dominant asset" deduction would over-penalize
  // perfectly normal household structures (e.g. primary residence
  // + a small investment portfolio). When the dominant asset OR
  // category is real estate, we apply a softer deduction instead.
  // WORKSPACE-LIQUIDITY-LOGIC-1: read the deduction against the largest
  // INVESTED holding, not the absolute largest. A 65% EUR cash position
  // is not the same risk shape as a 65% single altcoin; cash already
  // has its own dedicated cashPct deductions below. No fallback to
  // topAsset on purpose — if topInvestedAsset is null, the portfolio
  // is fully liquid and the concentration deduction must not fire.
  const dominantAsset = snap.topInvestedAsset || null;
  const topIsRE = !!(dominantAsset && dominantAsset.type === 'real_estate');
  const catIsRE = !!(snap.topCategory && snap.topCategory.type === 'real_estate');
  let s = 100;
  if (dominantAsset && dominantAsset.pctTotal > 60)       s -= topIsRE ? 8  : 25;
  if (snap.topCategory && snap.topCategory.pctTotal > 60) s -= catIsRE ? 6  : 20;
  if (snap.cryptoPct > 50)                                s -= 15;
  if (snap.assetCount === 1)                              s -= 25;
  if (snap.cashPct > 60)                                  s -= 10;
  if (snap.cashPct === 0)                                 s -= 5;
  if (snap.worstAsset && snap.worstAsset.change24h < -15) s -= 10;
  s = Math.max(0, Math.min(100, s));
  let label, tone, explain;
  if (s >= 80)      { label = t('healthScoreSolid');    tone = 'solid';    explain = t('healthScoreExplainSolid'); }
  else if (s >= 60) { label = t('healthScoreModerate'); tone = 'moderate'; explain = t('healthScoreExplainModerate'); }
  else if (s >= 40) { label = t('healthScoreElevated'); tone = 'elevated'; explain = t('healthScoreExplainElevated'); }
  else              { label = t('healthScoreHigh');     tone = 'high';     explain = t('healthScoreExplainHigh'); }
  return { score: s, label, tone, explain: explain || '' };
}

// WORKSPACE-INTELLIGENCE-3 — the WHY engine.
//
// Workspace is NOT a snapshot. It is interpretation. Every fact this
// engine surfaces is paired with the reason it matters, so the user
// reads "Bitcoin representa el 40% de tu cartera. Eso hace que una
// parte importante de tu rendimiento dependa de un solo activo."
// instead of the truncated "BTC domina".
//
// Output shape — reusable across surfaces:
//   {
//     mode: 'zero' | 'one' | 'normal',
//     status: {
//       health:          { value, state, sub, tone },
//       risk:            { value, state, sub, tone },
//       diversification: { value, state, sub, tone },
//       liquidity:       { value, state, sub, tone },
//     },
//     hero: { title, summary, explanation, optionalHint, severity, kind },
//     dimensions: [ { id, label, state, why, tone } ],   // 4 cards
//     signals:    [ { kind, category, title, explanation, severity } ],
//   }
//
// No new portfolio math — this is a pure interpretation layer over
// _aurixHealthSnapshot + getDerivedFinancialSnapshot, the same data
// the dashboard signal pool consumes.
function _aurixWorkspaceIntelligence() {
  const snap   = (typeof _aurixHealthSnapshot === 'function') ? _aurixHealthSnapshot() : null;
  const score  = (typeof _aurixHealthScore    === 'function') ? _aurixHealthScore(snap) : { score: null, tone: 'neutral' };
  const assetCount = snap ? Number(snap.assetCount || 0) : 0;
  const totUSD     = snap ? Number(snap.totUSD || 0)     : 0;
  const _ti = (key, ...args) => {
    const v = (typeof t === 'function') ? t(key) : null;
    return (typeof v === 'function') ? v(...args) : (typeof v === 'string' ? v : '');
  };

  if (!assetCount || totUSD <= 0) {
    return {
      mode: 'zero',
      status: null,
      hero: {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_empty_title'),
        summary:      '',
        explanation:  _ti('ws_intel_empty_explanation'),
        optionalHint: '',
        severity:     'neutral',
        kind:         'empty',
      },
      dimensions: [],
      signals:    [],
    };
  }

  // Distribution + percentages. Reuse the live in-memory math.
  const cryptoPct  = Number(snap.cryptoPct || 0);
  const cashPct    = Number(snap.cashPct   || 0);
  const catCount   = Number(snap.categoryCount || 0);
  const topAsset   = snap.topAsset || null;
  const topCat     = snap.topCategory || null;
  const topAssetPct = topAsset ? Number(topAsset.pctTotal || 0) : 0;
  const topAssetName = topAsset
    ? (topAsset.name || String(topAsset.ticker || '').toUpperCase() || '—')
    : '';

  // WORKSPACE-LIQUIDITY-LOGIC-1: the *invested* top holding drives
  // concentration narrative (hero / dimension card / deep signal).
  // Cash/currency is interpreted separately as flexibility, not as
  // dominance, so a 36% EUR position never reads "Euros domina".
  // Falls back to the absolute top when the user holds no invested
  // assets — in that case the single-asset / liquidity heroes own the
  // narrative anyway.
  const topInvested     = snap.topInvestedAsset || null;
  const topInvestedPct  = topInvested ? Number(topInvested.pctTotal || 0) : 0;
  const topInvestedName = topInvested
    ? (topInvested.name || String(topInvested.ticker || '').toUpperCase() || '—')
    : '';
  const topIsCash       = !!(topAsset && topAsset.type === 'cash');

  // REAL-ESTATE-INTEL: surface property weight + liquid net worth up
  // front so every downstream heuristic (risk band, dimensions, deep
  // signals, hero) interprets concentration calmly when it comes from
  // a primary residence or investment property.
  const realEstatePct = Number(snap.realEstatePct || 0);
  const liquidPct     = Number(snap.liquidPct     || 0);
  const liquidUSD     = Number(snap.liquidUSD     || 0);
  // WORKSPACE-LIQUIDITY-LOGIC-1: RE check now reads from the invested
  // top so a cash entry never masks real-estate dominance.
  const topIsRE       = !!(topInvested && topInvested.type === 'real_estate');
  const topCatIsRE    = !!(topCat      && topCat.type      === 'real_estate');
  const liquidLabel   = (typeof formatBase === 'function' && Number.isFinite(liquidUSD))
    ? formatBase(liquidUSD)
    : `$${Math.round(liquidUSD).toLocaleString()}`;

  // Risk band — same heuristic the existing cockpit uses, kept
  // deterministic so terminal + cockpit never disagree.
  // REAL-ESTATE-INTEL: a top asset that happens to be a primary
  // residence shouldn't push the risk band into "elevated". Property
  // concentration adds modestly (illiquidity matters), but not as much
  // as a single dominant equity or crypto position.
  // WORKSPACE-LIQUIDITY-LOGIC-1: risk reads against the invested
  // subset so cash weight never inflates the risk band.
  let riskScore = 25;
  if (topInvestedPct > 50)       riskScore += topIsRE ? 8 : 25;
  else if (topInvestedPct > 35)  riskScore += topIsRE ? 4 : 12;
  if (cryptoPct > 40)         riskScore += 25;
  else if (cryptoPct > 15)    riskScore += 10;
  if (assetCount > 0 && assetCount < 4) riskScore += 10;
  riskScore = Math.min(100, Math.max(0, Math.round(riskScore)));
  // WORKSPACE-COHERENCE-1 — risk WORDING adapts to the user's investor
  // profile. The numeric riskScore is unchanged (same machine truth);
  // only the human framing flexes:
  //   • conservative → "superior a tu perfil objetivo"
  //   • aggressive   → "coherente con un perfil dinámico"
  //   • professional / balanced → neutral base copy
  // Profile reads from the existing _aurixInvestorProfile helper. Calm
  // band stays universal — nothing to nuance when risk is low.
  const profile = (typeof _aurixInvestorProfile === 'function')
    ? _aurixInvestorProfile()
    : { riskProfile: 'balanced', experience: 'intermediate' };
  const _resolveProfileKey = (baseKey) => {
    const rp = profile && profile.riskProfile;
    if (rp !== 'conservative' && rp !== 'aggressive') return baseKey;
    const tonedKey = `${baseKey}_${rp}`;
    if (typeof t === 'function') {
      const v = t(tonedKey);
      if ((typeof v === 'string' && v && v !== tonedKey) ||
           typeof v === 'function') return tonedKey;
    }
    return baseKey;
  };
  const riskState =
    riskScore >= 60 ? _ti(_resolveProfileKey('ws_intel_risk_elevated')) :
    riskScore >= 35 ? _ti(_resolveProfileKey('ws_intel_risk_mid'))      :
                      _ti('ws_intel_risk_calm');
  const riskTone =
    riskScore >= 60 ? 'warn' :
    riskScore >= 35 ? 'info' :
                      'positive';
  const riskSub =
    riskScore >= 60 ? _ti(_resolveProfileKey('ws_intel_risk_elevated_sub')) :
    riskScore >= 35 ? _ti(_resolveProfileKey('ws_intel_risk_mid_sub'))      :
                      _ti('ws_intel_risk_calm_sub');

  // Diversification.
  let divState, divTone, divSub;
  if (assetCount <= 2 || catCount <= 1) {
    divState = _ti('ws_intel_div_low');
    divTone  = 'warn';
    divSub   = _ti('ws_intel_div_low_sub', assetCount, catCount);
  } else if (assetCount <= 5 || catCount <= 2) {
    divState = _ti('ws_intel_div_mid');
    divTone  = 'info';
    divSub   = _ti('ws_intel_div_mid_sub', assetCount, catCount);
  } else {
    divState = _ti('ws_intel_div_high');
    divTone  = 'positive';
    divSub   = _ti('ws_intel_div_high_sub', assetCount, catCount);
  }

  // Liquidity. Note the spec tone: never alarmist. "Sin margen
  // inmediato" beats "Sin liquidez".
  let liqState, liqTone, liqSub;
  if (cashPct === 0) {
    liqState = _ti('ws_intel_liq_none');
    liqTone  = 'warn';
    liqSub   = _ti('ws_intel_liq_none_sub');
  } else if (cashPct < 5) {
    liqState = _ti('ws_intel_liq_thin');
    liqTone  = 'info';
    liqSub   = _ti('ws_intel_liq_thin_sub', cashPct);
  } else if (cashPct > 60) {
    liqState = _ti('ws_intel_liq_high');
    liqTone  = 'info';
    liqSub   = _ti('ws_intel_liq_high_sub', cashPct);
  } else {
    liqState = _ti('ws_intel_liq_ok');
    liqTone  = 'positive';
    liqSub   = _ti('ws_intel_liq_ok_sub', cashPct);
  }

  // STATUS STRIP — four cards. Health reuses the score helper so
  // workspace + portfolio-health never disagree.
  const status = {
    health: {
      value: (score && score.score != null) ? String(score.score) : '—',
      state: (score && score.label) || '',
      sub:   (score && score.label) || '',
      tone:  score && score.tone ? score.tone : 'neutral',
    },
    risk: {
      value: riskState,
      state: riskState,
      sub:   riskSub,
      tone:  riskTone,
    },
    diversification: {
      value: divState,
      state: divState,
      sub:   divSub,
      tone:  divTone,
    },
    liquidity: {
      value: `${cashPct}%`,
      state: liqState,
      sub:   liqSub,
      tone:  liqTone,
    },
  };

  // DIMENSIONS — full prose state for the grid below the hero.
  const dimensions = [
    {
      id:    'diversification',
      label: _ti('ws_intel_dim_diversification'),
      state: divState,
      why:   _ti('ws_intel_dim_diversification_why', assetCount, catCount),
      tone:  divTone,
    },
    {
      id:    'liquidity',
      label: _ti('ws_intel_dim_liquidity'),
      state: liqState,
      why:   cashPct === 0
              ? _ti('ws_intel_dim_liquidity_why_none')
              : _ti('ws_intel_dim_liquidity_why_pct', cashPct),
      tone:  liqTone,
    },
    {
      id:    'concentration',
      label: _ti('ws_intel_dim_concentration'),
      // WORKSPACE-LIQUIDITY-LOGIC-1: concentration state, copy and tone
      // are all read against the invested subset. Cash weight does not
      // count as concentration — it's interpreted separately as
      // liquidity / flexibility above.
      state: topInvestedPct > 60 ? _ti('ws_intel_conc_high')
            : topInvestedPct > 35 ? _ti('ws_intel_conc_mod')
                                  : _ti('ws_intel_conc_low'),
      why:   topInvested
              ? _ti('ws_intel_dim_concentration_why', topInvestedName, topInvestedPct)
              : _ti('ws_intel_dim_concentration_why_none'),
      // REAL-ESTATE-INTEL: never paint property concentration as warn —
      // a primary residence anchoring a household balance sheet is not
      // the same risk shape as a single altcoin.
      tone:  topIsRE ? (topInvestedPct > 60 ? 'info' : 'positive')
            : topInvestedPct > 60 ? 'warn'
            : topInvestedPct > 35 ? 'info'
                                  : 'positive',
    },
    // BLOQUE-0.3 — the 'performance' dimension was a permanent hardcoded
    // placeholder ("Historial en construcción") shown to every user regardless
    // of real history/PnL. Hidden until a real, flow-aware performance reading
    // is built (Bloque 2.1). i18n keys (ws_intel_dim_performance / _perf_initial
    // / _why_initial) are kept for that work. Render maps over this array, so
    // omitting the card simply yields 3 honest dimensions.
  ];

  // HERO INSIGHT — pick the single most consequential interpretation.
  // Priority: single asset → real-estate dominance → liquidity relevant
  // → high concentration → high crypto → liquidity gap → moderate
  // concentration → resilient default.
  // WORKSPACE-LIQUIDITY-LOGIC-1: a single-asset portfolio where the
  // only asset is cash is not "dependent on one risky position" — it's
  // a fully-liquid balance sheet. The dedicated liquidity hero below
  // owns that case.
  const hero = (() => {
    if (assetCount === 1 && topAsset && !topIsCash) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_single_title'),
        summary:      _ti('ws_intel_hero_single_summary', topAssetName),
        explanation:  _ti('ws_intel_hero_single_explanation'),
        optionalHint: _ti('ws_intel_hero_single_hint'),
        severity:     'warn',
        kind:         'single',
      };
    }
    // REAL-ESTATE-INTEL: when real estate dominates we never say
    // "overexposed". We describe stability + reduced liquidity, and
    // surface the liquid portfolio number so the user reads a complete
    // picture instead of a misleading single percentage.
    if (realEstatePct >= 70 || (topIsRE && topInvestedPct > 60) || (topCatIsRE && Number(topCat.pctTotal || 0) > 60)) {
      const reShown = realEstatePct || (topCatIsRE ? Number(topCat.pctTotal || 0) : topInvestedPct);
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_re_title'),
        summary:      _ti('ws_intel_hero_re_summary', reShown),
        explanation:  _ti('ws_intel_hero_re_explanation'),
        optionalHint: _ti('ws_intel_hero_re_liquid_hint', liquidPct, liquidLabel)
                      || _ti('ws_intel_hero_re_hint'),
        severity:     'info',
        kind:         'real_estate',
      };
    }
    // WORKSPACE-LIQUIDITY-LOGIC-1: when cash/currency is the largest
    // single holding, we never call it concentration or dominance. The
    // hero describes what that liquidity ENABLES (flexibility for new
    // decisions, less forced selling). 25% floor avoids surfacing this
    // when cash happens to win by a single percentage point.
    if (topIsCash && cashPct >= 25) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_liq_rel_title'),
        summary:      _ti('ws_intel_hero_liq_rel_summary', cashPct),
        explanation:  _ti('ws_intel_hero_liq_rel_explanation'),
        optionalHint: _ti('ws_intel_hero_liq_rel_hint'),
        severity:     'positive',
        kind:         'liquidity_relevant',
      };
    }
    if (topInvestedPct > 60 && topInvested) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_conc_title', topInvestedName),
        summary:      _ti('ws_intel_hero_conc_summary', topInvestedName, topInvestedPct),
        explanation:  _ti('ws_intel_hero_conc_explanation'),
        optionalHint: _ti('ws_intel_hero_conc_hint'),
        severity:     'warn',
        kind:         'concentration',
      };
    }
    if (cryptoPct > 50) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_crypto_title'),
        summary:      _ti('ws_intel_hero_crypto_summary', cryptoPct),
        explanation:  _ti('ws_intel_hero_crypto_explanation'),
        optionalHint: _ti('ws_intel_hero_crypto_hint'),
        severity:     'info',
        kind:         'crypto',
      };
    }
    if (cashPct === 0) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_liq_title'),
        summary:      _ti('ws_intel_hero_liq_summary'),
        explanation:  _ti('ws_intel_hero_liq_explanation'),
        optionalHint: _ti('ws_intel_hero_liq_hint'),
        severity:     'moderate',
        kind:         'liquidity',
      };
    }
    if (topInvestedPct > 35 && topInvested) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_conc_mod_title', topInvestedName),
        summary:      _ti('ws_intel_hero_conc_mod_summary', topInvestedName, topInvestedPct),
        explanation:  _ti('ws_intel_hero_conc_explanation'),
        // WORKSPACE-COHERENCE-1: hint now closes with a forward look so
        // the moderate-concentration hero answers "qué mirar después".
        optionalHint: _ti('ws_intel_hero_conc_mod_hint'),
        severity:     'info',
        kind:         'concentration',
      };
    }
    // WORKSPACE-COHERENCE-1 — early-history hero. Fires when nothing
    // structural triggered: the portfolio is just too young / small for
    // a meaningful concentration / liquidity / RE / crypto narrative.
    // We say so explicitly instead of defaulting to "Estructura
    // equilibrada", which can read as a confident claim about a 2-asset
    // wallet with two days of history.
    if (assetCount <= 3) {
      return {
        eyebrow:      _ti('ws_intel_hero_eyebrow'),
        title:        _ti('ws_intel_hero_history_title'),
        summary:      _ti('ws_intel_hero_history_summary'),
        explanation:  _ti('ws_intel_hero_history_explanation'),
        optionalHint: _ti('ws_intel_hero_history_hint'),
        severity:     'neutral',
        kind:         'early_history',
      };
    }
    return {
      eyebrow:      _ti('ws_intel_hero_eyebrow'),
      title:        _ti('ws_intel_hero_resilient_title'),
      summary:      _ti('ws_intel_hero_resilient_summary'),
      explanation:  _ti('ws_intel_hero_resilient_explanation'),
      // WORKSPACE-COHERENCE-1: forward-looking hint for the balanced
      // state, completes the "qué mirar después" beat.
      optionalHint: _ti('ws_intel_hero_resilient_hint'),
      severity:     'positive',
      kind:         'resilient',
    };
  })();

  // DEEP SIGNALS — institutional intelligence rows, category + claim +
  // one explanation sentence. Always ordered concentration → diversif
  // → liquidity → performance so the reader builds a mental model in
  // the same direction every time.
  const signals = [
    {
      kind:        'concentration',
      category:    _ti('ws_intel_signal_concentration'),
      // WORKSPACE-LIQUIDITY-LOGIC-1: read against the invested subset.
      // When the user holds meaningful cash we explicitly frame the
      // concentration narrative as "among invested assets…" so fiat is
      // never described as dominating the portfolio.
      title:       topInvested
                    ? (topIsCash
                        ? _ti('ws_intel_signal_concentration_title_invested', topInvestedName)
                        : _ti('ws_intel_signal_concentration_title',          topInvestedName))
                    : _ti('ws_intel_signal_concentration_title_none'),
      explanation: topInvested
                    ? (topIsCash
                        ? _ti('ws_intel_signal_concentration_explanation_invested', topInvestedName, topInvestedPct)
                        : _ti('ws_intel_signal_concentration_explanation',          topInvestedName, topInvestedPct))
                    : _ti('ws_intel_signal_concentration_explanation_none'),
      // REAL-ESTATE-INTEL: downgrade severity when property dominates.
      severity:    topIsRE ? (topInvestedPct > 60 ? 'info' : 'positive')
                  : topInvestedPct > 60 ? 'warn'
                  : topInvestedPct > 35 ? 'info'
                                        : 'positive',
    },
    {
      kind:        'diversification',
      category:    _ti('ws_intel_signal_diversification'),
      title:       divTone === 'positive'
                    ? _ti('ws_intel_signal_diversification_title_strong')
                    : divTone === 'info'
                      ? _ti('ws_intel_signal_diversification_title_mid')
                      : _ti('ws_intel_signal_diversification_title_low'),
      explanation: _ti('ws_intel_signal_diversification_explanation', assetCount, catCount),
      severity:    divTone === 'positive' ? 'positive' : divTone === 'info' ? 'info' : 'warn',
    },
    {
      kind:        'liquidity',
      category:    _ti('ws_intel_signal_liquidity'),
      title:       cashPct === 0
                    ? _ti('ws_intel_signal_liquidity_title_none')
                    : _ti('ws_intel_signal_liquidity_title_pct', cashPct),
      explanation: cashPct === 0
                    ? _ti('ws_intel_signal_liquidity_explanation_none')
                    : _ti('ws_intel_signal_liquidity_explanation_pct', cashPct),
      severity:    liqTone === 'positive' ? 'positive' : liqTone === 'info' ? 'info' : 'warn',
    },
    // BLOQUE-0.3 — performance signal hidden alongside its dimension (placeholder
    // only). Restored when real performance lands (Bloque 2.1). i18n keys kept.
  ];

  // WORKSPACE-COHERENCE-1 — de-duplicate signals against the hero.
  // The hero is the loudest narrative on the surface; an "explained
  // signal" that simply restates it makes the page read like four
  // disconnected cards saying the same thing four ways. Each hero kind
  // maps to the deep-signal row that would repeat it; we filter that
  // row out so the section becomes "the rest of the story, calmly".
  // Hero kinds with no obvious overlap (empty / null) keep the full
  // four rows.
  const HERO_TO_MUTED_SIGNAL = {
    single:             'concentration',
    real_estate:        'concentration',
    liquidity_relevant: 'liquidity',
    concentration:      'concentration',
    crypto:             'concentration',
    liquidity:          'liquidity',
    resilient:          'diversification',
    early_history:      'performance',
  };
  const mutedKind  = hero && hero.kind ? HERO_TO_MUTED_SIGNAL[hero.kind] : null;
  const visibleSignals = mutedKind
    ? signals.filter(s => s.kind !== mutedKind)
    : signals;

  return {
    mode: assetCount === 1 ? 'one' : 'normal',
    status,
    hero,
    dimensions,
    signals: visibleSignals,
  };
}

// HEALTH-3: developer-facing diagnostics for the Portfolio Health
// surface. Surfaces the live source the snapshot reads from, the
// resulting counts, the rotated signal pool and any stale future-
// proof cache keys present in localStorage (none of which the
// engine reads — they're cleared by reset to keep things tidy).
// DEBUG-HARDEN-1: gated to dev hosts only.
if (_aurixIsDebugHost()) window.__aurixHealthDebug = function () {
  const snap   = _aurixHealthSnapshot();
  const score  = _aurixHealthScore(snap);
  const symbols = Array.isArray(assets)
    ? assets.map(a => a.ticker || a.name || '?').slice(0, 25)
    : [];
  const dist = (typeof getDistribution === 'function') ? (getDistribution() || []) : [];
  const categoryCounts = {};
  dist.forEach(d => { categoryCounts[d.type] = Math.round(d.pct); });
  const checkKeys = [
    'aurix_health_snapshot', 'aurix_signal_state', 'aurix_workspace_snapshot',
    'aurix_risk_snapshot',   'aurix_portfolio_summary',
  ];
  const staleKeysFound = [];
  for (const k of checkKeys) {
    try { if (localStorage.getItem(k)) staleKeysFound.push(k); } catch (_) {}
  }
  return {
    source:         'live: assets[] + totalValueUSD() + getDistribution()',
    assetCount:     snap.assetCount,
    assetSymbols:   symbols,
    categoryCounts,
    cashPct:        snap.cashPct,
    cryptoPct:      snap.cryptoPct,
    topAsset:       snap.topAsset,
    topCategory:    snap.topCategory,
    score:          score.score,
    scoreLabel:     score.label,
    scoreTone:      score.tone,
    signalPool:     computeAurixSignalPool().map(s => s.kind),
    lastComputedAt: new Date().toISOString(),
    staleKeysFound,
  };
};

// HEALTH-2: produce up to N diagnostic cards from a snapshot. Each
// card has { title, body, tone }. Order is priority — most signal-
// relevant first — and the renderer caps at 5.
function _aurixHealthCards(snap, max) {
  const cap = Math.max(1, Math.min(5, max || 5));
  const cards = [];

  // Concentration (top asset)
  if (snap.topAsset) {
    const pct = snap.topAsset.pctTotal;
    if (pct >= 40) {
      cards.push({
        title: t('healthCardConcentrationTitle'),
        body:  (t('healthCardConcentrationBody'))(snap.topAsset.name, pct),
        tone:  pct > 60 ? 'warn' : 'info',
      });
    }
  }

  // Category dominance — special-cased for crypto: when the entire
  // portfolio (or near-entire) is crypto, surface the dedicated
  // "Cripto" card per spec rather than the generic category copy.
  if (snap.topCategory) {
    const pct = snap.topCategory.pctTotal;
    if (snap.topCategory.type === 'crypto' && pct >= 80) {
      cards.push({
        title: t('healthCardCryptoConcTitle'),
        body:  t('healthCardCryptoConcBody'),
        tone:  pct > 90 ? 'warn' : 'info',
      });
    } else if (pct >= 50) {
      cards.push({
        title: t('healthCardCategoryTitle'),
        body:  (t('healthCardCategoryBody'))(snap.topCategory.label, pct),
        tone:  pct > 75 ? 'warn' : 'info',
      });
    }
  }

  // Diversification — always shown (single + multi). Uses the same
  // pluralised body so the user always sees their N assets / C
  // categories.
  cards.push({
    title: t('healthCardDiversificationTitle'),
    body:  (t('healthCardDiversificationBody'))(snap.assetCount, snap.categoryCount),
    tone:  (snap.assetCount === 1) ? 'warn'
            : (snap.categoryCount >= 3 ? 'good' : 'info'),
  });

  // Liquidity
  if (snap.cashPct === 0) {
    cards.push({
      title: t('healthCardLiquidityTitle'),
      body:  t('healthCardLiquidityBodyNone'),
      tone:  'info',
    });
  } else if (snap.cashPct > 40) {
    cards.push({
      title: t('healthCardLiquidityTitle'),
      body:  (t('healthCardLiquidityBodyHigh'))(snap.cashPct),
      tone:  'info',
    });
  }

  // Performance momentum
  if (snap.bestAsset && snap.bestAsset.change24h > 15) {
    const sign = snap.bestAsset.change24h >= 0 ? '+' : '';
    const ch = `${sign}${snap.bestAsset.change24h.toFixed(1)}%`;
    cards.push({
      title: t('healthCardPerformanceTitle'),
      body:  (t('healthCardPerformanceBody'))(snap.bestAsset.name, ch),
      tone:  'good',
    });
  }

  // Loss pressure
  if (snap.worstAsset && snap.worstAsset.change24h < -12) {
    const ch = `${snap.worstAsset.change24h.toFixed(1)}%`;
    cards.push({
      title: t('healthCardLossTitle'),
      body:  (t('healthCardLossBody'))(snap.worstAsset.name, ch),
      tone:  'bad',
    });
  }

  return cards.slice(0, cap);
}

function _aurixHealthContext(signal, snap) {
  if (!signal || !snap) return '';
  const t24 = (asset) => {
    if (typeof asset.change24h !== 'number') return '';
    const sign = asset.change24h >= 0 ? '+' : '';
    return `${sign}${asset.change24h.toFixed(1)}%`;
  };
  const typeLabel = (type) => {
    const meta = (typeof TYPE_META !== 'undefined' && TYPE_META[type]) || null;
    return meta ? meta.label : (type || '—');
  };
  switch (signal.kind) {
    case 'concentration': {
      if (!snap.topAsset) return '';
      const fn = t('healthCtxConcentration');
      return typeof fn === 'function' ? fn(snap.topAsset.name, snap.topAsset.pctTotal) : '';
    }
    case 'crypto': {
      const fn = t('healthCtxCrypto');
      return typeof fn === 'function' ? fn(snap.cryptoPct) : '';
    }
    case 'cash': {
      const fn = t('healthCtxCash');
      return typeof fn === 'function' ? fn(snap.cashPct) : '';
    }
    case 'single': {
      if (!snap.topAsset) return '';
      const fn = t('healthCtxSingle');
      return typeof fn === 'function' ? fn(snap.topAsset.name, typeLabel(snap.topAsset.type)) : '';
    }
    case 'performance': {
      // Find the asset with the max 24h change to surface its name.
      let best = null, bestCh = -Infinity;
      for (const a of assets) {
        if (typeof a.change24h === 'number' && a.change24h > bestCh) { best = a; bestCh = a.change24h; }
      }
      if (!best) return '';
      const fn = t('healthCtxPerformance');
      return typeof fn === 'function' ? fn(best.name || best.ticker, t24(best)) : '';
    }
    case 'loss': {
      let worst = null, worstCh = Infinity;
      for (const a of assets) {
        if (typeof a.change24h === 'number' && a.change24h < worstCh) { worst = a; worstCh = a.change24h; }
      }
      if (!worst) return '';
      const fn = t('healthCtxLoss');
      return typeof fn === 'function' ? fn(worst.name || worst.ticker, t24(worst)) : '';
    }
    default: return '';
  }
}

function openHealthPanel() {
  const overlay = document.getElementById('healthOverlay');
  if (!overlay) return;
  const snap   = _aurixHealthSnapshot();

  // Show / hide the empty branch first — the panel is opened from
  // the signal CTA, which already needs a non-empty portfolio to
  // even render, so this guard is mostly defensive (e.g. the user
  // deleted every asset while the panel was about to open).
  const emptySection = document.getElementById('healthEmpty');
  const scoreSection = document.getElementById('healthScoreSection');
  const metricsSec   = document.getElementById('healthMetrics');
  const cardsSec     = document.getElementById('healthCards');
  const footerRow    = document.querySelector('.health-footer-row');
  const isEmpty = (snap.assetCount === 0 || snap.totUSD <= 0);
  if (emptySection) emptySection.hidden = !isEmpty;
  if (scoreSection) scoreSection.hidden = isEmpty;
  if (metricsSec)   metricsSec.hidden   = isEmpty;
  if (cardsSec)     cardsSec.hidden     = isEmpty;
  if (footerRow)    footerRow.hidden    = isEmpty;

  if (!isEmpty) {
    // Score ring + bar + label
    const score = _aurixHealthScore(snap);
    const ring  = document.getElementById('healthScoreRing');
    const num   = document.getElementById('healthScoreNum');
    const lbl   = document.getElementById('healthScoreLabel');
    const fill  = document.getElementById('healthScoreBarFill');
    if (ring) {
      ring.dataset.tone = score.tone;
      // conic-gradient consumes --health-score as % filled.
      ring.style.setProperty('--health-score', String(score.score != null ? score.score : 0));
    }
    if (num)  num.textContent = (score.score != null) ? String(score.score) : '—';
    if (lbl)  lbl.textContent = score.label || '—';
    if (fill) fill.style.width = ((score.score != null ? score.score : 0)) + '%';
    const explainEl = document.getElementById('healthScoreExplain');
    if (explainEl) explainEl.textContent = score.explain || '';

    // Metrics row
    const valEl = id => document.getElementById(id);
    const assetsLbl = (snap.assetCount === 1) ? t('healthMetricAssetSingle')   : t('healthMetricAssetsLabel');
    const catsLbl   = (snap.categoryCount === 1) ? t('healthMetricCategorySingle') : t('healthMetricCategoriesLabel');
    if (valEl('healthMetAssets'))      valEl('healthMetAssets').textContent      = String(snap.assetCount);
    if (valEl('healthMetAssetsLabel')) valEl('healthMetAssetsLabel').textContent = assetsLbl;
    if (valEl('healthMetCats'))        valEl('healthMetCats').textContent        = String(snap.categoryCount);
    if (valEl('healthMetCatsLabel'))   valEl('healthMetCatsLabel').textContent   = catsLbl;
    if (valEl('healthMetDom')) {
      valEl('healthMetDom').textContent = snap.topAsset
        ? `${snap.topAsset.ticker || snap.topAsset.name} · ${snap.topAsset.pctTotal}%`
        : '—';
    }
    if (valEl('healthMetCash')) {
      valEl('healthMetCash').textContent = (snap.cashPct > 0) ? `${snap.cashPct}%` : `0%`;
    }

    // Diagnostic cards (rendered dynamically, max 5)
    if (cardsSec) {
      const cards = _aurixHealthCards(snap, 5);
      cardsSec.innerHTML = cards.map(c => `
        <div class="health-card" data-tone="${c.tone}">
          <span class="health-card-title">${c.title}</span>
          <p class="health-card-body">${c.body}</p>
        </div>
      `).join('');
    }
  }

  // Re-apply i18n so static data-i18n labels follow the current language.
  if (typeof applyI18n === 'function') applyI18n();

  overlay.classList.add('open');
  overlay.setAttribute('aria-hidden', 'false');
  document.body.classList.add('modal-open');
}

function closeHealthPanel() {
  const overlay = document.getElementById('healthOverlay');
  if (!overlay) return;
  overlay.classList.remove('open');
  overlay.setAttribute('aria-hidden', 'true');
  document.body.classList.remove('modal-open');
}

// AURIX-WORKSPACE-TEASER-POLISH-1: the dashboard signal is now a static
// single-line Workspace teaser (see renderAurixSignal). The legacy rotation
// carousel — its pool index / timer / pause state, the ~10s interval, the
// per-tick apply + tonal-copy resolver and the mobile/narrow copy probes —
// has been removed. Only the visibility-reason tag is kept for diagnostics.
let _aurixSignalVisibility = 'init';

// ── INVESTOR-PROFILE-1 ─────────────────────────────────────────────
// Aurix Signals personalise their tone to the user's investor profile.
// Profile lives in the onboarding prefs (experience, riskProfile,
// ageBand). Reading it never forces onboarding — missing values fall
// through to safe defaults (intermediate / balanced / prefer_not_say).
function _aurixInvestorProfile() {
  let snap = null;
  try {
    if (typeof window !== 'undefined' && window.AurixOnboarding
        && typeof window.AurixOnboarding.getSnapshot === 'function') {
      snap = window.AurixOnboarding.getSnapshot();
    }
  } catch (_) { snap = null; }
  if (!snap) {
    // Fallback path — older sessions or non-hydrated boots.
    try {
      const raw = localStorage.getItem('aurix_onboarding_preferences');
      if (raw) snap = JSON.parse(raw) || {};
    } catch (_) { snap = {}; }
  }
  snap = snap || {};
  const experience  = (typeof snap.experience  === 'string' && snap.experience)  ? snap.experience  : 'intermediate';
  const riskProfile = (typeof snap.riskProfile === 'string' && snap.riskProfile) ? snap.riskProfile : 'balanced';
  const ageBand     = (typeof snap.ageBand     === 'string' && snap.ageBand)     ? snap.ageBand     : 'prefer_not_say';
  return { experience, riskProfile, ageBand };
}

// Re-render the teaser on viewport changes (debounced) so its visibility
// decisions stay correct across breakpoints. The dot's pulse is CSS-owned.
let _aurixSignalResizeTimer = null;
let _aurixSignalResizeBound = false;
function _aurixSignalBindResize() {
  if (_aurixSignalResizeBound) return;
  _aurixSignalResizeBound = true;
  window.addEventListener('resize', () => {
    clearTimeout(_aurixSignalResizeTimer);
    _aurixSignalResizeTimer = setTimeout(() => {
      const sec = document.getElementById('aurixSignal');
      if (!sec) return;
      try { renderAurixSignal(); } catch (_) { /* never let resize hide the teaser */ }
    }, 180);
  });
}

function renderAurixSignal() {
  const sec = document.getElementById('aurixSignal');
  if (!sec) return;

  // Empty portfolio OR drill-down view → no signal, stop rotation.
  // SIGNAL-HOTFIX: visibility decisions are derived live from `assets`
  // and `activeCategory`; no localStorage snapshot is consulted here.
  if (!Array.isArray(assets) || assets.length === 0) {
    _aurixSignalVisibility = 'hidden:empty';
    sec.hidden = true;
    sec.removeAttribute('data-tone');
    return;
  }
  // DRILLDOWN-RACE-2 audit: Aurix Signal is a dashboard root widget.
  // The original check covered the steady state — also gate on
  // _enteringCategory so an async refresh that lands inside the 210ms
  // drill-in animation cannot re-paint the signal card over the
  // category drill-down.
  if ((typeof activeCategory !== 'undefined' && activeCategory) ||
      (typeof _enteringCategory !== 'undefined' && _enteringCategory)) {
    _aurixSignalVisibility = 'hidden:drilldown';
    sec.hidden = true;
    sec.removeAttribute('data-tone');
    return;
  }

  // AURIX-PREMIUM-CLEANUP-1 / AURIX-WORKSPACE-TEASER-POLISH-1: single-line
  // Workspace teaser. The dashboard owns STATUS, so this shows only the
  // portfolio health STATE (natural copy) and a tone-coloured dot — no
  // rotating pool, no carousel. Workspace owns the full interpretation.
  const snap  = (typeof _aurixHealthSnapshot === 'function') ? _aurixHealthSnapshot() : null;
  const score = (typeof _aurixHealthScore    === 'function') ? _aurixHealthScore(snap) : null;
  const tone  = (score && score.tone) || 'solid';

  // Map the (unchanged) health tone to a natural teaser label so the line
  // reads "Salud sólida" rather than "Salud de cartera · Salud sólida".
  const _TEASER_LABEL = {
    solid:    'teaserHealthSolid',
    moderate: 'teaserHealthModerate',
    elevated: 'teaserHealthElevated',
    high:     'teaserHealthHigh',
  };
  const state = (score && score.score != null)
    ? (t(_TEASER_LABEL[tone] || 'teaserHealthSolid') || score.label)
    : (t('healthScoreEmpty') || '—');

  const msgEl = document.getElementById('aurixSignalMsg');
  const ctaEl = document.getElementById('aurixSignalCtaLabel');
  if (msgEl) msgEl.textContent = state;
  if (ctaEl) ctaEl.textContent = t('signalHealthCta') || 'Ver análisis';

  sec.removeAttribute('data-kind');
  sec.setAttribute('data-tone', tone);
  _aurixSignalVisibility = 'visible:health:' + tone;
  sec.hidden = false;
  _aurixSignalBindResize();

  // Keyboard parity for role="button" — Enter/Space opens Intelligence too (INT.2R).
  if (!sec.dataset.keybound) {
    sec.dataset.keybound = '1';
    sec.addEventListener('keydown', (ev) => {
      if (ev.key === 'Enter' || ev.key === ' ' || ev.key === 'Spacebar') {
        ev.preventDefault();
        if (typeof switchTab === 'function') switchTab('intelligence');
        else { const tab = document.querySelector('#bottomNav [data-tab="intelligence"]'); if (tab) tab.click(); }
      }
    });
  }
}

// AURIX-WORKSPACE-TEASER-POLISH-1: debug probe for the Workspace teaser.
// Run `__aurixSignalDebug()` in devtools to inspect the live health state
// the teaser displays, why it's visible/hidden, and the investor profile.
// The legacy rotation/pool fields were removed with the carousel.
// DEBUG-HARDEN-1: gated to dev hosts only.
if (typeof window !== 'undefined' && _aurixIsDebugHost()) {
  window.__aurixSignalDebug = function () {
    const livePool = (typeof computeAurixSignalPool === 'function')
      ? computeAurixSignalPool() : [];
    const snap  = (typeof _aurixHealthSnapshot === 'function') ? _aurixHealthSnapshot() : null;
    const score = (typeof _aurixHealthScore    === 'function') ? _aurixHealthScore(snap) : null;
    const profile = (typeof _aurixInvestorProfile === 'function') ? _aurixInvestorProfile() : null;
    return {
      assets: Array.isArray(assets) ? assets.map(a => ({
        ticker: a.ticker || a.symbol || null,
        type:   a.type || null,
        qty:    a.quantity ?? a.qty ?? null,
      })) : [],
      health: score ? { score: score.score, tone: score.tone, label: score.label } : null,
      livePool:         livePool.map(s => s.kind),
      visibilityReason: _aurixSignalVisibility,
      investorProfile:  profile,
    };
  };
}

// ── AURIX-EMPTY-1 / ACTIVATION-2: activation card + quick-chip wiring ──
// Pure event delegation — no engine, no state, no observers. Mounts
// on the document so it survives every re-render of #assetsList.
(function _initEmptyActivationWiring() {
  // AURIX-ACTIVATION-2: hand-curated entries so each quick chip can
  // call selectAsset() directly and skip the search round-trip. The
  // shape matches what the search suggestions return — selectAsset
  // resolves the live price via the existing provider chain.
  const QUICK_ENTRIES = {
    btc:  { ticker: 'BTC',  name: 'Bitcoin',                type: 'crypto', coinId: 'bitcoin' },
    aapl: { ticker: 'AAPL', name: 'Apple Inc.',             type: 'stock',  marketSymbol: 'AAPL' },
    spy:  { ticker: 'SPY',  name: 'SPDR S&P 500 ETF Trust', type: 'etf',    marketSymbol: 'SPY' },
    gold: { ticker: 'XAU',  name: 'Gold',                   type: 'metal',  marketSymbol: 'GC=F' },
  };

  function _quickAdd(kind) {
    if (kind === 'cash') {
      if (typeof openLiquidityModal === 'function') openLiquidityModal();
      return;
    }
    const entry = QUICK_ENTRIES[kind];
    if (!entry || typeof openModal !== 'function') return;
    // skipPicker lands directly on the form so selectAsset can mount
    // the qty/preview controls. Defer the call one tick so the modal's
    // own reset routine finishes before we paint the chip + price.
    openModal({ skipPicker: true });
    setTimeout(() => {
      if (typeof selectAsset === 'function') {
        try { selectAsset(entry); }
        catch (e) { console.warn('[quick-add]', e && e.message); }
      }
    }, 60);
  }

  function _handleChip(kind) {
    _quickAdd(kind);
  }

  document.addEventListener('click', e => {
    // Activation card CTAs.
    const action = e.target.closest && e.target.closest('[data-empty-action]');
    if (action) {
      const a = action.dataset.emptyAction;
      if (a === 'add-asset') {
        // CAT-CONTEXT-1: empty state inside a category drill-down must
        // route through the contextual flow, never re-ask via the
        // generic picker.
        const cat = typeof activeCategory === 'string' ? activeCategory : null;
        if (cat === 'cash') {
          if (typeof openLiquidityModal === 'function') openLiquidityModal();
          return;
        }
        if (cat && typeof openContextualModal === 'function') {
          openContextualModal(cat);
          return;
        }
        if (typeof openModal === 'function') openModal();
        return;
      }
      if (a === 'add-liquidity') {
        // AURIX-EMPTY-1: secondary CTA opens the existing liquidity
        // modal. Same flow as the global "+ Añadir liquidez" button so
        // no duplicate logic.
        if (typeof openLiquidityModal === 'function') openLiquidityModal();
        return;
      }
    }
    // Quick-start chips.
    const chip = e.target.closest && e.target.closest('[data-empty-chip]');
    if (chip) {
      _handleChip(chip.dataset.emptyChip);
      return;
    }

    // INT.2R (Bloque 12): the Dashboard health signal ("Ver análisis") now routes
    // to the dedicated Intelligence tab — portfolio intelligence moved out of
    // Workspace (IA.1), so the old Workspace handoff was stale. The WHOLE card
    // (and its inner CTA) opens Intelligence.
    const sigEl = e.target.closest && e.target.closest('#aurixSignal');
    if (sigEl) {
      if (typeof switchTab === 'function') {
        switchTab('intelligence');
      } else {
        const tab = document.querySelector('#bottomNav [data-tab="intelligence"]');
        if (tab) tab.click();
      }
      return;
    }

    // Portfolio Health panel — close interactions (X button, secondary
    // CTA, and backdrop click on the overlay itself).
    if (e.target.closest && e.target.closest('#healthClose')) {
      closeHealthPanel();
      return;
    }
    if (e.target.closest && e.target.closest('#healthCloseBtn')) {
      closeHealthPanel();
      return;
    }
    const healthOv = document.getElementById('healthOverlay');
    if (healthOv && healthOv.classList.contains('open') && e.target === healthOv) {
      closeHealthPanel();
      return;
    }

    // Portfolio Health panel — explicit Workspace handoff.
    if (e.target.closest && e.target.closest('#healthWorkspaceBtn')) {
      closeHealthPanel();
      if (typeof switchTab === 'function') {
        switchTab('workspace');
      } else {
        const tab = document.querySelector('#bottomNav [data-tab="workspace"]');
        if (tab) tab.click();
      }
      return;
    }
  });

  // ESC closes the Health panel without affecting other open overlays.
  document.addEventListener('keydown', e => {
    if (e.key !== 'Escape') return;
    const ov = document.getElementById('healthOverlay');
    if (ov && ov.classList.contains('open')) closeHealthPanel();
  });
})();

